import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, generateProductSku, normalizeString } from '../services/storageService';
import { parseOrderText, verifyAddress } from '../services/geminiService';
import { differenceInDays } from 'date-fns';
import { ProductEditModal } from './InventoryManager';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [quickTags, setQuickTags] = useState<string[]>([]);
  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [isVerifyingAddr, setIsVerifyingAddr] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const loadTags = () => setQuickTags(storageService.getQuickTags());
    loadTags();
    window.addEventListener('local_tags_updated', loadTags);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 10);

        setExistingBatches(sortedBatches);

        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date();
           const dateStr = today.toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(dateStr)) || `LÔ-${dateStr}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) {
        setShowCustomerSuggestions(false);
      }
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) {
        setActiveProductRow(null);
      }
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) {
        setShowBatchSuggestions(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        window.removeEventListener('local_tags_updated', loadTags);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  // --- BATCH STATISTICS SIDEBAR LOGIC ---
  const batchStats = useMemo(() => {
      const statsMap = new Map<string, { qty: number }>();
      orders.forEach(o => {
          if (o.batchId === batchId && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  const current = statsMap.get(normName) || { qty: 0 };
                  current.qty += item.quantity;
                  statsMap.set(normName, current);
              });
          }
      });

      return products.map(p => {
          const normName = normalizeString(p.name);
          const soldInBatch = statsMap.get(normName)?.qty || 0;
          return {
              product: p,
              soldInBatch,
              stock: p.stockQuantity || 0,
              totalImported: p.totalImported || 0
          };
      })
      .filter(item => item.soldInBatch > 0 || (item.stock < 10 && item.stock > -50))
      .sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId]);

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => { setIsListening(true); toast('Đang nghe...', { icon: '🎙️' }); };
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        const transcript = event.results[0][0].transcript;
        await processOrderText(transcript);
    };
    recognition.start();
  };

  const handlePasteFromMessenger = async () => {
      try {
          const text = await navigator.clipboard.readText();
          if (!text) { toast.error("Clipboard trống"); return; }
          await processOrderText(text);
      } catch (err) { toast.error("Lỗi truy cập Clipboard"); }
  };

  const processOrderText = async (text: string) => {
      setIsProcessingAI(true);
      const loadingToast = toast.loading("AI đang phân tích...");
      try {
          const result = await parseOrderText(text, products, customers);
          setCustomerInfo(prev => ({
              ...prev,
              customerName: result.customerName || prev.customerName,
              customerPhone: result.customerPhone || prev.customerPhone,
              address: result.address || prev.address,
              notes: result.notes || prev.notes
          }));

          if (result.parsedItems && result.parsedItems.length > 0) {
              const newItems = result.parsedItems.map(pi => {
                  const searchName = pi.productName.toLowerCase();
                  const matched = products.find(p => p.name.toLowerCase() === searchName || p.name.toLowerCase().includes(searchName));
                  return {
                      id: uuidv4(),
                      name: matched ? matched.name : pi.productName,
                      quantity: pi.quantity || 1,
                      price: matched ? matched.defaultPrice : 0,
                      productId: matched ? matched.id : undefined,
                      importPrice: matched ? matched.importPrice : undefined
                  };
              });
              setItems(newItems);
          }
          toast.success("Xong!");
      } catch (error) { toast.error("AI không đọc được nội dung này"); }
      finally { setIsProcessingAI(false); toast.dismiss(loadingToast); }
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = {
        ...newItems[index],
        productId: product.id,
        name: product.name,
        price: product.defaultPrice,
        importPrice: product.importPrice
      };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleCustomerSelect = (customer: Customer) => {
    setCustomerInfo({
      customerId: customer.id,
      customerName: customer.name,
      customerPhone: customer.phone,
      address: customer.address,
      notes: customerInfo.notes
    });
    setShowCustomerSuggestions(false);
  };

  const resetForm = () => {
      setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
      setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
      if (nameInputRef.current) nameInputRef.current.focus();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) {
      toast.error('Thiếu thông tin bắt buộc');
      return;
    }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    resetForm();
  };

  const customerSuggestions = customers.filter(c => 
    c.name.toLowerCase().includes((customerInfo.customerName || '').toLowerCase()) &&
    customerInfo.customerName && customerInfo.customerName !== c.name
  ).slice(0, 5);

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-bold text-eco-800">AI đang đọc dữ liệu...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Nhập Đơn</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'STATS' ? 'border-purple-600 text-purple-700' : 'text-gray-400'}`}>Thống Kê Lô ({batchStats.length})</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[70%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/50">
                       <div className="flex items-center gap-2">
                           <div className="w-7 h-7 rounded-full bg-eco-100 flex items-center justify-center text-eco-600"><i className="fas fa-plus-circle"></i></div>
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border border-gray-200 rounded-lg px-2 py-1 shadow-sm hover:border-eco-400 cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-24 text-[10px] font-bold text-eco-700 outline-none bg-transparent" placeholder="LÔ-HÔM-NAY" />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-400 ml-1"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-40 bg-white border border-gray-100 rounded-lg shadow-xl z-50 overflow-hidden">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-3 py-2 hover:bg-eco-50 cursor-pointer text-xs font-medium text-gray-700 border-b border-gray-50 last:border-0">{b}</div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handlePasteFromMessenger} className="w-8 h-8 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 flex items-center justify-center transition-colors" title="Dán từ Messenger"><i className="fab fa-facebook-messenger"></i></button>
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                           <button onClick={resetForm} className="w-8 h-8 rounded-lg bg-gray-50 text-gray-400 hover:bg-red-50 hover:text-red-500 flex items-center justify-center transition-colors"><i className="fas fa-trash-alt text-xs"></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[80px]">
                            <div className="text-[9px] text-gray-400 font-bold uppercase">Tổng tiền</div>
                            <div className="text-xl font-black text-eco-700">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-xs font-medium text-gray-400">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3 px-4 font-bold text-sm shadow-lg active:scale-95 transition-all">LÊN ĐƠN NGAY <i className="fas fa-paper-plane ml-1"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-3 pb-20">
                    <div className="bg-gray-50/50 p-3 rounded-xl border border-gray-100">
                        <div className="grid grid-cols-12 gap-2 mb-2">
                            <div className="col-span-7 relative" ref={customerWrapperRef}>
                                <label className="block text-[10px] font-bold text-gray-400 uppercase mb-0.5 ml-1">Tên khách</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className="w-full p-2 bg-white border border-gray-200 rounded-lg outline-none text-sm font-bold" placeholder="Nhập tên..." autoComplete="off" />
                                {showCustomerSuggestions && customerSuggestions.length > 0 && (
                                    <ul className="absolute z-30 w-full bg-white border border-gray-100 rounded-lg shadow-xl mt-1 overflow-hidden">
                                        {customerSuggestions.map(s => (
                                            <li key={s.id} onClick={() => handleCustomerSelect(s)} className="px-3 py-2 hover:bg-blue-50 cursor-pointer border-b border-gray-50 last:border-0 text-xs font-bold">{s.name} - <span className="font-normal text-gray-400">{s.phone}</span></li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-bold text-gray-400 uppercase mb-0.5 ml-1">Điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className="w-full p-2 bg-white border border-gray-200 rounded-lg outline-none text-sm" placeholder="SĐT..." />
                            </div>
                        </div>
                        <div className="mb-2">
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className="w-full p-2 bg-white border border-gray-200 rounded-lg outline-none text-sm" placeholder="Địa chỉ giao hàng..." />
                        </div>
                        <div className="flex gap-2">
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className="flex-grow p-2 bg-white border border-gray-200 rounded-lg outline-none text-xs" placeholder="Ghi chú..." />
                        </div>
                    </div>

                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-xs font-bold text-gray-500 uppercase">Hàng hóa</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-bold text-white bg-eco-600 px-2 py-1 rounded shadow-sm hover:bg-eco-700">+ Thêm dòng</button>
                        </div>

                        {items.map((item, idx) => {
                            const availableProducts = products.filter(p => !item.name || p.name.toLowerCase().includes(item.name.toLowerCase()));
                            return (
                                <div key={item.id} className="flex items-center gap-2 bg-white p-2 rounded-lg border border-gray-200 shadow-sm relative">
                                    <div className="flex-grow relative">
                                        <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-1.5 bg-gray-50 border border-gray-100 rounded text-sm font-bold outline-none focus:bg-white" placeholder="Sản phẩm..." />
                                        {activeProductRow === idx && (
                                            <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-xl z-50 max-h-48 overflow-y-auto">
                                                {availableProducts.length === 0 ? (
                                                    <div className="p-2 text-xs text-gray-400 text-center italic">Không thấy mặt hàng này</div>
                                                ) : (
                                                    availableProducts.map(p => (
                                                        <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-3 py-2 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-50 last:border-0">
                                                            <div className="text-xs font-bold text-gray-800">{p.name} <span className={`ml-1 text-[9px] ${p.stockQuantity < 5 ? 'text-red-500' : 'text-gray-400'}`}>(Tồn: {p.stockQuantity})</span></div>
                                                            <div className="text-[10px] font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}</div>
                                                        </div>
                                                    ))
                                                )}
                                                <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-2 bg-gray-50 text-center text-xs font-bold text-eco-600 hover:bg-eco-100 cursor-pointer border-t border-gray-100">[+] Tạo hàng mới trong kho</div>
                                            </div>
                                        )}
                                    </div>
                                    <div className="w-12"><input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-1.5 text-center bg-gray-50 border border-gray-100 rounded text-sm font-bold outline-none" placeholder="SL" /></div>
                                    <div className="w-20 hidden sm:block"><input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-1.5 text-right bg-gray-50 border border-gray-100 rounded text-sm font-bold outline-none" placeholder="Giá" /></div>
                                    <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-500 p-1"><i className="fas fa-times"></i></button>
                                </div>
                            );
                        })}
                    </div>
                </form>
            </div>

            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[30%] flex-col bg-gray-50/30 h-full overflow-hidden`}>
                <div className="p-3 border-b border-gray-200 bg-white flex justify-between items-center">
                    <h3 className="text-xs font-bold text-gray-500 uppercase">Thống kê Lô {batchId}</h3>
                    <button onClick={async () => { await storageService.recalculateInventoryFromOrders(); toast.success("Đã đồng bộ lại tồn kho"); }} className="text-[10px] text-blue-600 hover:underline"><i className="fas fa-sync-alt mr-1"></i>Đồng bộ</button>
                </div>

                <div className="flex-grow overflow-y-auto">
                    {batchStats.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-gray-300 opacity-50"><i className="fas fa-box-open text-3xl mb-2"></i><p className="text-xs">Chưa bán hàng trong lô</p></div>
                    ) : (
                        <table className="w-full text-left text-[10px]">
                            <thead className="bg-gray-100 text-gray-400 font-bold sticky top-0 uppercase">
                                <tr><th className="p-2 pl-3">Sản phẩm</th><th className="p-2 text-center">Bán</th><th className="p-2 text-right pr-3">Tồn Kho</th></tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 bg-white">
                                {batchStats.map((stat, idx) => (
                                    <tr key={idx} className="hover:bg-purple-50 group">
                                        <td className="p-2 pl-3">
                                            <div className="font-bold text-gray-800 flex items-center gap-1">
                                                {stat.product.name}
                                                <button onClick={() => handleEditProduct(stat.product)} className="opacity-0 group-hover:opacity-100 text-blue-400 hover:text-blue-600"><i className="fas fa-edit text-[8px]"></i></button>
                                            </div>
                                        </td>
                                        <td className="p-2 text-center"><span className="bg-purple-100 text-purple-700 px-1.5 py-0.5 rounded font-black">{stat.soldInBatch}</span></td>
                                        <td className={`p-2 pr-3 text-right font-bold ${stat.stock < 5 ? 'text-red-500' : 'text-gray-400'}`}>{stat.stock}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
                <div className="p-3 bg-white border-t border-gray-100 text-[10px] text-gray-400 text-center italic">Tự động trừ kho khi lưu đơn thành công</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const QUOTA_KEY = 'ecogo_quota_status';
const LOGO_KEY = 'ecogo_company_logo';

const checkQuotaStatus = () => {
    try {
        const stored = localStorage.getItem(QUOTA_KEY);
        if (stored) {
            const { date, exhausted } = JSON.parse(stored);
            if (date === new Date().toDateString() && exhausted) return true;
        }
    } catch {}
    return false;
};

let _quotaExhausted = checkQuotaStatus();
const isOnline = () => !!db && !_quotaExhausted;

const markQuotaExhausted = () => {
    if (!_quotaExhausted) {
        _quotaExhausted = true;
        localStorage.setItem(QUOTA_KEY, JSON.stringify({ date: new Date().toDateString(), exhausted: true }));
        window.dispatchEvent(new Event('quota_exhausted'));
    }
};

let _memoryCustomers: Customer[] | null = null;
let _memoryOrders: Order[] | null = null;
let _memoryProducts: Product[] | null = null;

const ensureProductsLoaded = () => {
    if (_memoryProducts) return _memoryProducts;
    try {
        const local = localStorage.getItem(PRODUCT_KEY);
        _memoryProducts = local ? JSON.parse(local) : [];
    } catch { _memoryProducts = []; }
    return _memoryProducts || [];
};

const ensureOrdersLoaded = () => {
    if (_memoryOrders) return _memoryOrders;
    try {
        const local = localStorage.getItem(ORDER_KEY);
        _memoryOrders = local ? JSON.parse(local) : [];
    } catch { _memoryOrders = []; }
    return _memoryOrders || [];
};

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    const sku = name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
    return sku.length < 2 ? uuidv4() : sku;
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    if (p.length === 9 && !p.startsWith('0')) p = '0' + p;
    return p;
};

const sanitize = <T>(obj: T): T => JSON.parse(JSON.stringify(obj));

const safeCloudOp = async (operation: () => Promise<any>) => {
    if (_quotaExhausted || !db) return;
    try { await operation(); } catch (error: any) {
        if (error.code === 'resource-exhausted') markQuotaExhausted();
    }
};

