                                        {/* Social Link Input */}
                                        <div className="relative flex-grow sm:flex-grow-0 sm:w-8">
                                            <input 
                                                className={`w-full sm:w-8 sm:h-8 rounded-full border border-gray-200 text-xs px-2 sm:px-0 sm:text-center outline-none focus:border-blue-500 focus:ring-1 focus:ring-blue-200 transition-all ${c.socialLink ? 'text-blue-600 bg-blue-50 border-blue-200' : 'text-gray-400 bg-gray-50'}`}
                                                placeholder={c.socialLink ? "Link..." : "+Link"}
                                                defaultValue={c.socialLink}
                                                title={c.socialLink || "Dán link Facebook"}
                                                onBlur={(e) => handleInlineUpdate(c, 'socialLink', e.target.value)}
                                                onKeyDown={(e) => e.key === 'Enter' && e.currentTarget.blur()}
                                            />
                                            {c.socialLink && (
                                                <a href={c.socialLink} target="_blank" rel="noopener noreferrer" className="absolute right-2 top-1/2 -translate-y-1/2 sm:hidden text-blue-500">
                                                    <i className="fas fa-external-link-alt"></i>
                                                </a>
                                            )}
                                        </div>
                                    </div>

                                    {/* Delete Button (Desktop: Col 5) */}
                                    <div className="absolute top-2 right-2 sm:static sm:order-5 sm:text-right">
                                        <button 
                                            onClick={() => handleDeleteClick(c.id)} 
                                            className="w-7 h-7 rounded-full flex items-center justify-center text-gray-300 hover:bg-red-50 hover:text-red-500 transition-all" 
                                            title="Xóa"
                                        >
                                            <i className="fas fa-times text-sm"></i>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
      </div>

      {/* IMPORT MODAL */}
      {showImportModal && (
          <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
                  <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                      <h3 className="font-bold text-lg text-gray-800">Nhập liệu Khách Hàng (Excel/Text)</h3>
                      <button onClick={() => setShowImportModal(false)} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times"></i></button>
                  </div>

                  <div className="p-6 space-y-4 overflow-y-auto">
                      <div className="flex items-center gap-2 bg-yellow-50 p-2 rounded-lg border border-yellow-100">
                          <input 
                              type="checkbox" 
                              id="devMode" 
                              checked={isLocalMode} 
                              onChange={e => setIsLocalMode(e.target.checked)} 
                              className="w-4 h-4 text-eco-600 rounded focus:ring-eco-500 cursor-pointer"
                          />
                          <label htmlFor="devMode" className="text-xs font-bold text-yellow-800 cursor-pointer select-none flex-grow">
                              Chế độ Test (Tắt Cloud Sync)
                          </label>
                      </div>

                      <div className="flex gap-2 p-1 bg-gray-100 rounded-lg">
                          <button onClick={() => setImportMode('TEXT')} className={`flex-1 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${importMode === 'TEXT' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>Excel / Text</button>
                          <button onClick={() => setImportMode('JSON')} className={`flex-1 px-3 py-1.5 rounded-md text-xs font-bold transition-all ${importMode === 'JSON' ? 'bg-white text-black shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>JSON</button>
                      </div>

                      {importMode === 'TEXT' ? (
                          <>
                            <p className="text-[10px] text-gray-500 leading-relaxed italic bg-blue-50 p-2 rounded border border-blue-100">
                                Copy từ Excel (không cần tiêu đề):<br/>
                                <b>Tên | SĐT | Địa chỉ | Ưu tiên</b><br/>
                                <i>Số điện thoại không bắt buộc.</i>
                            </p>
                            <textarea value={importText} onChange={e => setImportText(e.target.value)} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-mono h-48 focus:border-eco-500 outline-none whitespace-pre scrollbar-thin" placeholder={"Nguyen Van A\t0909123\tQuan 1\t1\nLe Thi B\t\tQuan 3\t2"} disabled={isImporting} />
                          </>
                      ) : (
                          <>
                            <p className="text-xs text-gray-500 leading-relaxed">Dán mảng JSON vào đây (cho dữ liệu lớn)</p>
                            <textarea value={importText} onChange={e => setImportText(e.target.value)} className="w-full p-3 bg-gray-50 border border-gray-200 rounded-xl text-xs font-mono h-48 focus:border-eco-500 outline-none scrollbar-thin" placeholder='[ {"name": "A", "phone": "", "priority": 1} ]' disabled={isImporting} />
                          </>
                      )}

                      {isImporting && (
                          <div className="w-full bg-gray-200 rounded-full h-2 overflow-hidden">
                              <div className="bg-eco-600 h-2 rounded-full transition-all duration-300 animate-pulse" style={{ width: `${importProgress}%` }}></div>
                          </div>
                      )}

                      <button onClick={handleImport} type="button" disabled={isImporting} className={`w-full py-3 rounded-xl text-sm font-bold text-white transition-all shadow-md ${isImporting ? 'bg-gray-400 cursor-not-allowed' : 'bg-eco-600 hover:bg-eco-700'}`}>{isImporting ? `Đang nhập ${importProgress}%` : 'Bắt đầu Nhập'}</button>
                  </div>
              </div>
          </div>
      )}

      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa khách hàng?" message="Hành động này sẽ xóa khách hàng khỏi danh bạ." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa" isDanger={true} />
      <ConfirmModal isOpen={showDeleteAllConfirm} title={`CẢNH BÁO: Xóa TẤT CẢ?`} message={`Bạn có chắc chắn muốn xóa toàn bộ danh sách khách hàng? \n\n ${isLocalMode ? 'Chế độ Test: Chỉ xóa trên máy này.' : 'Dữ liệu sẽ bị xóa cả trên Cloud (nếu có mạng).'}`} onConfirm={confirmDeleteAll} onCancel={() => setShowDeleteAllConfirm(false)} confirmLabel="XÓA SẠCH" isDanger={true} />
    </div>
  );
};

export default CustomerManager;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 10);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  // --- SMART SIDEBAR LOGIC ---
  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, number>();
      orders.forEach(o => {
          if (o.batchId === batchId && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  soldMap.set(normName, (soldMap.get(normName) || 0) + item.quantity);
              });
          }
      });

      return products.map(p => ({
          product: p,
          soldInBatch: soldMap.get(normalizeString(p.name)) || 0,
          stock: p.stockQuantity || 0
      })).filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 1000 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => processOrderText(event.results[0][0].transcript, products, customers).then(res => {
        setCustomerInfo(prev => ({ ...prev, customerName: res.customerName || prev.customerName, customerPhone: res.customerPhone || prev.customerPhone, address: res.address || prev.address, notes: res.notes || prev.notes }));
        if (res.parsedItems?.length) {
            setItems(res.parsedItems.map(pi => {
                const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                return { id: uuidv4(), name: matched ? matched.name : pi.productName, quantity: pi.quantity || 1, price: matched ? matched.defaultPrice : 0, productId: matched?.id };
            }));
        }
    });
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
