import { GoogleGenAI, Type } from "@google/genai";
import { SmartParseResult, Order, OrderStatus, PaymentMethod, Product, Customer, RawPDFImportData } from "../types";

const getClient = () => {
  // STRICT SECURITY RULE: API key must be obtained exclusively from process.env.API_KEY
  const apiKey = process.env.API_KEY;

  if (!apiKey) {
    console.error("Missing API Key. Ensure process.env.API_KEY is populated.");
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// NEW: Verify Address using Google Maps Grounding
// Note: Maps grounding is currently only supported in Gemini 2.5 series models.
export const verifyAddress = async (addressQuery: string): Promise<{ address: string, mapLink?: string }> => {
  const ai = getClient();

  const prompt = `
    Verify and standardize this address location: "${addressQuery}".
    If it is a valid location, return ONLY the official, fully formatted address string in Vietnamese.
    If the input is vague, find the most likely specific location.
    Do not add introductory text like "Địa chỉ là...". Just return the address string.
  `;

  try {
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt,
        config: {
          tools: [{ googleMaps: {} }],
        },
      });

      let text = response.text ? response.text.trim() : addressQuery;
      // Cleanup any potential model conversational filler
      text = text.replace(/^Địa chỉ: /i, '').replace(/\.$/, '');

      // Extract Google Maps Link from Grounding Metadata
      let mapLink = undefined;
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

      if (chunks) {
          for (const chunk of chunks) {
              // Priority 1: Check for Maps tool specific URI
              if (chunk.maps) {
                  const mapsData = chunk.maps as any;
                  if (mapsData.googleMapsUri) {
                      mapLink = mapsData.googleMapsUri;
                      break;
                  }
                  if (mapsData.uri) {
                      mapLink = mapsData.uri;
                      break;
                  }
              }

              // Priority 2: Fallback to Web chunk if it points to Google Maps
              if (chunk.web && chunk.web.uri && chunk.web.uri.includes('google.com/maps')) {
                  mapLink = chunk.web.uri;
                  break;
              }
          }
      }

      return { address: text, mapLink };
  } catch (error) {
      console.error("Maps Grounding Error:", error);
      throw new Error("Không thể xác minh địa điểm này.");
  }
};

// Update: Use gemini-3-flash-preview for text parsing tasks
export const parseOrderText = async (
  text: string, 
  products: Product[] = [], 
  customers: Customer[] = []
): Promise<SmartParseResult> => {
  const ai = getClient();

  // Prepare Context Data (Limit to avoid token overflow)
  const productContext = products.map(p => `"${p.name}"`).join(', ');
  const customerContext = customers.slice(0, 200).map(c => `"${c.name}" (${c.phone})`).join(', ');

  const prompt = `
    You are an intelligent order parser for a logistics app (Vietnamese context).
    The input text is a raw chat log copied from Facebook Messenger, Zalo, TikTok Shop, or SMS.

    CONTEXT DATA:
    1. VALID PRODUCT NAMES: [${productContext}]
    2. EXISTING CUSTOMERS: [${customerContext}]

    INPUT TEXT: "${text}"

    INSTRUCTIONS:
    1. **Noise Filtering (Aggressive)**: 
       - Ignore timestamps: "10:30", "Yesterday", "Hôm qua", "Hôm nay", "Mon", "Tue", "Vừa xong".
       - Ignore status labels: "Sent", "Seen", "Delivered", "Đã gửi", "Đã xem", "Đã nhận", "Hoạt động...".
       - Ignore headers: "You sent", "You:", "Customer:", "Shop:", "Bạn đã gửi", "Trả lời".
    2. **Customer Extraction**: 
       - Name: Identify capitalized names (e.g., "Nguyen Van A", "Chị Lan"). Check "EXISTING CUSTOMERS" for matches.
       - Phone: Extract Vietnamese phone numbers (09x, 03x, 07x...). Remove dots/spaces (e.g., 0912.345.678 -> 0912345678).
       - Address: Identify address markers: "số", "ngõ", "ngách", "đường", "p", "phường", "q", "quận", "tp", "thôn", "xã".
       - NOTE: If an existing customer matches the Phone/Name, prefer their stored data.
    3. **Items Extraction**: 
       - Fuzzy match input text to "VALID PRODUCT NAMES".
       - Handle quantities like "2 cái", "x2", "2kg", "lấy 2", "cho 2".
       - If no match in valid list, extract the raw item text.
    4. **Payment Detection**: 
       - "ck", "chuyển khoản", "banking" -> TRANSFER.
       - "đã tt", "đã thanh toán" -> PAID.
       - Default -> CASH.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          customerName: { type: Type.STRING },
          customerPhone: { type: Type.STRING },
          address: { type: Type.STRING },
          parsedItems: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                productName: { type: Type.STRING, description: "The matched product name from inventory" },
                quantity: { type: Type.NUMBER }
              }
            }
          },
          itemsString: { type: Type.STRING, description: "Fallback summary string if array is empty" },
          notes: { type: Type.STRING },
          paymentMethod: { type: Type.STRING, enum: ["CASH", "TRANSFER", "PAID"] }
        },
        required: ["customerName", "address"],
      },
    },
  });

  if (response.text) {
    const raw = JSON.parse(response.text);
    let method = PaymentMethod.CASH;
    if (raw.paymentMethod === 'TRANSFER') method = PaymentMethod.TRANSFER;
    if (raw.paymentMethod === 'PAID') method = PaymentMethod.PAID;

    return { ...raw, paymentMethod: method } as SmartParseResult;
  }
  throw new Error("Failed to parse order text");
};

export const generateDeliveryMessage = async (order: Order): Promise<string> => {
  // Template tin nhắn ngắn gọn, đầy đủ
  let statusText = "";
  switch(order.status) {
      case OrderStatus.PENDING: statusText = "đang chờ xử lý"; break;
      case OrderStatus.PICKED_UP: statusText = "đã được lấy"; break;
      case OrderStatus.IN_TRANSIT: statusText = "đang giao"; break;
      case OrderStatus.DELIVERED: statusText = "đã giao thành công"; break;
      case OrderStatus.CANCELLED: statusText = "đã hủy"; break;
  }

  const itemsList = order.items.map(i => `${i.name}${i.quantity > 1 ? ` (${i.quantity})` : ''}`).join(", ");

  const priceFormatted = new Intl.NumberFormat('vi-VN').format(order.totalPrice);
  const paymentText = order.paymentMethod === PaymentMethod.CASH 
    ? `Thu: ${priceFormatted}đ` 
    : "Đã thanh toán";

  return `Chào ${order.customerName}, đơn ${itemsList} ${statusText}. ${paymentText}. Cảm ơn!`;
};

// Update: Use gemini-3-flash-preview for data extraction from raw text tasks
export const structureImportData = async (rawText: string): Promise<RawPDFImportData[]> => {
  const ai = getClient();

  const prompt = `
    You are a data extraction assistant. 
    I will provide raw text extracted from a PDF/Excel file containing a list of orders (Vietnamese).

    IMPORTANT: 
    1. Vietnamese text extracted from PDF often has broken spaces or corrupted fonts (e.g., "K h á c h H à n g" or "N g u y ? n"). 
       You MUST intelligently merge these characters to form correct Vietnamese words.
    2. The input might be unstructured. Look for rows that contain Price, Name, Address, and Items.

    INPUT TEXT:
    ${rawText.substring(0, 30000)} 
    (Text truncated if too long)

    EXTRACTION RULES:
    1. Look for rows representing distinct orders.
    2. 'unit_price': Convert string like "120" to number 120. If "120.000", output 120. If price is missing or 0, return 0.
    3. 'customer_name': Reconstruct the name if broken.
    4. 'address': Reconstruct the address.
    5. 'phone': Phone number if available.
    6. 'items_raw': The string describing items (e.g., "gạo 2 cá 1"). Preserve quantity numbers.

    Ignore headers/footers.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                unit_price: { type: Type.NUMBER },
                customer_name: { type: Type.STRING },
                address: { type: Type.STRING },
                phone: { type: Type.STRING, nullable: true },
                items_raw: { type: Type.STRING }
            },
            required: ["unit_price", "customer_name", "address", "items_raw"]
        }
      },
    },
  });

  if (response.text) {
    try {
        return JSON.parse(response.text) as RawPDFImportData[];
    } catch (e) {
        console.error("Failed to parse AI response as JSON", e);
        throw new Error("AI trả về định dạng không hợp lệ.");
    }
  }
  return [];
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 10);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  // --- SMART SIDEBAR LOGIC (IMPROVED ACCURACY) ---
  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, number>();
      const currentBatch = batchId?.trim();

      orders.forEach(o => {
          if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  // Khớp theo ID sản phẩm hoặc Tên chuẩn hóa
                  const key = item.productId || normalizeString(item.name);
                  const currentQty = soldMap.get(key) || 0;
                  soldMap.set(key, currentQty + (Number(item.quantity) || 0));
              });
          }
      });

      return products.map(p => {
          // Lấy số lượng bán: ưu tiên ID, fallback về Tên
          const soldInBatch = soldMap.get(p.id) || soldMap.get(normalizeString(p.name)) || 0;
          return {
              product: p,
              soldInBatch: soldInBatch,
              stock: p.stockQuantity || 0
          };
      }).filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 1000 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ 
                ...prev, 
                customerName: res.customerName || prev.customerName, 
                customerPhone: res.customerPhone || prev.customerPhone, 
                address: res.address || prev.address, 
                notes: res.notes || prev.notes 
            }));
            if (res.parsedItems?.length) {
                setItems(res.parsedItems.map(pi => {
                    const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                    return { 
                        id: uuidv4(), 
                        name: matched ? matched.name : pi.productName, 
                        quantity: pi.quantity || 1, 
                        price: matched ? matched.defaultPrice : 0, 
                        productId: matched?.id 
                    };
                }));
            }
        } catch (error) {
            console.error("AI processing error:", error);
            toast.error("Lỗi xử lý đơn bằng AI");
        } finally {
            setIsProcessingAI(false);
        }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-bold text-eco-800">AI đang xử lý...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Nhập Đơn</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Thống Kê</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            {/* LEFT FORM */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/50">
                       <div className="flex items-center gap-2">
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border border-gray-300 rounded-lg px-2 py-1 shadow-sm hover:border-eco-400 cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-24 text-[10px] font-bold text-eco-700 outline-none bg-transparent" placeholder="LÔ-HÔM-NAY" />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-400 ml-1"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-40 bg-white border border-gray-200 rounded-lg shadow-xl z-50">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-3 py-2 hover:bg-eco-50 cursor-pointer text-xs font-medium border-b border-gray-50 last:border-0">{b}</div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[80px]">
                            <div className="text-[9px] text-gray-400 font-bold uppercase">Tổng thu</div>
                            <div className="text-xl font-black text-eco-700">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-xs font-medium text-gray-400">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3 px-4 font-bold text-sm shadow-lg active:scale-95 transition-all uppercase tracking-tight">Lưu Đơn Hàng <i className="fas fa-check-circle ml-1"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-3 pb-20">
                    <div className="bg-white p-3 rounded-xl border border-gray-300 space-y-2 shadow-sm">
                        <div className="grid grid-cols-12 gap-2" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-0.5 ml-1">Người nhận</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className="w-full p-2 bg-white border border-gray-300 rounded-lg outline-none text-sm font-bold text-gray-900 focus:border-eco-500" placeholder="Tên khách..." autoComplete="off" />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border border-gray-300 rounded-lg shadow-xl mt-1 max-h-40 overflow-y-auto">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-3 py-2 hover:bg-eco-50 cursor-pointer border-b border-gray-100 text-xs font-bold text-gray-800">{s.name} - <span className="font-normal text-gray-500">{s.phone}</span></li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-bold text-gray-500 uppercase mb-0.5 ml-1">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className="w-full p-2 bg-white border border-gray-300 rounded-lg outline-none text-sm text-gray-900 focus:border-eco-500" placeholder="09..." />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-0.5 ml-1">Địa chỉ</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className="w-full p-2 bg-white border border-gray-300 rounded-lg outline-none text-sm text-gray-900 focus:border-eco-500" placeholder="Địa chỉ giao hàng..." />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-gray-500 uppercase mb-0.5 ml-1">Ghi chú đơn hàng</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className="w-full p-2 bg-white border border-gray-300 rounded-lg outline-none text-xs text-gray-700 focus:border-eco-500" placeholder="Ghi chú thêm..." />
                        </div>
                    </div>

                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-xs font-bold text-gray-500 uppercase">Hàng hóa trong đơn</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-bold text-eco-700 bg-eco-50 px-2 py-1 rounded border border-eco-200">+ Dòng mới</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-2 bg-white p-2 rounded-lg border border-gray-300 shadow-sm relative">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-1.5 bg-gray-50 border border-gray-200 rounded text-sm font-bold text-gray-900 outline-none focus:bg-white focus:border-eco-500" placeholder="Sản phẩm..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-300 rounded-lg shadow-xl z-50 max-h-40 overflow-y-auto">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-3 py-2 hover:bg-eco-50 cursor-pointer flex justify-between items-center border-b border-gray-100">
                                                    <div className="text-xs font-bold text-gray-800">{p.name} <span className="text-[9px] text-gray-400">(Tồn: {p.stockQuantity})</span></div>
                                                    <div className="text-[10px] font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}</div>
                                                </div>
                                            ))}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-2 bg-gray-50 text-center text-xs font-bold text-eco-600 hover:bg-eco-100 cursor-pointer border-t border-gray-100">+ Tạo sản phẩm mới</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-12">
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-1.5 text-center bg-gray-50 border border-gray-200 rounded text-sm font-bold text-gray-900 outline-none focus:bg-white focus:border-eco-500" />
                                </div>
                                <div className="w-20">
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-1.5 text-right bg-gray-50 border border-gray-200 rounded text-sm font-bold text-gray-900 outline-none focus:bg-white focus:border-eco-500" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-400 hover:text-red-500"><i className="fas fa-times-circle"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            {/* RIGHT SIDEBAR - SMART STATS */}
            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-3 bg-white border-b border-gray-200">
                    <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-3">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => (
                            <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1.5 text-[10px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>
                                {tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}
                            </button>
                        ))}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <i className="fas fa-search absolute left-2 top-2 text-gray-300 text-[10px]"></i>
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-7 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded-lg text-xs outline-none focus:bg-white text-gray-800" placeholder="Tìm sản phẩm bất kỳ..." />
                        </div>
                    )}
                </div>

                <div className="flex-grow overflow-y-auto p-2 space-y-2">
                    {filteredSidebarProducts.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-300 opacity-50">
                            <i className="fas fa-layer-group text-2xl mb-2"></i>
                            <p className="text-[10px] font-bold uppercase">Trống</p>
                        </div>
                    ) : (
                        filteredSidebarProducts.map((item) => (
                            <div key={item.product.id} className="bg-white p-2 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
                                <div className="flex justify-between items-start mb-1">
                                    <div className="flex-grow min-w-0 pr-8">
                                        <div onClick={() => handleQuickInsert(item.product)} className="font-bold text-xs text-gray-800 truncate cursor-pointer hover:text-eco-600">{item.product.name}</div>
                                        <div className="text-[9px] text-gray-400 font-bold uppercase">{new Intl.NumberFormat('vi-VN').format(item.product.defaultPrice)}đ / sp</div>
                                    </div>
                                    <button onClick={() => handleEditProduct(item.product)} className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 text-gray-300 hover:text-blue-600 transition-opacity"><i className="fas fa-edit text-[10px]"></i></button>
                                </div>
                                <div className="flex items-end justify-between gap-2">
                                    <div className="flex-grow">
                                        <div className="flex justify-between text-[9px] font-bold mb-0.5">
                                            <span className="text-gray-400 uppercase">Tồn kho</span>
                                            <span className={item.stock < 5 ? 'text-red-500' : 'text-eco-600'}>{item.stock} cái</span>
                                        </div>
                                        <div className="w-full bg-gray-100 rounded-full h-1 overflow-hidden">
                                            <div className={`h-full rounded-full ${item.stock < 5 ? 'bg-red-400' : 'bg-eco-400'}`} style={{ width: `${Math.min(100, (item.stock / 50) * 100)}%` }}></div>
                                        </div>
                                    </div>
                                    {item.soldInBatch > 0 && (
                                        <div className="text-right shrink-0">
                                            <div className="text-[9px] text-purple-400 font-bold uppercase">Đã bán</div>
                                            <div className="text-sm font-black text-purple-700 leading-none">{item.soldInBatch}</div>
                                        </div>
                                    )}
                                </div>
                                {/* Quick Add Button Overlay */}
                                <div onClick={() => handleQuickInsert(item.product)} className="absolute inset-y-0 left-0 w-1 bg-transparent group-hover:bg-eco-500 cursor-pointer transition-colors"></div>
                            </div>
                        ))
                    )}
                </div>
                <div className="p-3 bg-white border-t border-gray-200 text-[9px] text-gray-400 text-center italic">Bấm vào tên để chèn nhanh vào đơn</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

