  getProductOrderHistory: (productId: string) => {
      const orders = ensureOrdersLoaded();
      const history: { order: Order, quantity: number }[] = [];
      orders.forEach(o => {
          o.items.forEach(i => {
              if (i.productId === productId) history.push({ order: o, quantity: i.quantity });
          });
      });
      return history;
