  learnRoutePriority: async (sortedOrders: Order[]) => {
      // Logic để lưu độ ưu tiên khách hàng dựa trên vị trí trong list đã sắp xếp
      for (let i = 0; i < sortedOrders.length; i++) {
          const o = sortedOrders[i];
          if (o.customerId) {
              const custList = await storageService.getAllCustomers();
              const cust = custList.find(c => c.id === o.customerId);
              if (cust) {
                  cust.priorityScore = i + 1;
                  await storageService.upsertCustomer(cust);
              }
          }
      }
  },

  // --- CUSTOMER MANAGEMENT ---
  subscribeCustomers: (callback: (c: Customer[]) => void) => {
      const load = () => {
          try {
              const local = localStorage.getItem(CUSTOMER_KEY);
              _memoryCustomers = local ? (JSON.parse(local) as Customer[]) : [];
              callback(_memoryCustomers || []);
          } catch { callback([]); }
      };
      load();
      if (isOnline()) {
          return onSnapshot(collection(db, "customers"), (snap) => {
              const l: Customer[] = [];
              snap.forEach(d => l.push(d.data() as Customer));
              if (l.length > 0) {
                _memoryCustomers = l;
                localStorage.setItem(CUSTOMER_KEY, JSON.stringify(l));
                callback(l);
              }
          });
      }
  },

  // Added explicit return type and type cast
  getAllCustomers: async (): Promise<Customer[]> => {
      if (_memoryCustomers) return _memoryCustomers;
      const local = localStorage.getItem(CUSTOMER_KEY);
      return local ? (JSON.parse(local) as Customer[]) : [];
  },

  upsertCustomer: async (c: Customer) => {
      const list = await storageService.getAllCustomers();
      const idx = list.findIndex(x => x.id === c.id);
      const cSave = { ...c, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.unshift(cSave);
      _memoryCustomers = list;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => setDoc(doc(db, "customers", c.id), sanitize(cSave)));
  },

  deleteCustomer: async (id: string) => {
      const list = (await storageService.getAllCustomers()).filter(c => c.id !== id);
      _memoryCustomers = list;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => deleteDoc(doc(db, "customers", id)));
  },

  importCustomersBatch: async (customers: Customer[], localOnly: boolean = false) => {
      const list = await storageService.getAllCustomers();
      // Explicitly typed Map to avoid unknown inference
      const newMap = new Map<string, Customer>(list.map(c => [c.id, c]));
      customers.forEach(c => newMap.set(c.id, { ...c, updatedAt: Date.now() }));
      const finalList = Array.from(newMap.values());
      _memoryCustomers = finalList;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(finalList));
      if (!localOnly && isOnline()) {
          const chunks = [];
          for (let i = 0; i < customers.length; i += 400) {
              chunks.push(customers.slice(i, i + 400));
          }
          for (const chunk of chunks) {
              const batch = writeBatch(db);
              chunk.forEach(c => batch.set(doc(db, "customers", c.id), sanitize(c)));
              await batch.commit();
          }
      }
  },

  clearAllCustomers: async (localOnly: boolean = false) => {
      localStorage.removeItem(CUSTOMER_KEY);
      _memoryCustomers = [];
      if (!localOnly && isOnline()) {
          const snap = await getDocs(collection(db, "customers"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      }
  },

  markAllCustomersAsOld: async () => {
      const list = await storageService.getAllCustomers();
      list.forEach(c => { c.isLegacy = true; c.totalOrders = (c.totalOrders || 0) + 1; });
      await storageService.importCustomersBatch(list);
      return list.length;
  },

  fixDuplicateCustomerIds: async () => {
      const list = await storageService.getAllCustomers();
      const seen = new Set();
      let fixed = 0;
      for (const c of list) {
          if (seen.has(c.id)) {
              c.id = uuidv4();
              fixed++;
          }
          seen.add(c.id);
      }
      if (fixed > 0) await storageService.importCustomersBatch(list);
      return fixed;
  },

  mergeCustomersByPhone: async () => {
      const list = await storageService.getAllCustomers();
      const phoneMap = new Map<string, Customer[]>();
      list.forEach(c => {
          if (c.phone) {
              const p = normalizePhone(c.phone);
              if (!phoneMap.has(p)) phoneMap.set(p, []);
              phoneMap.get(p)!.push(c);
          }
      });
      let mergedGroups = 0;
      for (const [phone, group] of phoneMap.entries()) {
          if (group.length > 1) {
              group.sort((a, b) => (b.totalOrders || 0) - (a.totalOrders || 0));
              const primary = group[0];
              for (let i = 1; i < group.length; i++) {
                  primary.totalOrders = (primary.totalOrders || 0) + (group[i].totalOrders || 0);
                  await storageService.deleteCustomer(group[i].id);
              }
              await storageService.upsertCustomer(primary);
              mergedGroups++;
          }
      }
      return mergedGroups;
  },

  isNewCustomer: (phone: string, addr: string, id?: string) => {
      const list = ensureOrdersLoaded();
      if (id) return !list.some(o => o.customerId === id);
      const p = normalizePhone(phone);
      if (p.length > 8) return !list.some(o => normalizePhone(o.customerPhone) === p);
      return !list.some(o => normalizeString(o.address) === normalizeString(addr));
  },

  findMatchingCustomer: (phone: string, addr: string, id?: string) => {
      const list = _memoryCustomers || [];
      if (id) return list.find(c => c.id === id);
      const p = normalizePhone(phone);
      if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
      const nAddr = normalizeString(addr);
      return list.find(c => normalizeString(c.address) === nAddr);
  },

  // --- NOTIFICATION MANAGEMENT ---
  subscribeNotifications: (callback: (notifs: Notification[]) => void) => {
      const load = () => {
          try {
              const local = localStorage.getItem(NOTIF_KEY);
              callback(local ? (JSON.parse(local) as Notification[]) : []);
          } catch { callback([]); }
      };
      load();
      if (isOnline()) {
          return onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc"), limit(50)), (snap) => {
              const list: Notification[] = [];
              snap.forEach(d => list.push(d.data() as Notification));
              localStorage.setItem(NOTIF_KEY, JSON.stringify(list));
              callback(list);
          });
      }
  },

  markNotificationRead: async (id: string) => {
      await safeCloudOp(() => updateDoc(doc(db, "notifications", id), { isRead: true }));
      window.dispatchEvent(new CustomEvent('local_notif_read', { detail: id }));
  },

  markAllNotificationsRead: async () => {
      if (isOnline()) {
          const snap = await getDocs(query(collection(db, "notifications"), where("isRead", "==", false)));
          const batch = writeBatch(db);
          snap.forEach(d => batch.update(d.ref, { isRead: true }));
          await batch.commit();
      }
      window.dispatchEvent(new Event('local_notif_read_all'));
  },

  clearAllNotifications: async () => {
      localStorage.removeItem(NOTIF_KEY);
      if (isOnline()) {
          const snap = await getDocs(collection(db, "notifications"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      }
      window.dispatchEvent(new Event('local_notif_clear_all'));
  },

  // --- UTILS ---
  // Added explicit return type
  fetchLongTermStats: async (): Promise<Order[]> => {
      if (isOnline()) {
          const snap = await getDocs(query(collection(db, "orders"), limit(2000)));
          return snap.docs.map(d => d.data() as Order);
      }
      return ensureOrdersLoaded();
  },

  // Explicitly typing Customer objects inside generatePerformanceData
  generatePerformanceData: async (count: number) => {
      const start = Date.now();
      const fakeCustomers: Customer[] = [];
      for (let i = 0; i < count; i++) {
          const newCustomer: Customer = {
              id: uuidv4(),
              name: `Khách Hàng Ảo ${i}`,
              phone: `09${Math.floor(10000000 + Math.random() * 90000000)}`,
              address: `${i} Đường ABC, Quận XYZ, TP. HCM`,
              lastOrderDate: Date.now(),
              priorityScore: 999
          };
          fakeCustomers.push(newCustomer);
      }
      await storageService.importCustomersBatch(fakeCustomers, true);
      return { count, duration: Date.now() - start };
  }
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 10);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  // --- SMART SIDEBAR LOGIC (ENHANCED FOR ACCURACY) ---
  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();

      // 1. Quét thực tế tất cả sản phẩm trong các đơn hàng của Lô
      orders.forEach(o => {
          if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId };
                  existing.qty += (Number(item.quantity) || 0);
                  soldMap.set(normName, existing);
              });
          }
      });

      // 2. Chuẩn bị danh sách hiển thị
      // Bắt đầu bằng việc map từ Kho hàng để có đầy đủ thông tin tồn kho
      const inventoryItems = products.map(p => {
          const normName = normalizeString(p.name);
          const soldData = soldMap.get(normName);
          if (soldData) soldMap.delete(normName); // Đánh dấu đã xử lý

          return {
              product: p,
              soldInBatch: soldData?.qty || 0,
              stock: p.stockQuantity || 0,
              isGhost: false
          };
      });

      // 3. Xử lý các món "Ghost" (Món có trong đơn nhưng không có trong kho)
      const ghostItems = Array.from(soldMap.values()).map(ghost => ({
          product: { id: ghost.productId || 'GHOST', name: ghost.name, defaultPrice: 0, stockQuantity: 0 } as Product,
          soldInBatch: ghost.qty,
          stock: 0,
          isGhost: true
      }));

      const allItems = [...inventoryItems, ...ghostItems];

      return allItems.filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return !item.isGhost && item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 1000 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ 
                ...prev, 
                customerName: res.customerName || prev.customerName, 
                customerPhone: res.customerPhone || prev.customerPhone, 
                address: res.address || prev.address, 
                notes: res.notes || prev.notes 
            }));
            if (res.parsedItems?.length) {
                setItems(res.parsedItems.map(pi => {
                    const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                    return { 
                        id: uuidv4(), 
                        name: matched ? matched.name : pi.productName, 
                        quantity: pi.quantity || 1, 
                        price: matched ? matched.defaultPrice : 0, 
                        productId: matched?.id 
                    };
                }));
            }
        } catch (error) {
            console.error("AI processing error:", error);
            toast.error("Lỗi xử lý đơn bằng AI");
        } finally {
            setIsProcessingAI(false);
        }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  };

  // Reusable input class for design consistency
  const inputBaseClass = "w-full p-2.5 bg-gray-50 border border-gray-300 rounded-xl outline-none text-sm font-bold text-gray-900 placeholder-gray-400 focus:bg-white focus:border-eco-600 focus:ring-4 focus:ring-eco-50 transition-all";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-bold text-eco-800">AI đang xử lý...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Nhập Đơn</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Thống Kê</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            {/* LEFT FORM */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/50">
                       <div className="flex items-center gap-2">
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border border-gray-300 rounded-lg px-2 py-1 shadow-sm hover:border-eco-400 cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-24 text-[10px] font-black text-eco-700 outline-none bg-transparent" placeholder="LÔ-HÔM-NAY" />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-400 ml-1"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-40 bg-white border border-gray-200 rounded-lg shadow-xl z-50">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-3 py-2 hover:bg-eco-50 cursor-pointer text-xs font-medium border-b border-gray-50 last:border-0">{b}</div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[80px]">
                            <div className="text-[9px] text-gray-400 font-bold uppercase">Tổng thu</div>
                            <div className="text-xl font-black text-eco-700">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-xs font-medium text-gray-400">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3 px-4 font-bold text-sm shadow-lg active:scale-95 transition-all uppercase tracking-tight">Lưu Đơn Hàng <i className="fas fa-check-circle ml-1"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-4 pb-20">
                    <div className="bg-white p-3 rounded-2xl border border-gray-200 space-y-3 shadow-sm">
                        <div className="grid grid-cols-12 gap-3" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Người nhận</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách..." autoComplete="off" />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border border-gray-200 rounded-xl shadow-2xl mt-1 max-h-48 overflow-y-auto border-t-4 border-t-eco-500">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-eco-50 cursor-pointer border-b border-gray-50 flex flex-col">
                                                <span className="text-sm font-black text-gray-800">{s.name}</span>
                                                <span className="text-[10px] text-gray-500">{s.phone} - {s.address}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09..." />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Địa chỉ giao hàng</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputBaseClass} placeholder="Số nhà, đường, quận..." />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Ghi chú (Giao giờ hành chính, gọi trước...)</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputBaseClass} placeholder="Lời nhắn cho shipper..." />
                        </div>
                    </div>

                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-xs font-black text-gray-500 uppercase tracking-widest">Danh sách hàng hóa</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-black text-eco-700 bg-eco-50 px-3 py-1.5 rounded-lg border border-eco-200 hover:bg-eco-100 transition-colors">+ THÊM DÒNG</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-2 bg-white p-2 rounded-xl border border-gray-200 shadow-sm relative group">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-2 bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600 transition-all" placeholder="Sản phẩm..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-xl shadow-2xl z-50 max-h-48 overflow-y-auto border-t-4 border-t-blue-500">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-4 py-3 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-50">
                                                    <div className="flex flex-col">
                                                        <span className="text-sm font-black text-gray-800">{p.name}</span>
                                                        <span className="text-[10px] text-gray-400 font-bold uppercase">Tồn kho: {p.stockQuantity}</span>
                                                    </div>
                                                    <div className="text-xs font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</div>
                                                </div>
                                            ))}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-3 bg-gray-50 text-center text-xs font-black text-eco-600 hover:bg-eco-100 cursor-pointer border-t border-gray-100 italic">+ Tạo sản phẩm mới vào kho</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-16">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">SL</label>
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-2 text-center bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-eco-700 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <div className="w-24">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">Đơn giá</label>
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-2 text-right bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-500 transition-colors p-1"><i className="fas fa-times-circle"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            {/* RIGHT SIDEBAR - SMART STATS */}
            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-3 bg-white border-b border-gray-200">
                    <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-3">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => (
                            <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1.5 text-[10px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>
                                {tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}
                            </button>
                        ))}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <i className="fas fa-search absolute left-3 top-2.5 text-gray-300 text-[10px]"></i>
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-8 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold outline-none focus:bg-white text-gray-800" placeholder="Mã hoặc tên sản phẩm..." />
                        </div>
                    )}
                </div>

                <div className="flex-grow overflow-y-auto p-2 space-y-2">
                    {filteredSidebarProducts.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-300 opacity-50">
                            <i className="fas fa-layer-group text-2xl mb-2"></i>
                            <p className="text-[10px] font-black uppercase tracking-widest">Không có dữ liệu</p>
                        </div>
                    ) : (
                        filteredSidebarProducts.map((item) => (
                            <div key={item.product.id + (item.isGhost ? '-ghost' : '')} className={`p-3 rounded-2xl border transition-all group relative overflow-hidden ${item.isGhost ? 'bg-orange-50 border-orange-100' : 'bg-white border-gray-100 shadow-sm hover:shadow-md'}`}>
                                <div className="flex justify-between items-start mb-1.5">
                                    <div className="flex-grow min-w-0 pr-8">
                                        <div onClick={() => handleQuickInsert(item.product)} className="font-black text-xs text-gray-800 truncate cursor-pointer hover:text-eco-600 transition-colors uppercase tracking-tight">{item.product.name}</div>
                                        <div className="flex items-center gap-2 mt-0.5">
                                            <span className="text-[9px] text-gray-400 font-bold uppercase">{new Intl.NumberFormat('vi-VN').format(item.product.defaultPrice)}đ</span>
                                            {item.isGhost && <span className="text-[8px] font-black bg-orange-200 text-orange-700 px-1 rounded">NGOÀI KHO</span>}
                                        </div>
                                    </div>
                                    {!item.isGhost && (
                                        <button onClick={() => handleEditProduct(item.product)} className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 text-gray-300 hover:text-blue-600 transition-all p-1 bg-white rounded shadow-sm border border-gray-100"><i className="fas fa-edit text-[10px]"></i></button>
                                    )}
                                </div>
                                <div className="flex items-end justify-between gap-3">
                                    <div className="flex-grow">
                                        <div className="flex justify-between text-[9px] font-black mb-1">
                                            <span className="text-gray-400 uppercase tracking-tighter">Hiện còn</span>
                                            <span className={item.stock < 5 ? 'text-red-500' : 'text-eco-600'}>{item.stock} sp</span>
                                        </div>
                                        <div className="w-full bg-gray-100 rounded-full h-1.5 overflow-hidden">
                                            <div className={`h-full rounded-full transition-all duration-500 ${item.stock < 5 ? 'bg-red-400' : 'bg-eco-400'}`} style={{ width: `${Math.min(100, (item.stock / 50) * 100)}%` }}></div>
                                        </div>
                                    </div>
                                    {item.soldInBatch > 0 && (
                                        <div className="text-right shrink-0 bg-eco-50 px-2 py-1 rounded-lg border border-eco-100">
                                            <div className="text-[8px] text-eco-400 font-black uppercase leading-none mb-0.5">Đã bán</div>
                                            <div className="text-sm font-black text-eco-700 leading-none">{item.soldInBatch}</div>
                                        </div>
                                    )}
                                </div>
                                {/* Quick Add Button Overlay Left Edge */}
                                <div onClick={() => handleQuickInsert(item.product)} className="absolute inset-y-0 left-0 w-1 bg-transparent group-hover:bg-eco-500 cursor-pointer transition-colors"></div>
                            </div>
                        ))
                    )}
                </div>
                <div className="p-3 bg-white border-t border-gray-100 text-[9px] text-gray-400 text-center italic font-bold">Bấm vào tên để chèn nhanh vào dòng trống</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 10);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();

      orders.forEach(o => {
          if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId };
                  existing.qty += (Number(item.quantity) || 0);
                  soldMap.set(normName, existing);
              });
          }
      });

      const inventoryItems = products.map(p => {
          const normName = normalizeString(p.name);
          const soldData = soldMap.get(normName);
          if (soldData) soldMap.delete(normName);

          return {
              product: p,
              soldInBatch: soldData?.qty || 0,
              stock: p.stockQuantity || 0,
              isGhost: false
          };
      });

      const ghostItems = Array.from(soldMap.values()).map(ghost => ({
          product: { id: ghost.productId || 'GHOST', name: ghost.name, defaultPrice: 0, stockQuantity: 0 } as Product,
          soldInBatch: ghost.qty,
          stock: 0,
          isGhost: true
      }));

      const allItems = [...inventoryItems, ...ghostItems];

      return allItems.filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return !item.isGhost && item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 1000 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ 
                ...prev, 
                customerName: res.customerName || prev.customerName, 
                customerPhone: res.customerPhone || prev.customerPhone, 
                address: res.address || prev.address, 
                notes: res.notes || prev.notes 
            }));
            if (res.parsedItems?.length) {
                setItems(res.parsedItems.map(pi => {
                    const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                    return { 
                        id: uuidv4(), 
                        name: matched ? matched.name : pi.productName, 
                        quantity: pi.quantity || 1, 
                        price: matched ? matched.defaultPrice : 0, 
                        productId: matched?.id 
                    };
                }));
            }
        } catch (error) {
            console.error("AI processing error:", error);
            toast.error("Lỗi xử lý đơn bằng AI");
        } finally {
            setIsProcessingAI(false);
        }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  };

  const inputBaseClass = "w-full p-2.5 bg-gray-50 border border-gray-300 rounded-xl outline-none text-sm font-bold text-gray-900 placeholder-gray-400 focus:bg-white focus:border-eco-600 focus:ring-4 focus:ring-eco-50 transition-all";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-bold text-eco-800">AI đang xử lý...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Nhập Đơn</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-bold border-b-2 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'text-gray-400'}`}>Thống Kê</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            {/* LEFT FORM */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/50">
                       <div className="flex items-center gap-2">
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border border-gray-300 rounded-lg px-2 py-1 shadow-sm hover:border-eco-400 cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-24 text-[10px] font-black text-eco-700 outline-none bg-transparent" placeholder="LÔ-HÔM-NAY" />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-400 ml-1"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-48 bg-white border border-gray-300 rounded-xl shadow-2xl z-[100] overflow-hidden">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-4 py-2.5 hover:bg-gray-100 cursor-pointer text-xs font-black text-gray-800 border-b border-gray-100 last:border-0 flex items-center gap-2">
                                                <i className="fas fa-layer-group text-gray-400"></i>
                                                {b}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[80px]">
                            <div className="text-[9px] text-gray-400 font-bold uppercase">Tổng thu</div>
                            <div className="text-xl font-black text-eco-700">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-xs font-medium text-gray-400">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3 px-4 font-bold text-sm shadow-lg active:scale-95 transition-all uppercase tracking-tight">Lưu Đơn Hàng <i className="fas fa-check-circle ml-1"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-4 pb-20">
                    <div className="bg-white p-3 rounded-2xl border border-gray-200 space-y-3 shadow-sm">
                        <div className="grid grid-cols-12 gap-3" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Người nhận</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách..." autoComplete="off" />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border border-gray-200 rounded-xl shadow-2xl mt-1 max-h-48 overflow-y-auto border-t-4 border-t-eco-500">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-eco-50 cursor-pointer border-b border-gray-50 flex flex-col">
                                                <span className="text-sm font-black text-gray-800">{s.name}</span>
                                                <span className="text-[10px] text-gray-500">{s.phone} - {s.address}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09..." />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Địa chỉ giao hàng</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputBaseClass} placeholder="Số nhà, đường, quận..." />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Ghi chú (Giao giờ hành chính, gọi trước...)</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputBaseClass} placeholder="Lời nhắn cho shipper..." />
                        </div>
                    </div>

                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-xs font-black text-gray-500 uppercase tracking-widest">Danh sách hàng hóa</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-black text-eco-700 bg-eco-50 px-3 py-1.5 rounded-lg border border-eco-200 hover:bg-eco-100 transition-colors">+ THÊM DÒNG</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-2 bg-white p-2 rounded-xl border border-gray-200 shadow-sm relative group">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-2 bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600 transition-all" placeholder="Sản phẩm..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-xl shadow-2xl z-50 max-h-48 overflow-y-auto border-t-4 border-t-blue-500">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-4 py-3 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-50">
                                                    <div className="flex flex-col">
                                                        <span className="text-sm font-black text-gray-800">{p.name}</span>
                                                        <span className="text-[10px] text-gray-400 font-bold uppercase">Tồn kho: {p.stockQuantity}</span>
                                                    </div>
                                                    <div className="text-xs font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</div>
                                                </div>
                                            ))}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-3 bg-gray-50 text-center text-xs font-black text-eco-600 hover:bg-eco-100 cursor-pointer border-t border-gray-100 italic">+ Tạo sản phẩm mới vào kho</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-16">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">SL</label>
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-2 text-center bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-eco-700 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <div className="w-24">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">Đơn giá</label>
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-2 text-right bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-500 transition-colors p-1"><i className="fas fa-times-circle"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            {/* RIGHT SIDEBAR - ULTRA COMPACT STATS */}
            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-3 bg-white border-b border-gray-200">
                    <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-2">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => (
                            <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1 text-[9px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>
                                {tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}
                            </button>
                        ))}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <i className="fas fa-search absolute left-2.5 top-2 text-gray-300 text-[9px]"></i>
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-7 pr-2 py-1.5 bg-gray-50 border border-gray-200 rounded-lg text-[10px] font-bold outline-none focus:bg-white text-gray-800" placeholder="Mã hoặc tên..." />
                        </div>
                    )}
                </div>

                <div className="flex-grow overflow-y-auto p-2 space-y-1">
                    {filteredSidebarProducts.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-300 opacity-50">
                            <i className="fas fa-layer-group text-xl mb-2"></i>
                            <p className="text-[9px] font-black uppercase tracking-widest">Trống</p>
                        </div>
                    ) : (
                        filteredSidebarProducts.map((item) => (
                            <div key={item.product.id + (item.isGhost ? '-ghost' : '')} className="flex items-center gap-2 p-1.5 hover:bg-white rounded-lg transition-colors border-b border-gray-100/50 group">
                                {/* Sold Counter Badge */}
                                {item.soldInBatch > 0 && (
                                    <div className="w-6 h-6 rounded bg-eco-600 text-white flex items-center justify-center text-[10px] font-black shrink-0 shadow-sm">
                                        {item.soldInBatch}
                                    </div>
                                )}

                                {/* Product Info (Compact) */}
                                <div className="flex-grow min-w-0">
                                    <div onClick={() => handleQuickInsert(item.product)} className="text-[11px] font-black text-gray-700 truncate cursor-pointer hover:text-eco-600 uppercase tracking-tight">
                                        {item.product.name}
                                    </div>
                                    <div className="flex items-center gap-1.5">
                                        <span className="text-[9px] text-gray-400 font-bold">{new Intl.NumberFormat('vi-VN').format(item.product.defaultPrice)}</span>
                                        {item.isGhost && <span className="text-[8px] font-black text-orange-600 bg-orange-50 px-1 rounded">GHOST</span>}
                                    </div>
                                </div>

                                {/* Stock Indicator (Minimal) */}
                                <div className="flex flex-col items-end shrink-0 pl-1">
                                    {!item.isGhost && (
                                        <>
                                            <div className={`text-[10px] font-black ${item.stock < 5 ? 'text-red-500' : 'text-gray-500'}`}>
                                                {item.stock}
                                            </div>
                                            <button onClick={() => handleEditProduct(item.product)} className="opacity-0 group-hover:opacity-100 text-[8px] text-blue-500 font-bold hover:underline transition-opacity">SỬA</button>
                                        </>
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                </div>
                <div className="p-2 bg-white border-t border-gray-100 text-[8px] text-gray-400 text-center font-bold italic uppercase">Bấm tên để chèn hàng</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 15);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();

      orders.forEach(o => {
          if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId };
                  existing.qty += (Number(item.quantity) || 0);
                  soldMap.set(normName, existing);
              });
          }
      });

      const inventoryItems = products.map(p => {
          const normName = normalizeString(p.name);
          const soldData = soldMap.get(normName);
          if (soldData) soldMap.delete(normName);

          return {
              product: p,
              soldInBatch: soldData?.qty || 0,
              stock: p.stockQuantity || 0,
              isExternal: false
          };
      });

      const externalItems = Array.from(soldMap.values()).map(ext => ({
          product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product,
          soldInBatch: ext.qty,
          stock: 0,
          isExternal: true
      }));

      const allItems = [...inventoryItems, ...externalItems];

      return allItems.filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 800 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ 
                ...prev, 
                customerName: res.customerName || prev.customerName, 
                customerPhone: res.customerPhone || prev.customerPhone, 
                address: res.address || prev.address, 
                notes: res.notes || prev.notes 
            }));
            if (res.parsedItems?.length) {
                setItems(res.parsedItems.map(pi => {
                    const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                    return { 
                        id: uuidv4(), 
                        name: matched ? matched.name : pi.productName, 
                        quantity: pi.quantity || 1, 
                        price: matched ? matched.defaultPrice : 0, 
                        productId: matched?.id 
                    };
                }));
            }
        } catch (error) {
            console.error("AI processing error:", error);
            toast.error("Lỗi xử lý đơn bằng AI");
        } finally {
            setIsProcessingAI(false);
        }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  };

  const inputBaseClass = "w-full p-2.5 bg-gray-50 border border-gray-300 rounded-xl outline-none text-sm font-bold text-gray-900 placeholder-gray-400 focus:bg-white focus:border-eco-600 focus:ring-4 focus:ring-eco-50 transition-all";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-black text-eco-800">AI ĐANG PHÂN TÍCH...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-black border-b-4 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>NHẬP ĐƠN</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-black border-b-4 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>THỐNG KÊ LÔ</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            {/* LEFT FORM */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/80">
                       <div className="flex items-center gap-2">
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border-2 border-gray-400 rounded-lg px-2 py-1 shadow-sm hover:border-black cursor-pointer transition-colors" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-28 text-[10px] font-black text-gray-800 outline-none bg-transparent uppercase" placeholder="NHẬP TÊN LÔ..." />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-800 ml-2"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-52 bg-white border-2 border-gray-800 rounded-xl shadow-2xl z-[100] overflow-hidden">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-4 py-2.5 hover:bg-gray-100 cursor-pointer text-xs font-black text-gray-900 border-b border-gray-100 last:border-0 flex items-center gap-3">
                                                <i className="fas fa-box text-gray-400"></i>
                                                {b}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-white border-2 border-gray-200 text-gray-600 hover:border-gray-400'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[90px]">
                            <div className="text-[9px] text-gray-400 font-black uppercase">Tổng thu</div>
                            <div className="text-2xl font-black text-eco-700 tracking-tighter">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-[10px] font-bold text-gray-400 ml-0.5">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3.5 px-4 font-black text-sm shadow-xl active:scale-95 transition-all uppercase tracking-widest">XÁC NHẬN LƯU ĐƠN <i className="fas fa-check-circle ml-2"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-4 pb-20">
                    <div className="bg-white p-4 rounded-2xl border border-gray-200 space-y-3 shadow-sm">
                        <div className="grid grid-cols-12 gap-3" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Người nhận hàng</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách..." autoComplete="off" />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border-2 border-gray-200 rounded-xl shadow-2xl mt-1 max-h-48 overflow-y-auto border-t-4 border-t-eco-600">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-eco-50 cursor-pointer border-b border-gray-50 flex flex-col">
                                                <span className="text-sm font-black text-gray-900">{s.name}</span>
                                                <span className="text-[10px] text-gray-500 font-bold uppercase">{s.phone} • {s.address}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09..." />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Địa chỉ giao hàng</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputBaseClass} placeholder="Số nhà, đường, phường, quận..." />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Ghi chú vận chuyển</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputBaseClass} placeholder="Ví dụ: Giao giờ hành chính, gọi trước..." />
                        </div>
                    </div>

                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-xs font-black text-gray-500 uppercase tracking-widest flex items-center gap-2">
                                <i className="fas fa-shopping-basket"></i> Danh mục hàng
                            </h3>
                            <button type="button" onClick={addItemRow} className="text-[9px] font-black text-eco-700 bg-eco-50 px-3 py-1.5 rounded-lg border border-eco-200 hover:bg-eco-100 transition-colors uppercase">+ THÊM DÒNG</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-2 bg-white p-2 rounded-xl border border-gray-300 shadow-sm relative group">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-2.5 bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600 transition-all uppercase placeholder-gray-300" placeholder="Tên hàng..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border-2 border-gray-200 rounded-xl shadow-2xl z-50 max-h-48 overflow-y-auto border-t-4 border-t-blue-600">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => (
                                                <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-4 py-3 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-50">
                                                    <div className="flex flex-col min-w-0 pr-2">
                                                        <span className="text-sm font-black text-gray-800 truncate uppercase">{p.name}</span>
                                                        <span className="text-[10px] text-gray-400 font-black uppercase tracking-tighter">Kho: {p.stockQuantity} sp</span>
                                                    </div>
                                                    <div className="text-xs font-black text-blue-600 shrink-0">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</div>
                                                </div>
                                            ))}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-3 bg-gray-50 text-center text-[10px] font-black text-eco-600 hover:bg-eco-100 cursor-pointer border-t border-gray-100 italic uppercase">+ Tạo mặt hàng mới vào kho</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-14">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">SL</label>
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-2.5 text-center bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-eco-700 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <div className="w-24">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">Giá</label>
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-2.5 text-right bg-gray-50 border border-gray-200 rounded-lg text-sm font-black text-gray-900 outline-none focus:bg-white focus:border-eco-600" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-600 transition-colors p-1"><i className="fas fa-times-circle text-lg"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            {/* RIGHT SIDEBAR - ULTRA COMPACT STATS */}
            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-3 bg-white border-b border-gray-200">
                    <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-2">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => (
                            <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1.5 text-[9px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>
                                {tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}
                            </button>
                        ))}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <i className="fas fa-search absolute left-2.5 top-2.5 text-gray-300 text-[9px]"></i>
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-7 pr-2 py-2 bg-gray-100 border border-gray-200 rounded-lg text-[10px] font-black outline-none focus:bg-white text-gray-800 uppercase" placeholder="TÌM MÃ HOẶC TÊN..." />
                        </div>
                    )}
                </div>

                <div className="flex-grow overflow-y-auto p-1.5 space-y-0.5">
                    {filteredSidebarProducts.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-300 opacity-50">
                            <i className="fas fa-layer-group text-xl mb-2"></i>
                            <p className="text-[9px] font-black uppercase tracking-widest">KHÔNG CÓ DỮ LIỆU</p>
                        </div>
                    ) : (
                        filteredSidebarProducts.map((item) => (
                            <div key={item.product.id + (item.isExternal ? '-ext' : '')} className={`flex items-center gap-2 p-1.5 hover:bg-white rounded transition-colors border-b border-gray-100/30 group ${item.isExternal ? 'bg-orange-50/50' : ''}`}>
                                {/* Compact Badge Status */}
                                <div className={`w-5 h-5 rounded flex items-center justify-center text-[9px] font-black shrink-0 shadow-sm ${item.isExternal ? 'bg-orange-600 text-white' : item.soldInBatch > 0 ? 'bg-eco-600 text-white' : 'bg-gray-200 text-gray-500'}`}>
                                    {item.soldInBatch > 0 ? item.soldInBatch : '0'}
                                </div>

                                {/* Info */}
                                <div className="flex-grow min-w-0">
                                    <div onClick={() => handleQuickInsert(item.product)} className={`text-[10px] font-black truncate cursor-pointer hover:text-eco-600 uppercase tracking-tighter ${item.isExternal ? 'text-orange-700' : 'text-gray-700'}`}>
                                        {item.product.name}
                                    </div>
                                    <div className="flex items-center gap-1.5 leading-none">
                                        <span className="text-[8px] text-gray-400 font-bold">{new Intl.NumberFormat('vi-VN').format(item.product.defaultPrice)}đ</span>
                                        {item.isExternal && <span className="text-[7px] font-black text-orange-600 bg-orange-100 px-1 rounded uppercase">HÀNG NGOÀI</span>}
                                    </div>
                                </div>

                                {/* Stock Minimal */}
                                <div className="flex flex-col items-end shrink-0 pl-1 leading-none">
                                    {!item.isExternal && (
                                        <>
                                            <div className={`text-[10px] font-black ${item.stock < 5 ? 'text-red-500' : 'text-gray-500'}`}>
                                                T:{item.stock}
                                            </div>
                                            <button onClick={() => handleEditProduct(item.product)} className="opacity-0 group-hover:opacity-100 text-[8px] text-blue-600 font-black hover:underline transition-opacity">SỬA</button>
                                        </>
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                </div>
                <div className="p-2 bg-white border-t border-gray-100 text-[8px] text-gray-400 text-center font-black italic uppercase tracking-tighter">Bấm tên để thêm vào đơn</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 
  const [quickTags, setQuickTags] = useState<string[]>([]);

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<SidebarTab>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({
    customerId: '',
    customerName: '',
    customerPhone: '',
    address: '',
    notes: '',
  });

  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: uuidv4(), name: '', quantity: 1, price: 0 },
  ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    // Load Quick Tags
    setQuickTags(storageService.getQuickTags());

    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => {
            if (o.batchId) {
                const lastTime = batchActivity.get(o.batchId) || 0;
                batchActivity.set(o.batchId, Math.max(lastTime, o.createdAt));
            }
        });
        const sortedBatches = Array.from(batchActivity.entries())
            .sort((a, b) => b[1] - a[1])
            .map(entry => entry[0])
            .slice(0, 15);
        setExistingBatches(sortedBatches);
        setBatchId(prev => {
           if (prev) return prev;
           const today = new Date().toISOString().slice(0, 10);
           return sortedBatches.find(b => b.includes(today)) || `LÔ-${today}`;
        });
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(event.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(event.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(event.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();

    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers();
        if (unsubOrders) unsubOrders();
    };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();

      orders.forEach(o => {
          if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) {
              o.items.forEach(item => {
                  const normName = normalizeString(item.name);
                  const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId };
                  existing.qty += (Number(item.quantity) || 0);
                  soldMap.set(normName, existing);
              });
          }
      });

      const inventoryItems = products.map(p => {
          const normName = normalizeString(p.name);
          const soldData = soldMap.get(normName);
          if (soldData) soldMap.delete(normName);

          return {
              product: p,
              soldInBatch: soldData?.qty || 0,
              stock: p.stockQuantity || 0,
              isExternal: false
          };
      });

      const externalItems = Array.from(soldMap.values()).map(ext => ({
          product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product,
          soldInBatch: ext.qty,
          stock: 0,
          isExternal: true
      }));

      const allItems = [...inventoryItems, ...externalItems];

      return allItems.filter(item => {
          if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0;
          if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10;
          if (sidebarTab === 'SEARCH') {
              if (!sidebarSearch) return true;
              return normalizeString(item.product.name).includes(normalizeString(sidebarSearch));
          }
          return false;
      }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleQuickInsert = (product: Product) => {
      const lastItem = items[items.length - 1];
      if (!lastItem.name) {
          const newItems = [...items];
          newItems[items.length - 1] = {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          };
          setItems(newItems);
      } else {
          setItems([...items, {
              id: uuidv4(),
              productId: product.id,
              name: product.name,
              price: product.defaultPrice,
              quantity: 1
          }]);
      }
      toast.success(`Đã thêm ${product.name}`, { position: 'bottom-center', duration: 800 });
  };

  const handleEditProduct = (product: Product) => {
      setEditingProduct(product);
      setEditMode('IMPORT');
      setShowProductModal(true);
  };

  const handleSaveProduct = async (productData: Product, isImportMode: boolean = false, importQty: number = 0) => {
      if (isImportMode && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, importQty, {
              price: productData.importPrice || 0,
              note: 'Nhập thêm khi đang lên đơn'
          });
      } else {
          await storageService.saveProduct(productData);
      }
      toast.success("Đã cập nhật hàng hóa");
      setEditingProduct(null);
  };

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ giọng nói"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ 
                ...prev, 
                customerName: res.customerName || prev.customerName, 
                customerPhone: res.customerPhone || prev.customerPhone, 
                address: res.address || prev.address, 
                notes: res.notes || prev.notes 
            }));
            if (res.parsedItems?.length) {
                setItems(res.parsedItems.map(pi => {
                    const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName));
                    return { 
                        id: uuidv4(), 
                        name: matched ? matched.name : pi.productName, 
                        quantity: pi.quantity || 1, 
                        price: matched ? matched.defaultPrice : 0, 
                        productId: matched?.id 
                    };
                }));
            }
        } catch (error) {
            console.error("AI processing error:", error);
            toast.error("Lỗi xử lý đơn bằng AI");
        } finally {
            setIsProcessingAI(false);
        }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => {
    if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; }
    const newItems = [...items];
    newItems.splice(index, 1);
    setItems(newItems);
  };

  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => {
    const newItems = [...items];
    newItems[index] = { ...newItems[index], [field]: value };
    if (field === 'name') newItems[index].productId = undefined; 
    setItems(newItems);
  };

  const selectProductForItem = (index: number, product: Product) => {
      const newItems = [...items];
      newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice };
      setItems(newItems);
      setActiveProductRow(null);
  };

  const addTagToNotes = (tag: string) => {
      setCustomerInfo(prev => ({
          ...prev,
          notes: prev.notes ? `${prev.notes}, ${tag}` : tag
      }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin bắt buộc'); return; }

    const newOrder: Order = {
      id: uuidv4().slice(0, 8).toUpperCase(),
      customerId: customerInfo.customerId,
      batchId: batchId,
      customerName: customerInfo.customerName,
      customerPhone: customerInfo.customerPhone,
      address: customerInfo.address,
      items: validItems,
      notes: customerInfo.notes,
      totalPrice: totalPrice,
      paymentMethod: PaymentMethod.CASH, 
      status: OrderStatus.PENDING,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      orderIndex: Date.now()
    };

    await storageService.saveOrder(newOrder);
    toast.success('Lên đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
    if (nameInputRef.current) nameInputRef.current.focus();
  };

  const inputBaseClass = "w-full p-2.5 bg-gray-50 border border-gray-300 rounded-xl outline-none text-sm font-bold text-gray-900 placeholder-gray-400 focus:bg-white focus:border-eco-600 focus:ring-4 focus:ring-eco-50 transition-all";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">

        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-sm font-black text-eco-800 tracking-widest">AI ĐANG PHÂN TÍCH...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-sm font-black border-b-4 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>NHẬP ĐƠN</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-sm font-black border-b-4 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>THỐNG KÊ LÔ</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            {/* LEFT FORM */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/80">
                       <div className="flex items-center gap-2">
                           <div className="relative" ref={batchWrapperRef}>
                                <div className="flex items-center bg-white border-2 border-gray-800 rounded-lg px-2 py-1 shadow-sm hover:border-black cursor-pointer transition-colors" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-28 text-[10px] font-black text-gray-800 outline-none bg-transparent uppercase" placeholder="LÔ HÀNG..." />
                                    <i className="fas fa-chevron-down text-[8px] text-gray-800 ml-2"></i>
                                </div>
                                {showBatchSuggestions && existingBatches.length > 0 && (
                                    <div className="absolute top-full left-0 mt-1 w-56 bg-white border-2 border-gray-800 rounded-xl shadow-2xl z-[100] overflow-hidden">
                                        {existingBatches.map(b => (
                                            <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-4 py-2.5 hover:bg-gray-100 cursor-pointer text-xs font-black text-gray-900 border-b border-gray-100 last:border-0 flex items-center gap-3">
                                                <i className="fas fa-box text-gray-400"></i>
                                                {b}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                       </div>
                       <div className="flex items-center gap-2">
                           <button onClick={handleVoiceInput} disabled={isListening} className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-white border-2 border-gray-200 text-gray-600 hover:border-gray-400'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                       </div>
                    </div>
                    <div className="px-4 py-2 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[90px]">
                            <div className="text-[9px] text-gray-400 font-black uppercase">Tổng thu</div>
                            <div className="text-2xl font-black text-eco-700 tracking-tighter">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-[10px] font-bold text-gray-400 ml-0.5">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-xl py-3.5 px-4 font-black text-sm shadow-xl active:scale-95 transition-all uppercase tracking-widest">XÁC NHẬN LƯU ĐƠN <i className="fas fa-check-circle ml-2"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-3 space-y-4 pb-20">
                    <div className="bg-white p-4 rounded-2xl border border-gray-200 space-y-3 shadow-sm">
                        <div className="grid grid-cols-12 gap-3" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Người nhận hàng</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách..." autoComplete="off" />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border-2 border-gray-200 rounded-xl shadow-2xl mt-1 max-h-48 overflow-y-auto border-t-4 border-t-eco-600">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-eco-50 cursor-pointer border-b border-gray-50 flex flex-col">
                                                <span className="text-sm font-black text-gray-900">{s.name}</span>
                                                <span className="text-[10px] text-gray-500 font-bold uppercase">{s.phone} • {s.address}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-wider">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09..." />
                            </div>
                        </div>
                        <div>
