                                {/* Compact Badge Status - High Density */}
                                <div className={`w-5 h-5 rounded flex items-center justify-center text-[9px] font-black shrink-0 shadow-sm ${item.isExternal ? 'bg-orange-600 text-white' : item.soldInBatch > 0 ? 'bg-eco-600 text-white' : 'bg-gray-200 text-gray-500'}`}>
                                    {item.soldInBatch > 0 ? item.soldInBatch : '0'}
                                </div>

                                {/* Info Row */}
                                <div className="flex-grow min-w-0 flex items-center justify-between gap-1 pr-1">
                                    <div onClick={() => handleQuickInsert(item.product)} className={`text-[10px] font-black truncate cursor-pointer hover:text-eco-600 uppercase tracking-tighter ${item.isExternal ? 'text-orange-700' : 'text-gray-700'}`}>
                                        {item.product.name}
                                    </div>
                                    <div className="flex items-center gap-1.5 leading-none shrink-0">
                                        {!item.isExternal && (
                                            <div className={`text-[10px] font-black ${item.stock < 5 ? 'text-red-500' : 'text-gray-400'}`}>
                                                T:{item.stock}
                                            </div>
                                        )}
                                        {item.isExternal && <span className="text-[7px] font-black text-orange-600 bg-orange-100 px-1 rounded border border-orange-200 uppercase">NGOÀI</span>}
                                        <button onClick={() => handleEditProduct(item.product)} className="opacity-0 group-hover:opacity-100 text-[8px] text-blue-600 font-black hover:underline transition-opacity">SỬA</button>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
                <div className="p-2 bg-white border-t border-gray-100 text-[8px] text-gray-400 text-center font-black italic uppercase tracking-tighter">Bấm tên để thêm nhanh hàng vào đơn</div>
            </div>
        </div>

      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

