          return saved ? JSON.parse(saved) : [];
      } catch {
          return [];
      }
  });

  useEffect(() => {
      localStorage.setItem('ecogo_filter_batch', JSON.stringify(filterBatch));
  }, [filterBatch]);

  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);

  const [sortBy, setSortBy] = useState<SortOption>('NEWEST');
  const [isCompactMode, setIsCompactMode] = useState(false); 
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [activeEditProductRow, setActiveEditProductRow] = useState<number | null>(null); 
  const [isHeaderVisible, setIsHeaderVisible] = useState(true);
  const observerTarget = useRef<HTMLDivElement>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const statusDropdownBtnRef = useRef<HTMLButtonElement>(null);
  const batchDropdownBtnRef = useRef<HTMLButtonElement>(null);
  const [activeDropdown, setActiveDropdown] = useState<'STATUS' | 'BATCH' | null>(null);
  const [dropdownPos, setDropdownPos] = useState({ top: 0, left: 0, width: 0 });

  const [isListeningSearch, setIsListeningSearch] = useState(false);

  const [isSelectionMode, setIsSelectionMode] = useState(false);
  const [selectedOrderIds, setSelectedOrderIds] = useState<Set<string>>(new Set());
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showBulkStatusModal, setShowBulkStatusModal] = useState(false);

  const [isPrinting, setIsPrinting] = useState(false);
  const [isGeneratingImg, setIsGeneratingImg] = useState(false);
  const [showBatchSplitModal, setShowBatchSplitModal] = useState(false);
  const [showPrintTypeModal, setShowPrintTypeModal] = useState(false);
  const [ordersToPrint, setOrdersToPrint] = useState<Order[]>([]);

  const [showReconcileModal, setShowReconcileModal] = useState(false);
  const [reconcileResult, setReconcileResult] = useState<ReconciliationResult | null>(null);
  const [isReconciling, setIsReconciling] = useState(false);

  const [showStatsModal, setShowStatsModal] = useState(false);

  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editProductMode, setEditProductMode] = useState<'IMPORT' | 'SET'>('SET');

  const [showRoutePlanner, setShowRoutePlanner] = useState(false);
  const [showShipmentModal, setShowShipmentModal] = useState(false);
  const [shipmentOrder, setShipmentOrder] = useState<Order | null>(null);

  const [moveBatchData, setMoveBatchData] = useState<{isOpen: boolean, targetBatch: string}>({ isOpen: false, targetBatch: '' });
  const [qrState, setQrState] = useState<{ isOpen: boolean, url: string, order: Order | null }>({ isOpen: false, url: '', order: null });
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [visibleCount, setVisibleCount] = useState(20);

  const qrImgRef = useRef<HTMLImageElement | null>(null);
  const shopConfigRef = useRef<ShopConfig | null>(null);
  const bankConfigRef = useRef<BankConfig | null>(null);

  const statusLabels: Record<OrderStatus, string> = { [OrderStatus.PENDING]: 'Chờ xử lý', [OrderStatus.PICKED_UP]: 'Đã lấy hàng', [OrderStatus.IN_TRANSIT]: 'Đang giao', [OrderStatus.DELIVERED]: 'Đã giao', [OrderStatus.CANCELLED]: 'Đã hủy' };

  useEffect(() => {
      const observer = new IntersectionObserver(
          ([entry]) => { setIsHeaderVisible(entry.isIntersecting); setActiveDropdown(null); },
          { threshold: 0, rootMargin: "-70px 0px 0px 0px" }
      );
      if (observerTarget.current) observer.observe(observerTarget.current);
      return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    const handleWindowEvents = () => setActiveDropdown(null);
    window.addEventListener('resize', handleWindowEvents);
    window.addEventListener('scroll', handleWindowEvents, true);
    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
        window.removeEventListener('resize', handleWindowEvents); 
        window.removeEventListener('scroll', handleWindowEvents, true); 
    };
  }, []);

  useEffect(() => {
      if (qrState.isOpen && qrState.url) {
          storageService.getShopConfig().then(c => shopConfigRef.current = c);
          storageService.getBankConfig().then(c => bankConfigRef.current = c);
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = qrState.url;
          img.onload = () => { qrImgRef.current = img; };
      } else {
          qrImgRef.current = null;
      }
  }, [qrState.isOpen, qrState.url]);

  const handleViewDetail = (order: Order) => setDetailOrder(order);
  const handleDeleteClick = useCallback((id: string) => { setDeleteId(id); setShowDeleteConfirm(true); }, []);
  const handleEdit = useCallback((order: Order) => { setEditingOrder(JSON.parse(JSON.stringify(order))); setActiveEditProductRow(null); setDetailOrder(null); }, []);
  const handleSplitBatch = useCallback(async (order: Order) => { await storageService.splitOrderToNextBatch(order.id, order.batchId); toast.success('Đã chuyển đơn sang lô sau!'); if(detailOrder?.id === order.id) setDetailOrder(null); }, [detailOrder]);

  const handleShowQR = useCallback(async (order: Order) => { 
      const bankConfig = await storageService.getBankConfig(); 
      if (!bankConfig || !bankConfig.accountNo) { toast.error("Cài đặt Ngân hàng trước."); return; } 
      const desc = `DH ${order.id}`; 
      const url = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${order.totalPrice}&addInfo=${encodeURIComponent(desc)}&accountName=${encodeURIComponent(bankConfig.accountName)}`; 
      setQrState({ isOpen: true, url, order }); 
  }, []);

  const handleShareQR = async () => {
        if (!qrState.url || !qrState.order || isGeneratingImg) return;
        const qrImg = qrImgRef.current;
        if (!qrImg || !qrImg.complete) { toast.error("Đang tải ảnh QR, vui lòng đợi..."); return; }

        setIsGeneratingImg(true);
        const toastId = toast.loading("Đang tạo ảnh...");
        try {
            const shopConfig = shopConfigRef.current;
            const bankConfig = bankConfigRef.current;
            const order = qrState.order;

            const W = 800;
            const qrSize = 500;
            const drawHeight = qrSize / (qrImg.naturalWidth / qrImg.naturalHeight); 

            let H = 140 + 40 + 100 + 40 + drawHeight + 40 + 120 + 40 + 60 + (order.items.length * 50) + 40 + 120 + 50;

            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (!ctx) throw new Error("Canvas error");
            canvas.width = W; canvas.height = H;
            ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);

            let cursorY = 0;
            ctx.fillStyle = '#15803d'; ctx.fillRect(0, cursorY, W, 140);
            ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillText('QUÉT MÃ THANH TOÁN', W / 2, cursorY + 70);
            cursorY += 140 + 40; 

            ctx.fillStyle = '#f0fdf4'; 
            ctx.beginPath(); if ((ctx as any).roundRect) (ctx as any).roundRect(100, cursorY, 600, 100, 20); else ctx.fillRect(100, cursorY, 600, 100);
            ctx.fill(); ctx.strokeStyle = '#bbf7d0'; ctx.lineWidth = 2; ctx.stroke();
            ctx.fillStyle = '#15803d'; ctx.font = 'bold 60px Arial';
            ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`, W / 2, cursorY + 50);
            cursorY += 100 + 40;

            ctx.drawImage(qrImg, (W - qrSize) / 2, cursorY, qrSize, drawHeight);
            cursorY += drawHeight + 40;

            ctx.strokeStyle = '#e5e7eb'; ctx.lineWidth = 2; ctx.setLineDash([10, 10]);
            ctx.beginPath(); ctx.moveTo(50, cursorY); ctx.lineTo(W - 50, cursorY); ctx.stroke(); ctx.setLineDash([]);
            cursorY += 40;

            ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.font = '28px Arial'; ctx.fillStyle = '#6b7280';
            ctx.fillText('Đơn hàng:', 80, cursorY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(`#${order.id}`, 300, cursorY);
            cursorY += 50;
            ctx.fillStyle = '#6b7280'; ctx.font = '28px Arial'; ctx.fillText('Khách hàng:', 80, cursorY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(order.customerName, 300, cursorY);
            cursorY += 70;

            ctx.fillStyle = '#f3f4f6'; ctx.fillRect(50, cursorY, 700, 40);
            ctx.fillStyle = '#374151'; ctx.font = 'bold 24px Arial'; ctx.fillText('Chi tiết hàng hóa', 70, cursorY + 8);
            cursorY += 50;

            order.items.forEach((item, index) => {
                ctx.fillStyle = '#1f2937'; ctx.font = '26px Arial'; ctx.textAlign = 'left';
                ctx.fillText(`${index + 1}. ${item.name.substring(0, 35)}`, 70, cursorY + 20);
                ctx.textAlign = 'right'; ctx.font = 'bold 26px Arial'; ctx.fillText(`x${item.quantity}`, 730, cursorY + 20);
                cursorY += 50;
            });

            const dataUrl = canvas.toDataURL('image/png');
            const blob = await (await fetch(dataUrl)).blob();
            const file = new File([blob], `pay-${order.id}.png`, { type: "image/png" });

            if (navigator.canShare && navigator.canShare({ files: [file] })) {
                await navigator.share({ files: [file], title: `Thanh toán #${order.id}` });
            } else {
                const a = document.createElement('a'); a.href = dataUrl; a.download = `pay-${order.id}.png`; a.click();
                toast.success("Đã tải ảnh xuống");
            }
            toast.dismiss(toastId);
        } catch (e: any) {
            console.error(e); toast.dismiss(toastId); toast.error("Lỗi tạo ảnh: " + e.message);
        } finally { setIsGeneratingImg(false); }
    };

  const handleDetailAction = {
      call: () => window.open(`tel:${detailOrder?.customerPhone}`, '_self'),
      sms: async () => { if(detailOrder) { const msg = await generateDeliveryMessage(detailOrder); const separator = /iphone|ipad|ipod/.test(navigator.userAgent.toLowerCase()) ? '&' : '?'; window.open(`sms:${detailOrder.customerPhone}${separator}body=${encodeURIComponent(msg)}`, '_self'); } },
      zalo: () => { if(detailOrder) window.open(`https://zalo.me/${detailOrder.customerPhone.replace(/^0/,'84')}`, '_blank'); },
      print: () => { if(detailOrder) { /* existing logic */ } },
      delete: () => { if(detailOrder) { handleDeleteClick(detailOrder.id); setDetailOrder(null); } },
      edit: () => { if(detailOrder) { setEditingOrder(JSON.parse(JSON.stringify(detailOrder))); setDetailOrder(null); } },
      setStatus: async (status: OrderStatus) => { if(detailOrder) { await storageService.updateStatus(detailOrder.id, status); setDetailOrder({...detailOrder, status}); } },
      confirmPayment: async () => { if(detailOrder) { await storageService.updatePaymentVerification(detailOrder.id, true); setDetailOrder({...detailOrder, paymentVerified: true}); toast.success("Đã nhận tiền"); } },
      splitBatch: () => { if(detailOrder) handleSplitBatch(detailOrder); },
      showQR: () => { if(detailOrder) handleShowQR(detailOrder); },
      ship: () => { if(detailOrder) { setShipmentOrder(detailOrder); setShowShipmentModal(true); } }
  };

  const toggleFilter = (type: 'STATUS' | 'BATCH', value: any) => { /* existing logic */ };
  const getLabel = (type: 'STATUS' | 'BATCH') => { /* existing logic */ };
  const openDropdown = (type: 'STATUS' | 'BATCH') => { 
      const ref = type === 'STATUS' ? statusDropdownBtnRef : batchDropdownBtnRef; 
      if (ref.current) { 
          const rect = ref.current.getBoundingClientRect(); 
          setDropdownPos({ top: rect.bottom + 4, left: rect.left, width: Math.max(rect.width, 160) }); 
          setActiveDropdown(activeDropdown === type ? null : type); 
      } 
  };

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const statusMatch = filterStatus.length === 0 || filterStatus.includes(o.status);
      const batchMatch = filterBatch.length === 0 || (o.batchId && filterBatch.includes(o.batchId));
      if (!statusMatch || !batchMatch) return false;
      if (!deferredSearchTerm) return true;
      const term = normalizeString(deferredSearchTerm);
      return normalizeString(o.customerName).includes(term) || normalizePhone(o.customerPhone).includes(term) || normalizeString(o.address).includes(term) || o.items.some(i => normalizeString(i.name).includes(term));
    });
    if (sortBy === 'NEWEST') return result.sort((a, b) => b.createdAt - a.createdAt);
    if (sortBy === 'ROUTE') return result.sort((a, b) => a.orderIndex - b.orderIndex);
    return result;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, sortBy]);

  const visibleOrders = filteredOrders.slice(0, visibleCount);

  return (
    <div className="animate-fade-in pb-32">
      <div className="sticky top-16 z-30 bg-gray-50/95 backdrop-blur-sm transition-shadow shadow-sm">
         <div className="bg-white border-b border-gray-200 p-2 shadow-sm">
             <div className="flex gap-2 items-center mb-2">
                <div className="relative flex-grow">
                    <i className="fas fa-search absolute left-3 top-2.5 text-gray-400 text-xs"></i>
                    <input placeholder="Tìm kiếm..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-9 pr-9 py-2 rounded-lg bg-gray-100 border-transparent focus:bg-white text-sm outline-none" />
                </div>
                <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-9 h-9 flex-shrink-0 flex items-center justify-center rounded-lg border ${isCompactMode ? 'bg-eco-100 text-eco-700' : 'bg-white text-gray-400'}`}><i className={`fas ${isCompactMode ? 'fa-list' : 'fa-th-large'}`}></i></button>
             </div>
