        ))}
      </div>

      {qrState.isOpen && qrState.order && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-900/80 backdrop-blur-sm p-4" onClick={() => setQrState({...qrState, isOpen: false})}>
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm overflow-hidden" onClick={e => e.stopPropagation()}>
                <div className="p-4 bg-eco-600 text-white text-center">
                    <h3 className="font-bold">QUÉT MÃ THANH TOÁN</h3>
                    <div className="text-xs opacity-80 mt-1">Đơn hàng #{qrState.order.id}</div>
                </div>
                <div className="p-6 flex flex-col items-center">
                    <div className="bg-white p-2 rounded-xl shadow-lg border border-gray-100 mb-4">
                        <img src={qrState.url} alt="QR Code" className="w-48 h-48" />
                    </div>
                    <div className="text-2xl font-black text-gray-800 mb-6">{new Intl.NumberFormat('vi-VN').format(qrState.order.totalPrice)}đ</div>
                    <div className="grid grid-cols-2 gap-3 w-full">
                        <button onClick={handleShareQR} disabled={isGeneratingImg} className="py-3 bg-white border border-gray-200 text-gray-700 font-bold rounded-xl flex items-center justify-center gap-2">
                            {isGeneratingImg ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-share-alt"></i>} Chia sẻ
                        </button>
                        <button onClick={() => { storageService.updatePaymentVerification(qrState.order!.id, true); setQrState({...qrState, isOpen: false}); toast.success("Đã nhận tiền"); }} className="py-3 bg-eco-600 text-white font-bold rounded-xl flex items-center justify-center gap-2">
                            <i className="fas fa-check"></i> Đã nhận
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {activeDropdown && (<div id="floating-dropdown-portal" className="fixed z-[9999] bg-white border border-gray-100 rounded-lg shadow-xl max-h-60 overflow-y-auto p-1" style={{ top: dropdownPos.top, left: dropdownPos.left, minWidth: dropdownPos.width }}>
          {activeDropdown === 'STATUS' ? Object.entries(statusLabels).map(([k,v]) => (<div key={k} onClick={() => { setFilterStatus(prev => prev.includes(k as any) ? prev.filter(x => x !== k) : [...prev, k as any]); }} className="px-3 py-2 text-xs hover:bg-gray-50 cursor-pointer">{v}</div>)) : batches.map(b => (<div key={b} onClick={() => { setFilterBatch(prev => prev.includes(b) ? prev.filter(x => x !== b) : [...prev, b]); }} className="px-3 py-2 text-xs hover:bg-gray-50 cursor-pointer">{b}</div>))}
      </div>)}
    </div>
  );
};

