import React, { useState, useEffect, useMemo, useRef } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, ShopConfig } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import ConfirmModal from './ConfirmModal';

interface CustomerDebtGroup {
    key: string;
    customerId: string;
    customerName: string;
    customerPhone: string;
    orders: Order[];
    totalAmount: number;
    maxReminders: number;
}

const PaymentAudit: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [bankConfig, setBankConfig] = useState<any>(null);
  const [shopConfig, setShopConfig] = useState<ShopConfig | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedBatch, setSelectedBatch] = useState('ALL');
  const [selectedGroup, setSelectedGroup] = useState<CustomerDebtGroup | null>(null);
  const [confirmData, setConfirmData] = useState<{isOpen: boolean, ids: string[], message: string}>({ isOpen: false, ids: [], message: '' });
  const [isSharing, setIsSharing] = useState(false);
  const groupQrImgRef = useRef<HTMLImageElement | null>(null);

  useEffect(() => {
    const unsub = storageService.subscribeOrders((allOrders) => {
      const valid = allOrders.filter(o => !o.paymentVerified && o.paymentMethod === PaymentMethod.TRANSFER && o.status !== OrderStatus.CANCELLED);
      setOrders(valid);
    });
    storageService.getBankConfig().then(setBankConfig);
    storageService.getShopConfig().then(setShopConfig);
    return () => unsub();
  }, []);

  useEffect(() => {
      if (selectedGroup && bankConfig?.accountNo) {
          const idsStr = selectedGroup.orders.map(o => o.id).join(' ');
          const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${selectedGroup.totalAmount}&addInfo=${encodeURIComponent('DH ' + idsStr)}`;
          const img = new Image();
          img.crossOrigin = "anonymous";
          img.src = qrUrl;
          img.onload = () => { groupQrImgRef.current = img; };
      } else {
          groupQrImgRef.current = null;
      }
  }, [selectedGroup, bankConfig]);

  const customerGroups = useMemo(() => {
      const groups: Record<string, CustomerDebtGroup> = {};
      orders.forEach(o => {
          const key = o.customerPhone || o.customerName;
          if (!groups[key]) groups[key] = { key, customerId: o.customerId || '', customerName: o.customerName, customerPhone: o.customerPhone, orders: [], totalAmount: 0, maxReminders: 0 };
          groups[key].orders.push(o);
          groups[key].totalAmount += o.totalPrice;
          groups[key].maxReminders = Math.max(groups[key].maxReminders, o.reminderCount || 0);
      });
      return Object.values(groups).sort((a,b) => b.totalAmount - a.totalAmount);
  }, [orders]);

  const handleShareGroupQR = async (group: CustomerDebtGroup) => {
    if (!bankConfig || isSharing) return;
    const qrImg = groupQrImgRef.current;
    if (!qrImg || !qrImg.complete) { toast.error("Đang chuẩn bị ảnh QR..."); return; }

    setIsSharing(true);
    const toastId = toast.loading("Đang tạo phiếu nợ...");
    try {
        const itemsSummary: Record<string, number> = {};
        group.orders.forEach(o => o.items.forEach(i => { itemsSummary[i.name] = (itemsSummary[i.name] || 0) + i.quantity; }));
        const itemsList = Object.entries(itemsSummary);

        const W = 800;
        const qrSize = 500;
        const drawH = qrSize / (qrImg.naturalWidth / qrImg.naturalHeight);
        let H = 140 + 40 + 100 + 40 + drawH + 40 + 150 + 40 + 60 + (itemsList.length * 50) + 40 + 120 + 50;

        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error("Canvas error");
        canvas.width = W; canvas.height = H;
        ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);

        let curY = 0;
        ctx.fillStyle = '#1e3a8a'; ctx.fillRect(0, curY, W, 140);
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
        ctx.fillText('PHIẾU THANH TOÁN TỔNG HỢP', W / 2, curY + 70);
        curY += 140 + 40;

        ctx.fillStyle = '#eff6ff'; if ((ctx as any).roundRect) (ctx as any).roundRect(100, curY, 600, 100, 20); else ctx.fillRect(100, curY, 600, 100);
        ctx.fill(); ctx.strokeStyle = '#bfdbfe'; ctx.lineWidth = 2; ctx.stroke();
        ctx.fillStyle = '#1e40af'; ctx.font = 'bold 60px Arial';
        ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(group.totalAmount)}đ`, W / 2, curY + 50);
        curY += 100 + 40;

        ctx.drawImage(qrImg, (W - qrSize) / 2, curY, qrSize, drawH);
        curY += drawH + 40;

        ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.font = '28px Arial'; ctx.fillStyle = '#6b7280';
        ctx.fillText('Khách hàng:', 80, curY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(group.customerName, 300, curY);
        curY += 50;
        ctx.fillStyle = '#6b7280'; ctx.font = '28px Arial'; ctx.fillText('Số lượng đơn:', 80, curY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(`${group.orders.length} đơn hàng`, 300, curY);
        curY += 70;

        ctx.fillStyle = '#f3f4f6'; ctx.fillRect(50, curY, 700, 40);
        ctx.fillStyle = '#374151'; ctx.font = 'bold 24px Arial'; ctx.fillText('Chi tiết hàng hóa tổng hợp', 70, curY + 8);
        curY += 50;

        itemsList.forEach(([name, qty], idx) => {
            ctx.fillStyle = '#1f2937'; ctx.font = '26px Arial'; ctx.textAlign = 'left';
            ctx.fillText(`${idx + 1}. ${name.substring(0, 35)}`, 70, curY + 20);
            ctx.textAlign = 'right'; ctx.font = 'bold 26px Arial'; ctx.fillText(`x${qty}`, 730, curY + 20);
            curY += 50;
        });

        const dataUrl = canvas.toDataURL('image/png');
        const blob = await (await fetch(dataUrl)).blob();
        const file = new File([blob], `debt-${Date.now()}.png`, { type: "image/png" });

        if (navigator.canShare && navigator.canShare({ files: [file] })) {
            await navigator.share({ files: [file], title: `Nợ gộp ${group.customerName}` });
        } else {
            const a = document.createElement('a'); a.href = dataUrl; a.download = `debt-${Date.now()}.png`; a.click();
            toast.success("Đã tải ảnh xuống");
        }
        toast.dismiss(toastId);
    } catch (e: any) {
        console.error(e); toast.dismiss(toastId); toast.error("Lỗi: " + e.message);
    } finally { setIsSharing(false); }
  };

  const executeConfirm = async () => {
    if (confirmData.ids.length > 0) {
      await Promise.all(confirmData.ids.map(id => storageService.updatePaymentVerification(id, true)));
      toast.success("Đã nhận đủ tiền!");
      setConfirmData({ isOpen: false, ids: [], message: '' });
      setSelectedGroup(null);
    }
  };

  return (
    <div className="max-w-7xl mx-auto pb-24 animate-fade-in px-2">
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-eco-100 mb-4 flex justify-between items-center sticky top-16 z-30">
        <div className="flex items-center gap-4">
             <div className="w-11 h-11 rounded-full bg-eco-50 text-eco-600 flex items-center justify-center text-xl shadow-inner"><i className="fas fa-hand-holding-usd"></i></div>
             <div><h2 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">TỔNG NỢ CHỜ CK</h2><div className="text-2xl font-black text-eco-700 leading-none">{new Intl.NumberFormat('vi-VN').format(orders.reduce((s,o)=>s+o.totalPrice, 0))}đ</div></div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <table className="w-full text-left">
              <thead className="bg-gray-100 text-gray-500 font-bold uppercase text-[10px]">
                  <tr><th className="p-3">Khách Hàng</th><th className="p-3 text-center">Số đơn</th><th className="p-3 text-right">Tổng nợ</th><th className="p-3"></th></tr>
              </thead>
              <tbody className="divide-y">
                  {customerGroups.map(g => (
                      <tr key={g.key} onClick={() => setSelectedGroup(g)} className="hover:bg-blue-50 cursor-pointer transition-colors group">
                          <td className="p-3"><div className="font-bold text-gray-800 text-sm">{g.customerName}</div><div className="text-[10px] text-gray-400">{g.customerPhone}</div></td>
                          <td className="p-3 text-center"><span className="text-xs bg-gray-100 px-2 py-1 rounded-full font-bold">{g.orders.length}</span></td>
                          <td className="p-3 text-right font-black text-eco-600">{new Intl.NumberFormat('vi-VN').format(g.totalAmount)}</td>
                          <td className="p-3 text-center text-gray-300"><i className="fas fa-chevron-right"></i></td>
                      </tr>
                  ))}
              </tbody>
          </table>
      </div>

      {selectedGroup && (
          <div className="fixed inset-0 z-[100] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4" onClick={() => setSelectedGroup(null)}>
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                  <div className="p-5 border-b flex justify-between items-start bg-gray-50">
                      <div><h3 className="font-bold text-xl">{selectedGroup.customerName}</h3><div className="text-sm text-gray-500">{selectedGroup.customerPhone}</div></div>
                      <div className="text-right"><div className="text-[10px] font-bold text-gray-400 uppercase">Tổng nợ</div><div className="text-xl font-black text-eco-600">{new Intl.NumberFormat('vi-VN').format(selectedGroup.totalAmount)}đ</div></div>
                  </div>
                  <div className="flex-grow overflow-y-auto p-4 space-y-3">
                      {selectedGroup.orders.map(o => (
                          <div key={o.id} className="bg-white p-3 rounded-xl border flex justify-between items-center shadow-sm">
                              <div><span className="font-mono font-bold text-blue-600 text-xs">#{o.id}</span><div className="text-xs text-gray-600 mt-1">{o.items.map(i=>i.name).join(', ')}</div></div>
                              <div className="font-bold text-sm">{new Intl.NumberFormat('vi-VN').format(o.totalPrice)}</div>
                          </div>
                      ))}
                  </div>
                  <div className="p-4 border-t grid grid-cols-2 gap-3">
                      <button onClick={() => setConfirmData({ isOpen: true, ids: selectedGroup.orders.map(o=>o.id), message: `Xác nhận đã nhận ${new Intl.NumberFormat('vi-VN').format(selectedGroup.totalAmount)}đ từ ${selectedGroup.customerName}?` })} className="col-span-2 py-3 bg-eco-600 text-white font-bold rounded-xl shadow-lg">Xác nhận Đã nhận tiền</button>
                      <button onClick={() => handleShareGroupQR(selectedGroup)} disabled={isSharing} className="py-3 bg-white border border-blue-200 text-blue-700 font-bold rounded-xl flex items-center justify-center gap-2">
                          {isSharing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-qrcode"></i>} Chia sẻ QR nợ
                      </button>
                      <button onClick={() => { /* sms logic from prev file */ }} className="py-3 bg-white border border-gray-200 text-gray-600 font-bold rounded-xl">Nhắn SMS</button>
                  </div>
              </div>
          </div>
      )}
      <ConfirmModal isOpen={confirmData.isOpen} title="Xác nhận tiền về" message={confirmData.message} onConfirm={executeConfirm} onCancel={() => setConfirmData({ ...confirmData, isOpen: false })} />
    </div>
  );
};

export default PaymentAudit;

