            let H = 140 + 40 + 100 + 40 + drawHeight + 40 + 120 + 40 + 60 + (order.items.length * 50) + 40 + 120 + 50;

            const canvas = document.createElement('canvas');
            const ctx = canvas.getContext('2d');
            if (!ctx) throw new Error("Canvas error");
            canvas.width = W; canvas.height = H;
            ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);

            let cursorY = 0;
            ctx.fillStyle = '#15803d'; ctx.fillRect(0, cursorY, W, 140);
            ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillText('QUÉT MÃ THANH TOÁN', W / 2, cursorY + 70);
            cursorY += 140 + 40; 

            ctx.fillStyle = '#f0fdf4'; 
            ctx.beginPath(); if ((ctx as any).roundRect) (ctx as any).roundRect(100, cursorY, 600, 100, 20); else ctx.fillRect(100, cursorY, 600, 100);
            ctx.fill(); ctx.strokeStyle = '#bbf7d0'; ctx.lineWidth = 2; ctx.stroke();
            ctx.fillStyle = '#15803d'; ctx.font = 'bold 60px Arial';
            ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ`, W / 2, cursorY + 50);
            cursorY += 100 + 40;

            ctx.drawImage(qrImg, (W - qrSize) / 2, cursorY, qrSize, drawHeight);
            cursorY += drawHeight + 40;

            ctx.strokeStyle = '#e5e7eb'; ctx.lineWidth = 2; ctx.setLineDash([10, 10]);
            ctx.beginPath(); ctx.moveTo(50, cursorY); ctx.lineTo(W - 50, cursorY); ctx.stroke(); ctx.setLineDash([]);
            cursorY += 40;

            ctx.textAlign = 'left'; ctx.textBaseline = 'top'; ctx.font = '28px Arial'; ctx.fillStyle = '#6b7280';
            ctx.fillText('Đơn hàng:', 80, cursorY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(`#${order.id}`, 300, cursorY);
            cursorY += 50;
            ctx.fillStyle = '#6b7280'; ctx.font = '28px Arial'; ctx.fillText('Khách hàng:', 80, cursorY); ctx.fillStyle = '#111827'; ctx.font = 'bold 28px Arial'; ctx.fillText(order.customerName, 300, cursorY);
            cursorY += 70;

            ctx.fillStyle = '#f3f4f6'; ctx.fillRect(50, cursorY, 700, 40);
            ctx.fillStyle = '#374151'; ctx.font = 'bold 24px Arial'; ctx.fillText('Chi tiết hàng hóa', 70, cursorY + 8);
            cursorY += 50;

            order.items.forEach((item, index) => {
                ctx.fillStyle = '#1f2937'; ctx.font = '26px Arial'; ctx.textAlign = 'left';
                ctx.fillText(`${index + 1}. ${item.name.substring(0, 35)}`, 70, cursorY + 20);
                ctx.textAlign = 'right'; ctx.font = 'bold 26px Arial'; ctx.fillText(`x${item.quantity}`, 730, cursorY + 20);
                cursorY += 50;
            });

            const dataUrl = canvas.toDataURL('image/png');
            const blob = await (await fetch(dataUrl)).blob();
            const file = new File([blob], `pay-${order.id}.png`, { type: "image/png" });

            if (navigator.canShare && navigator.canShare({ files: [file] })) {
                await navigator.share({ files: [file], title: `Thanh toán #${order.id}` });
