      edit: () => { if(detailOrder) { setEditingOrder(JSON.parse(JSON.stringify(detailOrder))); setDetailOrder(null); } },
      setStatus: async (status: OrderStatus) => { if(detailOrder) { await storageService.updateStatus(detailOrder.id, status); setDetailOrder({...detailOrder, status}); } },
      confirmPayment: async () => { if(detailOrder) { await storageService.updatePaymentVerification(detailOrder.id, true); setDetailOrder({...detailOrder, paymentVerified: true}); toast.success("Đã nhận tiền"); } },
      splitBatch: () => { if(detailOrder) handleSplitBatch(detailOrder); },
