export const ProductEditModal: React.FC<ProductEditModalProps> = ({ isOpen, onClose, product, onSave, initialMode = 'IMPORT' }) => {
    const [editTab, setEditTab] = useState<'IMPORT' | 'SET'>(initialMode);
    const [importAmount, setImportAmount] = useState<string>('');
    const [formData, setFormData] = useState<Partial<Product>>({ name: '', defaultPrice: 0, importPrice: 0, stockQuantity: 0, totalImported: 0 });
    const [frozenSold, setFrozenSold] = useState(0);

    useEffect(() => {
        if (isOpen) {
            setEditTab(initialMode); setImportAmount('');
            if (product) {
                setFormData({ name: product.name, defaultPrice: product.defaultPrice, importPrice: product.importPrice, stockQuantity: product.stockQuantity, totalImported: product.totalImported || product.stockQuantity });
                setFrozenSold(Math.max(0, (product.totalImported || 0) - (product.stockQuantity || 0)));
            } else {
                setFormData({ name: '', defaultPrice: 0, importPrice: 0, stockQuantity: 0, totalImported: 0 }); setFrozenSold(0); setEditTab('SET');
            }
        }
    }, [isOpen, product, initialMode]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name) return;
        if (editTab === 'IMPORT' && product) {
            const qty = Number(importAmount) || 0;
            if (qty > 0) { await onSave({ ...product, name: formData.name || product.name, defaultPrice: Number(formData.defaultPrice) || 0, importPrice: Number(formData.importPrice) || 0 }, true, qty); onClose(); return; }
        }
        const total = Number(formData.totalImported) || 0;
        const finalStock = Math.max(0, total - frozenSold);
        await onSave({ id: product?.id || generateProductSku(formData.name!), name: formData.name!, defaultPrice: Number(formData.defaultPrice) || 0, importPrice: Number(formData.importPrice) || 0, defaultWeight: 1, stockQuantity: finalStock, totalImported: total, lastImportDate: Date.now(), importHistory: product?.importHistory || [] }, false, 0);
        onClose();
    };

    if (!isOpen) return null;
    const vInputClass = "w-full p-3 bg-white border-2 border-gray-800 rounded-2xl outline-none focus:ring-4 focus:ring-eco-50 font-black text-black text-sm transition-all";

    return (
        <div className="fixed inset-0 z-[110] bg-gray-900/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh]">
                <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <h3 className="font-black text-gray-800 uppercase text-sm tracking-widest">{product ? 'Cập nhật hàng hóa' : 'Tạo hàng mới'}</h3>
                    <button onClick={onClose} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center"><i className="fas fa-times"></i></button>
                </div>
                <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto">
                    <div>
                        <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 block">Tên sản phẩm *</label>
                        <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className={vInputClass} placeholder="VD: Gạo ST25..." />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 block">Giá bán</label>
                            <input type="number" value={formData.defaultPrice} onChange={e => setFormData({...formData, defaultPrice: Number(e.target.value)})} className={`${vInputClass} text-blue-600`} />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 block">Giá nhập (Vốn)</label>
                            <input type="number" value={formData.importPrice} onChange={e => setFormData({...formData, importPrice: Number(e.target.value)})} className={vInputClass} />
                        </div>
                    </div>
                    {product && (
                        <div className="flex bg-gray-100 p-1 rounded-2xl">
                            <button type="button" onClick={() => setEditTab('IMPORT')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${editTab === 'IMPORT' ? 'bg-white text-black shadow-sm' : 'text-gray-500'}`}>Nhập thêm hàng</button>
                            <button type="button" onClick={() => setEditTab('SET')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${editTab === 'SET' ? 'bg-white text-black shadow-sm' : 'text-gray-500'}`}>Sửa tồn kho</button>
                        </div>
                    )}
                    <div className={`p-4 rounded-2xl border-2 ${editTab === 'IMPORT' ? 'bg-blue-50 border-blue-200' : 'bg-orange-50 border-orange-200'}`}>
                        {editTab === 'IMPORT' && product ? (
                            <>
                                <label className="text-[10px] font-black text-blue-600 uppercase mb-1 block">Số lượng nhập về (+)</label>
                                <input type="number" value={importAmount} onChange={e => setImportAmount(e.target.value)} className={`${vInputClass} text-center text-xl`} placeholder="0" />
                            </>
                        ) : (
                            <div className="space-y-3">
                                <div>
                                    <label className="text-[10px] font-black text-orange-600 uppercase mb-1 block">Tổng số lượng đã nhập (Total)</label>
                                    <input type="number" value={formData.totalImported} onChange={e => setFormData({...formData, totalImported: Number(e.target.value)})} className={`${vInputClass} text-center`} />
                                </div>
                                <div className="flex justify-between items-center bg-white/50 p-2 rounded-xl border border-orange-100 font-black text-xs text-orange-800">
                                    <span>Tồn kho dự kiến:</span>
                                    <span className="text-lg">{Math.max(0, (Number(formData.totalImported) || 0) - frozenSold)}</span>
                                </div>
                            </div>
                        )}
                    </div>
                    <button type="submit" className="w-full py-4 bg-black text-white rounded-2xl font-black text-sm uppercase shadow-xl hover:bg-gray-800 active:scale-95 transition-all mt-2 tracking-widest">Lưu thay đổi <i className="fas fa-check-circle ml-1"></i></button>
                </form>
            </div>
        </div>
    );
};

const InventoryManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [showProductModal, setShowProductModal] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null); 
  const [editingProduct, setEditingProduct] = useState<Product | null>(null); 
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');
  const [isProcessing, setIsProcessing] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [showSyncConfirm, setShowSyncConfirm] = useState(false);
  const [pendingProductUpdate, setPendingProductUpdate] = useState<Product | null>(null);

  useEffect(() => { const unsub = storageService.subscribeProducts(setProducts); return () => unsub(); }, []);
  useEffect(() => {
    let result = products;
    if (searchTerm) { result = result.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())); }
    result.sort((a,b) => { if (a.stockQuantity < 5 && b.stockQuantity >= 5) return -1; if (a.stockQuantity >= 5 && b.stockQuantity < 5) return 1; return a.name.localeCompare(b.name); });
    setFilteredProducts(result);
  }, [products, searchTerm]);

  const stats = useMemo(() => {
      let capital = 0, profit = 0, low = 0;
      products.forEach(p => {
          const s = p.stockQuantity || 0;
          capital += (p.importPrice || 0) * s;
          profit += (p.defaultPrice - (p.importPrice || 0)) * s;
          if (s < 5) low++;
      });
      return { capital, profit, low, total: products.length };
  }, [products]);

  const handleSaveProduct = async (data: Product, isImport: boolean = false, qty: number = 0) => {
      if (isImport && editingProduct) {
          await storageService.adjustStockAtomic(editingProduct.id, qty, { price: data.importPrice || 0, note: 'Nhập hàng' });
          if (data.name !== editingProduct.name || data.defaultPrice !== editingProduct.defaultPrice) { await storageService.saveProduct({ ...editingProduct, name: data.name, defaultPrice: data.defaultPrice, importPrice: data.importPrice }); }
          toast.success("Đã nhập hàng");
      } else {
          await storageService.saveProduct(data);
          if (editingProduct) { setPendingProductUpdate(data); setShowSyncConfirm(true); } else { toast.success('Đã tạo hàng mới'); }
      }
  };

  const confirmDelete = async () => { if (deleteId) { await storageService.deleteProduct(deleteId); toast.success('Đã xóa'); setShowDeleteConfirm(false); } };

  return (
    <div className="max-w-7xl mx-auto pb-24 animate-fade-in relative">
      <div className="sticky top-0 z-30 bg-white/95 backdrop-blur-md shadow-sm border-b border-gray-200 p-3">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h2 className="text-2xl font-black tracking-tighter text-gray-800 uppercase shrink-0">Kho Hàng <span className="text-eco-600">Vivid</span></h2>
              <div className="flex items-center gap-3">
                  <div className="relative flex-grow md:w-64">
                      <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Tìm tên hàng..." className="w-full pl-8 pr-3 py-2.5 bg-white border-2 border-gray-800 rounded-xl text-xs font-black outline-none" />
                      <i className="fas fa-search absolute left-3 top-3.5 text-gray-400 text-xs"></i>
                  </div>
                  <button onClick={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="bg-black text-white px-5 py-3 rounded-2xl font-black text-xs shadow-xl hover:bg-gray-800 transition-all active:scale-95 uppercase tracking-widest shrink-0">+ Tạo mặt hàng</button>
              </div>
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar mt-3 pb-1">
              <div className="flex items-center gap-1.5 bg-gray-100 border border-gray-200 px-3 py-1.5 rounded-full text-[10px] font-black uppercase"><span className="text-gray-400">Vốn tồn:</span><span className="text-blue-600">{new Intl.NumberFormat('vi-VN').format(stats.capital)}đ</span></div>
              <div className="flex items-center gap-1.5 bg-gray-100 border border-gray-200 px-3 py-1.5 rounded-full text-[10px] font-black uppercase"><span className="text-gray-400">Lãi dự kiến:</span><span className="text-green-600">{new Intl.NumberFormat('vi-VN').format(stats.profit)}đ</span></div>
              <div className="flex items-center gap-1.5 bg-red-50 border border-red-100 px-3 py-1.5 rounded-full text-[10px] font-black uppercase"><span className="text-red-400">Sắp hết:</span><span className="text-red-600">{stats.low} sp</span></div>
          </div>
      </div>

      <div className="px-3 sm:px-4 py-6">
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredProducts.map(p => {
                  const current = p.stockQuantity || 0; const isLow = current < 5;
                  return (
                      <div key={p.id} onClick={() => setViewingProduct(p)} className="bg-white rounded-3xl border-2 border-gray-100 shadow-sm hover:border-gray-800 hover:shadow-xl hover:-translate-y-1 cursor-pointer transition-all duration-300 overflow-hidden flex flex-col group relative">
                          <div className="p-4 flex-grow">
                              <h3 className="text-xs font-black text-gray-800 uppercase leading-snug line-clamp-2 h-8 group-hover:text-blue-600 transition-colors" title={p.name}>{p.name}</h3>
                              <div className="mt-4 flex justify-between items-end">
                                  <span className={`text-4xl font-black tracking-tighter ${isLow ? 'text-red-600' : 'text-gray-900'}`}>{current}</span>
                                  <div className="text-right"><span className="text-[8px] font-black text-gray-400 uppercase block leading-none mb-1">Giá Bán</span><span className="text-sm font-black text-blue-600 leading-none">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</span></div>
                              </div>
                          </div>
                          <div className="bg-gray-50 border-t-2 border-gray-100 px-4 py-3 flex justify-between items-center group-hover:bg-gray-100 transition-colors">
                              <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Chi tiết <i className="fas fa-arrow-right ml-1"></i></span>
                              <div className={`w-2 h-2 rounded-full ${isLow ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>

      {viewingProduct && <ProductDetailModal isOpen={!!viewingProduct} onClose={() => setViewingProduct(null)} product={viewingProduct} onImport={() => { setEditingProduct(viewingProduct); setEditMode('IMPORT'); setViewingProduct(null); setShowProductModal(true); }} onAdjust={() => { setEditingProduct(viewingProduct); setEditMode('SET'); setViewingProduct(null); setShowProductModal(true); }} onDelete={() => { setDeleteId(viewingProduct.id); setShowDeleteConfirm(true); setViewingProduct(null); }} />}
      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa mặt hàng?" message="Sản phẩm sẽ bị xóa vĩnh viễn khỏi kho." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa" isDanger={true} />
    </div>
  );
};

export default InventoryManager;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 
  const [quickTags, setQuickTags] = useState<string[]>([]);

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<'ACTIVE' | 'WARNING' | 'SEARCH'>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
  const [items, setItems] = useState<Partial<OrderItem>[]>([ { id: uuidv4(), name: '', quantity: 1, price: 0 } ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    setQuickTags(storageService.getQuickTags());
    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => { if (o.batchId) { batchActivity.set(o.batchId, Math.max(batchActivity.get(o.batchId) || 0, o.createdAt)); } });
        const sorted = Array.from(batchActivity.entries()).sort((a, b) => b[1] - a[1]).map(e => e[0]).slice(0, 15);
        setExistingBatches(sorted);
        setBatchId(prev => { if (prev) return prev; const today = new Date().toISOString().slice(0, 10); return sorted.find(b => b.includes(today)) || `LÔ-${today}`; });
    });
    const handleClickOutside = (e: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(e.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(e.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(e.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();
    return () => { document.removeEventListener("mousedown", handleClickOutside); if (unsubProducts) unsubProducts(); if (unsubCustomers) unsubCustomers(); if (unsubOrders) unsubOrders(); };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();
      orders.forEach(o => { if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) { o.items.forEach(item => { const normName = normalizeString(item.name); const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId }; existing.qty += (Number(item.quantity) || 0); soldMap.set(normName, existing); }); } });
      const inventoryItems = products.map(p => { const normName = normalizeString(p.name); const soldData = soldMap.get(normName); if (soldData) soldMap.delete(normName); return { product: p, soldInBatch: soldData?.qty || 0, stock: p.stockQuantity || 0, isExternal: false }; });
      const externalItems = Array.from(soldMap.values()).map(ext => ({ product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product, soldInBatch: ext.qty, stock: 0, isExternal: true }));
      const allItems = [...inventoryItems, ...externalItems];
      return allItems.filter(item => { if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0; if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10; if (sidebarTab === 'SEARCH') { if (!sidebarSearch) return true; return normalizeString(item.product.name).includes(normalizeString(sidebarSearch)); } return false; }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ ...prev, customerName: res.customerName || prev.customerName, customerPhone: res.customerPhone || prev.customerPhone, address: res.address || prev.address, notes: res.notes || prev.notes }));
            if (res.parsedItems?.length) { setItems(res.parsedItems.map(pi => { const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName)); return { id: uuidv4(), name: matched ? matched.name : pi.productName, quantity: pi.quantity || 1, price: matched ? matched.defaultPrice : 0, productId: matched?.id }; })); }
        } catch (error) { toast.error("Lỗi AI"); } finally { setIsProcessingAI(false); }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => { if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; } const newItems = [...items]; newItems.splice(index, 1); setItems(newItems); };
  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => { const newItems = [...items]; newItems[index] = { ...newItems[index], [field]: value }; if (field === 'name') newItems[index].productId = undefined; setItems(newItems); };
  const selectProductForItem = (index: number, product: Product) => { const newItems = [...items]; newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice }; setItems(newItems); setActiveProductRow(null); };
  const addTagToNotes = (tag: string) => { setCustomerInfo(prev => ({ ...prev, notes: prev.notes ? `${prev.notes}, ${tag}` : tag })); };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin'); return; }
    const newOrder: Order = { id: uuidv4().slice(0, 8).toUpperCase(), customerId: customerInfo.customerId, batchId: batchId, customerName: customerInfo.customerName, customerPhone: customerInfo.customerPhone, address: customerInfo.address, items: validItems, notes: customerInfo.notes, totalPrice: totalPrice, paymentMethod: PaymentMethod.CASH, status: OrderStatus.PENDING, createdAt: Date.now(), updatedAt: Date.now(), orderIndex: Date.now() };
    await storageService.saveOrder(newOrder);
    toast.success('Đã lưu đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
    if (nameInputRef.current) nameInputRef.current.focus();
  };

  const inputBaseClass = "w-full p-2.5 bg-white border-2 border-gray-800 rounded-xl outline-none text-sm font-black text-black placeholder-gray-300 focus:ring-4 focus:ring-eco-50 transition-all uppercase";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden relative">
        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-3 text-[10px] font-black text-eco-800 tracking-widest uppercase">AI Đang phân tích...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b border-gray-200 bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-3 text-[10px] font-black border-b-4 transition-colors ${mobileTab === 'FORM' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>TẠO ĐƠN</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-3 text-[10px] font-black border-b-4 transition-colors ${mobileTab === 'STATS' ? 'border-eco-600 text-eco-700' : 'border-transparent text-gray-400'}`}>THỐNG KÊ LÔ</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r border-gray-100`}>
                <div className="flex flex-col shrink-0 bg-white shadow-sm z-20 border-b border-gray-200">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/80">
                       <div ref={batchWrapperRef} className="relative">
                            <div className="flex items-center bg-white border-2 border-gray-800 rounded-lg px-2 py-1 shadow-sm cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-28 text-[10px] font-black text-black outline-none bg-transparent uppercase" placeholder="LÔ HÀNG..." />
                                <i className="fas fa-chevron-down text-[8px] ml-2"></i>
                            </div>
                            {showBatchSuggestions && (
                                <div className="absolute top-full left-0 mt-1 w-56 bg-white border-2 border-gray-800 rounded-xl shadow-2xl z-[100] overflow-hidden">
                                    {existingBatches.map(b => <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-4 py-2.5 hover:bg-gray-100 cursor-pointer text-xs font-black text-black border-b border-gray-100 last:border-0">{b}</div>)}
                                </div>
                            )}
                       </div>
                       <button onClick={handleVoiceInput} disabled={isListening} className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-white border-2 border-gray-800 text-gray-800 hover:bg-gray-50'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                    </div>
                    <div className="px-4 py-3 flex gap-3 items-center bg-white">
                        <div className="flex-col min-w-[90px]">
                            <div className="text-[9px] text-gray-400 font-black uppercase">Tổng thu:</div>
                            <div className="text-2xl font-black text-eco-700 tracking-tighter leading-none">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-[10px] text-gray-400 ml-0.5 font-bold">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-2xl py-4 px-4 font-black text-xs shadow-xl active:scale-95 transition-all uppercase tracking-widest">LƯU ĐƠN NGAY <i className="fas fa-check-circle ml-2"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-4 space-y-5 pb-24 bg-gray-50/30">
                    <div className="bg-white p-5 rounded-3xl border-2 border-gray-100 shadow-sm space-y-4">
                        <div className="grid grid-cols-12 gap-3" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[9px] font-black text-gray-400 uppercase mb-1 ml-1">Người nhận hàng</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách hàng..." />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border-2 border-gray-800 rounded-xl shadow-2xl mt-1 max-h-48 overflow-y-auto">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-50 flex flex-col"><span className="text-sm font-black text-black">{s.name}</span><span className="text-[10px] text-gray-500 font-bold uppercase">{s.phone} • {s.address}</span></li>)}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[9px] font-black text-gray-400 uppercase mb-1 ml-1">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09xxxx" />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[9px] font-black text-gray-400 uppercase mb-1 ml-1">Địa chỉ giao hàng</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputBaseClass} placeholder="Số nhà, đường, quận..." />
                        </div>
                        <div>
                            <label className="block text-[9px] font-black text-gray-400 uppercase mb-1 ml-1">Ghi chú (Quick Tags)</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputBaseClass} placeholder="Giao hẻm, gọi trước..." />
                            <div className="flex flex-wrap gap-1.5 mt-2">
                                {quickTags.map(tag => <button key={tag} type="button" onClick={() => addTagToNotes(tag)} className="px-2 py-1 bg-gray-100 hover:bg-eco-100 text-gray-600 hover:text-eco-800 rounded-lg text-[8px] font-black border border-gray-200 uppercase transition-colors">{tag}</button>)}
                            </div>
                        </div>
                    </div>

                    <div className="space-y-3" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2"><i className="fas fa-shopping-basket"></i> Danh sách hàng</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-black text-eco-700 bg-eco-50 px-3 py-1.5 rounded-xl border-2 border-eco-200 uppercase hover:bg-eco-100">+ Thêm dòng</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-2 bg-white p-3 rounded-2xl border-2 border-gray-800 shadow-sm relative">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-2.5 bg-gray-50 border border-gray-200 rounded-xl text-sm font-black text-black outline-none focus:bg-white uppercase placeholder-gray-300" placeholder="Tên hàng..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border-2 border-gray-800 rounded-xl shadow-2xl z-50 max-h-48 overflow-y-auto">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-4 py-3 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-100"><div className="flex flex-col"><span className="text-sm font-black text-gray-800 uppercase">{p.name}</span><span className="text-[9px] text-gray-400 font-black uppercase">Kho: {p.stockQuantity} sp</span></div><span className="text-xs font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</span></div>)}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-3 bg-gray-50 text-center text-[9px] font-black text-eco-600 hover:bg-eco-100 border-t border-gray-100 uppercase">+ Tạo mới vào kho</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-16">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">SL</label>
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-2.5 text-center bg-gray-50 border border-gray-200 rounded-xl text-sm font-black text-eco-700 outline-none focus:bg-white" />
                                </div>
                                <div className="w-24">
                                    <label className="block text-[8px] font-black text-gray-400 uppercase text-center mb-0.5">Giá</label>
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-2.5 text-right bg-gray-50 border border-gray-200 rounded-xl text-sm font-black text-black outline-none focus:bg-white" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-600 p-1"><i className="fas fa-times-circle text-lg"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-3 bg-white border-b border-gray-200">
                    <div className="flex gap-1 p-1 bg-gray-100 rounded-xl mb-2">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1.5 text-[9px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>{tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}</button>)}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-8 pr-2 py-2 bg-white border-2 border-gray-800 rounded-xl text-[10px] font-black outline-none uppercase" placeholder="TÌM TÊN HOẶC MÃ..." />
                            <i className="fas fa-search absolute left-3 top-3 text-gray-300 text-[9px]"></i>
                        </div>
                    )}
                </div>
                <div className="flex-grow overflow-y-auto p-1.5 space-y-0.5">
                    {filteredSidebarProducts.length === 0 ? <div className="flex flex-col items-center justify-center h-40 text-gray-300 opacity-50"><i className="fas fa-layer-group text-xl mb-2"></i><p className="text-[9px] font-black uppercase tracking-widest text-center">CHƯA CÓ<br/>GIAO DỊCH</p></div> : filteredSidebarProducts.map((item) => (
                        <div key={item.product.id + (item.isExternal ? '-ext' : '')} className={`flex items-center gap-2 p-1.5 hover:bg-white rounded-lg transition-colors border-b border-gray-100/30 group ${item.isExternal ? 'bg-orange-50/50' : ''}`}>
                            <div className={`w-6 h-6 rounded flex items-center justify-center text-[10px] font-black shrink-0 shadow-sm ${item.isExternal ? 'bg-orange-600 text-white' : item.soldInBatch > 0 ? 'bg-eco-600 text-white' : 'bg-gray-200 text-gray-500'}`}>{item.soldInBatch > 0 ? item.soldInBatch : '0'}</div>
                            <div className="flex-grow min-w-0 flex items-center justify-between gap-1 pr-1">
                                <div onClick={() => handleQuickInsert(item.product)} className={`text-[11px] font-black truncate cursor-pointer hover:text-eco-600 uppercase tracking-tighter ${item.isExternal ? 'text-orange-700' : 'text-gray-700'}`}>{item.product.name}</div>
                                <div className="flex items-center gap-1.5 leading-none shrink-0">
                                    {!item.isExternal && <div className={`text-[10px] font-black ${item.stock < 5 ? 'text-red-500' : 'text-gray-400'}`}>T:{item.stock}</div>}
                                    <button onClick={() => { setEditingProduct(item.product); setEditMode('IMPORT'); setShowProductModal(true); }} className="opacity-0 group-hover:opacity-100 text-[9px] text-blue-600 font-black uppercase transition-opacity">Sửa</button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 
  const [quickTags, setQuickTags] = useState<string[]>([]);

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<'ACTIVE' | 'WARNING' | 'SEARCH'>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
  const [items, setItems] = useState<Partial<OrderItem>[]>([ { id: uuidv4(), name: '', quantity: 1, price: 0 } ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    setQuickTags(storageService.getQuickTags());
    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => { if (o.batchId) { batchActivity.set(o.batchId, Math.max(batchActivity.get(o.batchId) || 0, o.createdAt)); } });
        const sorted = Array.from(batchActivity.entries()).sort((a, b) => b[1] - a[1]).map(e => e[0]).slice(0, 15);
        setExistingBatches(sorted);
        setBatchId(prev => { if (prev) return prev; const today = new Date().toISOString().slice(0, 10); return sorted.find(b => b.includes(today)) || `LÔ-${today}`; });
    });
    const handleClickOutside = (e: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(e.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(e.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(e.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();
    return () => { document.removeEventListener("mousedown", handleClickOutside); if (unsubProducts) unsubProducts(); if (unsubCustomers) unsubCustomers(); if (unsubOrders) unsubOrders(); };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();
      orders.forEach(o => { if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) { o.items.forEach(item => { const normName = normalizeString(item.name); const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId }; existing.qty += (Number(item.quantity) || 0); soldMap.set(normName, existing); }); } });
      const inventoryItems = products.map(p => { const normName = normalizeString(p.name); const soldData = soldMap.get(normName); if (soldData) soldMap.delete(normName); return { product: p, soldInBatch: soldData?.qty || 0, stock: p.stockQuantity || 0, isExternal: false }; });
      const externalItems = Array.from(soldMap.values()).map(ext => ({ product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product, soldInBatch: ext.qty, stock: 0, isExternal: true }));
      const allItems = [...inventoryItems, ...externalItems];
      return allItems.filter(item => { if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0; if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10; if (sidebarTab === 'SEARCH') { if (!sidebarSearch) return true; return normalizeString(item.product.name).includes(normalizeString(sidebarSearch)); } return false; }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ ...prev, customerName: res.customerName || prev.customerName, customerPhone: res.customerPhone || prev.customerPhone, address: res.address || prev.address, notes: res.notes || prev.notes }));
            if (res.parsedItems?.length) { setItems(res.parsedItems.map(pi => { const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName)); return { id: uuidv4(), name: matched ? matched.name : pi.productName, quantity: pi.quantity || 1, price: matched ? matched.defaultPrice : 0, productId: matched?.id }; })); }
        } catch (error) { toast.error("Lỗi AI"); } finally { setIsProcessingAI(false); }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => { if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; } const newItems = [...items]; newItems.splice(index, 1); setItems(newItems); };
  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => { const newItems = [...items]; newItems[index] = { ...newItems[index], [field]: value }; if (field === 'name') newItems[index].productId = undefined; setItems(newItems); };
  const selectProductForItem = (index: number, product: Product) => { const newItems = [...items]; newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice }; setItems(newItems); setActiveProductRow(null); };
  const addTagToNotes = (tag: string) => { setCustomerInfo(prev => ({ ...prev, notes: prev.notes ? `${prev.notes}, ${tag}` : tag })); };

  /* FIX: Add missing handleQuickInsert and handleSaveProduct handlers */
  const handleQuickInsert = (product: Product) => {
    const existingIdx = items.findIndex(i => i.productId === product.id);
    if (existingIdx >= 0) {
      const newItems = [...items];
      newItems[existingIdx].quantity = (Number(newItems[existingIdx].quantity) || 0) + 1;
      setItems(newItems);
    } else {
      const emptyIdx = items.findIndex(i => !i.name && !i.productId);
      if (emptyIdx >= 0) {
        const newItems = [...items];
        newItems[emptyIdx] = { ...newItems[emptyIdx], productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 };
        setItems(newItems);
      } else {
        setItems([...items, { id: uuidv4(), productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 }]);
      }
    }
    toast.success(`Đã thêm ${product.name}`);
  };

  const handleSaveProduct = async (data: Product, isImport: boolean = false, qty: number = 0) => {
    if (isImport && editingProduct) {
      await storageService.adjustStockAtomic(editingProduct.id, qty, { price: data.importPrice || 0, note: 'Nhập hàng' });
      if (data.name !== editingProduct.name || data.defaultPrice !== editingProduct.defaultPrice) {
        await storageService.saveProduct({ ...editingProduct, name: data.name, defaultPrice: data.defaultPrice, importPrice: data.importPrice });
      }
      toast.success("Đã nhập hàng");
    } else {
      await storageService.saveProduct(data);
      toast.success(editingProduct ? 'Đã cập nhật' : 'Đã tạo hàng mới');
    }
    setShowProductModal(false);
  };

