import React, { useState, useEffect, useRef } from 'react';
import toast from 'react-hot-toast';
import { Order, OrderStatus, PaymentMethod, Customer } from '../types';
import { storageService } from '../services/storageService';
import { generateDeliveryMessage } from '../services/geminiService';
import { carrierService } from '../services/carrierService';

interface Props {
  order: Order;
  onUpdate: (order: Order) => void;
  onDelete: (id: string) => void;
  onEdit: (order: Order) => void;
  isSortMode?: boolean;
  index?: number;
  isCompactMode?: boolean; 
  onTouchStart?: (e: React.TouchEvent<HTMLDivElement>) => void;
  onTouchMove?: (e: React.TouchEvent<HTMLDivElement>) => void;
  onTouchEnd?: (e: React.TouchEvent<HTMLDivElement>) => void;
  onRowDragStart?: (e: React.DragEvent<HTMLDivElement>, index: number) => void;
  onRowDragEnter?: (e: React.DragEvent<HTMLDivElement>, index: number) => void;
  onDragEnd?: (e: React.DragEvent<HTMLDivElement>) => void;
  onDragOver?: (e: React.DragEvent<HTMLDivElement>) => void;
  isNewCustomer?: boolean;
  onSplitBatch?: (order: Order) => void;
  priorityScore?: number;
  customerData?: Customer;
  isSelectionMode?: boolean;
  isSelected?: boolean;
  onToggleSelect?: (id: string) => void;
  onLongPress?: (id: string) => void;
  onShowQR?: (order: Order) => void;
  onMoveBatch?: (order: Order) => void;
  onViewDetail?: (order: Order) => void;
  onShip?: (order: Order) => void;
}

const statusConfig: Record<OrderStatus, { color: string; bg: string; label: string; icon: string }> = {
  [OrderStatus.PENDING]: { bg: 'bg-yellow-100', color: 'text-yellow-900', label: 'Chờ xử lý', icon: 'fa-clock' },
  [OrderStatus.PICKED_UP]: { bg: 'bg-blue-100', color: 'text-blue-900', label: 'Đã lấy', icon: 'fa-box-open' },
  [OrderStatus.IN_TRANSIT]: { bg: 'bg-purple-100', color: 'text-purple-900', label: 'Đang giao', icon: 'fa-shipping-fast' },
  [OrderStatus.DELIVERED]: { bg: 'bg-eco-100', color: 'text-eco-900', label: 'Hoàn tất', icon: 'fa-check-circle' },
  [OrderStatus.CANCELLED]: { bg: 'bg-red-100', color: 'text-red-900', label: 'Đã hủy', icon: 'fa-times-circle' },
};

export const OrderCard: React.FC<Props> = ({ 
  order, onDelete, onEdit, isSortMode, index, isCompactMode,
  onTouchStart, onTouchMove, onTouchEnd, onRowDragStart, onRowDragEnter, onDragEnd,
  isNewCustomer, onSplitBatch, customerData, isSelectionMode, isSelected, onToggleSelect,
  onLongPress, onShowQR, onMoveBatch, onViewDetail, onShip
}) => {
  const [showCompactPaymentChoice, setShowCompactPaymentChoice] = useState(false);
  const longPressTimer = useRef<any>(null);
  const isLongPressing = useRef(false);

  const config = statusConfig[order.status];

  const handleCardClick = (e: React.MouseEvent) => {
      if (isSelectionMode && onToggleSelect) { e.preventDefault(); onToggleSelect(order.id); } 
      else if (!isLongPressing.current) { if (isCompactMode && onViewDetail) onViewDetail(order); else onEdit(order); }
      isLongPressing.current = false;
  };

  const handleFinishOrder = async (method: PaymentMethod) => {
      await storageService.updateOrderDetails({ ...order, paymentMethod: method });
      await storageService.updateStatus(order.id, OrderStatus.DELIVERED);
      toast.success('Đã hoàn tất đơn hàng!');
      setShowCompactPaymentChoice(false);
  };

  const nextStatus = (e: React.MouseEvent) => {
      e.stopPropagation();
      if(order.status === OrderStatus.PENDING) storageService.updateStatus(order.id, OrderStatus.PICKED_UP);
      else if(order.status === OrderStatus.PICKED_UP) storageService.updateStatus(order.id, OrderStatus.IN_TRANSIT);
      else if(order.status === OrderStatus.IN_TRANSIT) setShowCompactPaymentChoice(true);
  };

  // Vivid Styles
  const cardBaseClass = `bg-white border-2 border-black rounded-2xl overflow-hidden transition-all select-none group h-full flex flex-col ${isSelected ? 'shadow-none translate-x-1 translate-y-1' : 'shadow-vivid hover:translate-x-[1px] hover:translate-y-[1px] hover:shadow-vivid-sm'}`;

  if (isCompactMode) {
      return (
          <div onClick={handleCardClick} className={`bg-white border-b-2 border-black p-3 hover:bg-eco-50 cursor-pointer flex items-center justify-between ${isSelected ? 'bg-eco-50' : ''}`}>
              <div className="flex items-center gap-3 overflow-hidden">
                  <div className={`w-2 h-8 rounded-full border border-black ${config.bg.replace('100', '500')}`}></div>
                  <div>
                      <div className="font-black text-sm text-black truncate uppercase">{order.customerName}</div>
                      <div className="text-[10px] font-bold text-gray-400 truncate">{order.address}</div>
                  </div>
              </div>
              <div className="flex items-center gap-3 shrink-0">
                  <div className="text-right">
                      <div className="font-black text-sm text-black">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</div>
                      <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-lg border border-black ${config.bg} ${config.color}`}>{config.label}</span>
                  </div>
                  <button onClick={(e) => { e.stopPropagation(); onViewDetail?.(order); }} className="w-8 h-8 rounded-xl border-2 border-black flex items-center justify-center bg-white shadow-vivid-sm"><i className="fas fa-eye text-xs"></i></button>
              </div>
          </div>
      );
  }

  return (
    <div className={cardBaseClass} onClick={handleCardClick}>
      {/* Header */}
      <div className="p-4 border-b-2 border-black flex justify-between items-start bg-gray-50">
          <div className="flex-grow min-w-0 pr-2">
              <div className="flex items-center gap-2 mb-1">
                  {isSelectionMode && <div className={`w-5 h-5 rounded border-2 border-black flex items-center justify-center ${isSelected ? 'bg-black text-white' : 'bg-white'}`}><i className="fas fa-check text-[10px]"></i></div>}
                  <h3 className="font-black text-black text-sm truncate uppercase tracking-tighter">{order.customerName}</h3>
                  {isNewCustomer && <span className="text-[10px] font-black bg-eco-600 text-white px-2 py-0.5 rounded-full border border-black">NEW</span>}
              </div>
              <div className="text-[10px] font-bold text-gray-500 flex items-center gap-1"><i className="fas fa-map-marker-alt"></i> {order.address}</div>
          </div>
          <div className="shrink-0 flex flex-col items-end gap-1">
              <span className={`text-[8px] font-black uppercase px-2 py-1 rounded-xl border border-black shadow-vivid-sm ${config.bg} ${config.color}`}>{config.label}</span>
              <span className="text-[9px] font-black text-gray-400">#{order.id}</span>
          </div>
      </div>

      {/* Body */}
      <div className="p-4 flex-grow space-y-3">
          <div className="bg-white border-2 border-black rounded-xl p-3 shadow-vivid-sm">
              {order.items.map((item, idx) => (
                  <div key={idx} className="flex justify-between items-center text-xs mb-1 last:mb-0">
                      <span className="font-bold text-gray-700">{item.name}</span>
                      <span className="font-black text-black">x{item.quantity}</span>
                  </div>
              ))}
          </div>
          {order.notes && <div className="text-[9px] font-bold text-orange-700 italic flex gap-1"><i className="fas fa-tag"></i> {order.notes}</div>}
      </div>

      {/* Footer Financials */}
      <div className="px-4 py-3 bg-eco-50 border-t-2 border-black flex justify-between items-center">
          <div>
              <div className="text-[8px] font-black text-eco-800 uppercase tracking-widest">Tổng thu:</div>
              <div className="text-xl font-black text-black tracking-tighter">{new Intl.NumberFormat('vi-VN').format(order.totalPrice)}<span className="text-xs">đ</span></div>
          </div>
          <div className="flex items-center gap-1.5">
              <span className={`text-[8px] font-black uppercase px-2 py-1 rounded-lg border border-black bg-white ${order.paymentVerified ? 'text-eco-600' : 'text-blue-600'}`}>{order.paymentMethod === 'CASH' ? 'COD' : order.paymentVerified ? 'Đã Nhận' : 'Chờ CK'}</span>
          </div>
      </div>

      {/* Actions */}
      <div className="p-3 bg-white border-t-2 border-black grid grid-cols-4 gap-2">
          <button onClick={(e) => { e.stopPropagation(); }} className="w-full py-3 border-2 border-black rounded-xl shadow-vivid-sm hover:bg-gray-50 active:translate-y-[2px] active:shadow-none"><i className="fab fa-facebook-messenger"></i></button>
          <button onClick={(e) => { e.stopPropagation(); onShowQR?.(order); }} className="w-full py-3 border-2 border-black rounded-xl shadow-vivid-sm hover:bg-gray-50 active:translate-y-[2px] active:shadow-none"><i className="fas fa-qrcode"></i></button>
          <button onClick={(e) => { e.stopPropagation(); onShip?.(order); }} className="w-full py-3 border-2 border-black rounded-xl shadow-vivid-sm hover:bg-gray-50 active:translate-y-[2px] active:shadow-none text-orange-600"><i className="fas fa-truck"></i></button>
          <button onClick={nextStatus} className="w-full py-3 bg-black text-white border-2 border-black rounded-xl shadow-vivid-sm hover:bg-gray-800 active:translate-y-[2px] active:shadow-none text-[10px] font-black uppercase tracking-widest">
            {order.status === OrderStatus.DELIVERED ? <i className="fas fa-check"></i> : <i className="fas fa-arrow-right"></i>}
          </button>
      </div>

      {showCompactPaymentChoice && (<div className="fixed inset-0 z-[999] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={(e) => { e.stopPropagation(); setShowCompactPaymentChoice(false); }}><div className="bg-white border-4 border-black rounded-[2.5rem] shadow-vivid-lg p-6 w-full max-w-xs" onClick={e => e.stopPropagation()}><h3 className="text-center font-black text-black mb-6 uppercase tracking-tighter italic">Xác nhận thanh toán</h3><div className="space-y-3"><button onClick={() => handleFinishOrder(PaymentMethod.CASH)} className="w-full py-4 bg-white border-2 border-black rounded-2xl shadow-vivid font-black text-xs uppercase hover:bg-gray-50 active:translate-y-[2px] active:shadow-none transition-all">💵 Tiền mặt (COD)</button><button onClick={() => handleFinishOrder(PaymentMethod.TRANSFER)} className="w-full py-4 bg-black text-white border-2 border-black rounded-2xl shadow-vivid font-black text-xs uppercase hover:bg-gray-800 active:translate-y-[2px] active:shadow-none transition-all">💳 Chuyển khoản</button></div></div></div>)}
    </div>
  );
}

import React from 'react';

interface Props {
  isOpen: boolean;
  title: string;
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
  confirmLabel?: string;
  cancelLabel?: string;
  isDanger?: boolean;
}

const ConfirmModal: React.FC<Props> = ({
  isOpen, title, message, onConfirm, onCancel,
  confirmLabel = "Đồng ý", cancelLabel = "Hủy bỏ", isDanger = false
}) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
      <div className="bg-white border-4 border-black rounded-[2.5rem] shadow-vivid-lg max-w-sm w-full overflow-hidden animate-scale-in">
        <div className="p-8 text-center">
          <div className={`mx-auto flex items-center justify-center h-16 w-16 rounded-2xl border-4 border-black mb-6 shadow-vivid-sm ${isDanger ? 'bg-red-500 text-white' : 'bg-eco-500 text-white'}`}>
            <i className={`fas ${isDanger ? 'fa-exclamation-triangle' : 'fa-info-circle'} text-2xl`}></i>
          </div>
          <h3 className="text-2xl font-black text-black mb-3 italic uppercase tracking-tighter leading-tight">{title}</h3>
          <p className="text-sm font-bold text-gray-500 mb-8 leading-relaxed">{message}</p>

          <div className="flex gap-4">
            <button onClick={onCancel} className="flex-1 py-4 bg-white border-2 border-black rounded-2xl font-black text-xs uppercase shadow-vivid-sm active:translate-y-[2px] active:shadow-none transition-all">
              {cancelLabel}
            </button>
            <button onClick={onConfirm} className={`flex-1 py-4 text-white border-2 border-black rounded-2xl font-black text-xs uppercase shadow-vivid transition-all active:translate-y-[2px] active:shadow-none ${isDanger ? 'bg-red-600' : 'bg-black'}`}>
              {confirmLabel}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConfirmModal;

import React, { useEffect, useState, useMemo } from 'react';
import { NavLink } from 'react-router-dom';
import { Order, Product, OrderStatus } from '../types';
import { storageService } from '../services/storageService';
import RevenueReport from './RevenueReport';

const DashboardHome: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [showReport, setShowReport] = useState(false);
  const currentUser = storageService.getCurrentUser() || 'Admin';

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    return () => {
      if (unsubOrders) unsubOrders();
      if (unsubProducts) unsubProducts();
    };
  }, []);

  const stats = useMemo(() => {
    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
    const todaysOrders = orders.filter(o => o.createdAt >= todayStart);
    const pendingOrders = orders.filter(o => o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP);
    const deliveringOrders = orders.filter(o => o.status === OrderStatus.IN_TRANSIT);
    const todayRevenue = todaysOrders
        .filter(o => o.status !== OrderStatus.CANCELLED)
        .reduce((sum, o) => sum + o.totalPrice, 0);
    const lowStockCount = products.filter(p => p.stockQuantity < 5).length;

    return {
      todayCount: todaysOrders.length,
      todayRevenue,
      pendingCount: pendingOrders.length,
      deliveringCount: deliveringOrders.length,
      lowStockCount
    };
  }, [orders, products]);

  const StatCard = ({ title, value, subValue, icon, color, to }: any) => (
    <NavLink to={to} className="bg-white p-5 rounded-2xl border-2 border-black shadow-vivid hover:translate-x-[2px] hover:translate-y-[2px] hover:shadow-vivid-sm transition-all group">
      <div className="flex justify-between items-start mb-2">
        <div className={`w-10 h-10 rounded-xl border-2 border-black flex items-center justify-center ${color} text-white text-lg shadow-vivid-sm`}>
          <i className={`fas ${icon}`}></i>
        </div>
        {subValue && <span className="text-[9px] font-black text-gray-400 bg-gray-50 border border-gray-200 px-2 py-0.5 rounded-full uppercase tracking-widest">{subValue}</span>}
      </div>
      <div className="text-2xl font-black text-black mt-3 tracking-tighter">{value}</div>
      <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest mt-1">{title}</div>
    </NavLink>
  );

  return (
    <div className="max-w-6xl mx-auto pb-10 animate-fade-in">
      <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-4 px-2">
        <div>
            <h1 className="text-3xl font-black text-black tracking-tighter uppercase italic">Xin chào, {currentUser}! 👋</h1>
            <p className="text-gray-500 font-bold text-sm uppercase tracking-widest mt-1">Tổng quan hoạt động logistics</p>
        </div>
        <button 
            onClick={() => setShowReport(true)}
            className="bg-white border-2 border-black text-black hover:bg-gray-50 px-6 py-3 rounded-xl font-black text-xs shadow-vivid active:translate-y-[2px] active:shadow-none transition-all flex items-center gap-2 uppercase tracking-widest"
        >
            <i className="fas fa-chart-pie"></i> Báo Cáo Doanh Thu
        </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-6 mb-10">
        <StatCard title="Đơn hôm nay" value={stats.todayCount} icon="fa-calendar-day" color="bg-blue-600" to="/tracking" />
        <StatCard title="Doanh thu ngày" value={new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(stats.todayRevenue)} subValue="VNĐ" icon="fa-coins" color="bg-eco-600" to="/tracking" />
        <StatCard title="Cần xử lý" value={stats.pendingCount} icon="fa-clock" color="bg-yellow-500" to="/tracking" />
        <StatCard title="Sắp hết hàng" value={stats.lowStockCount} icon="fa-exclamation-triangle" color="bg-red-600" to="/inventory" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-black rounded-3xl p-8 text-white shadow-vivid-lg border-2 border-black flex flex-col justify-between items-start relative overflow-hidden group">
           <div className="absolute right-[-30px] top-[-30px] text-white opacity-10 text-[10rem] rotate-12 transition-transform group-hover:scale-110">
              <i className="fas fa-plus-circle"></i>
           </div>
           <div className="relative z-10">
             <h3 className="text-2xl font-black mb-2 uppercase italic tracking-tighter">Tạo Đơn Hàng Mới</h3>
             <p className="text-gray-400 font-bold text-xs mb-6 max-w-xs uppercase tracking-widest">Tự động trừ kho & tính doanh thu ngay lập tức.</p>
           </div>
           <NavLink to="/order" className="relative z-10 bg-eco-500 text-white border-2 border-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-eco-600 transition-all shadow-vivid-sm uppercase tracking-[0.2em]">
              Tạo Ngay <i className="fas fa-arrow-right ml-2"></i>
           </NavLink>
        </div>

        <div className="bg-white rounded-3xl p-8 border-2 border-black shadow-vivid flex flex-col">
            <h3 className="text-lg font-black text-black mb-6 flex items-center gap-2 uppercase italic tracking-tighter">
               <i className="fas fa-shipping-fast text-eco-600"></i> Trạng thái giao vận
            </h3>
            {stats.deliveringCount > 0 ? (
               <div className="flex-1 flex flex-col items-center justify-center text-center p-6 bg-blue-50 rounded-2xl border-2 border-black shadow-vivid-sm">
                  <div className="text-5xl font-black text-blue-600 mb-2 tracking-tighter">{stats.deliveringCount}</div>
                  <div className="text-xs text-blue-800 font-black uppercase tracking-widest">Đơn hàng đang đi giao</div>
                  <p className="text-[10px] font-bold text-blue-400 mt-4 uppercase tracking-widest">Cần cập nhật khi hoàn tất</p>
               </div>
            ) : (
               <div className="flex-1 flex flex-col items-center justify-center text-center text-gray-300 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-300">
                   <i className="fas fa-check-circle text-4xl mb-3 opacity-30"></i>
                   <span className="text-[10px] font-black uppercase tracking-widest">Mọi thứ đã được xử lý</span>
               </div>
            )}
            <NavLink to="/tracking" className="mt-6 text-center text-[10px] font-black text-eco-600 hover:text-eco-800 uppercase tracking-[0.2em] transition-colors">
               Quản lý chi tiết <i className="fas fa-chevron-right ml-1"></i>
            </NavLink>
        </div>
      </div>

      <RevenueReport isOpen={showReport} onClose={() => setShowReport(false)} />
    </div>
  );
};

export default DashboardHome;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 
  const [quickTags, setQuickTags] = useState<string[]>([]);

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<'ACTIVE' | 'WARNING' | 'SEARCH'>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
  const [items, setItems] = useState<Partial<OrderItem>[]>([ { id: uuidv4(), name: '', quantity: 1, price: 0 } ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    setQuickTags(storageService.getQuickTags());
    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => { if (o.batchId) { batchActivity.set(o.batchId, Math.max(batchActivity.get(o.batchId) || 0, o.createdAt)); } });
        const sorted = Array.from(batchActivity.entries()).sort((a, b) => b[1] - a[1]).map(e => e[0]).slice(0, 15);
        setExistingBatches(sorted);
        setBatchId(prev => { if (prev) return prev; const today = new Date().toISOString().slice(0, 10); return sorted.find(b => b.includes(today)) || `LÔ-${today}`; });
    });
    const handleClickOutside = (e: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(e.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(e.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(e.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();
    return () => { document.removeEventListener("mousedown", handleClickOutside); if (unsubProducts) unsubProducts(); if (unsubCustomers) unsubCustomers(); if (unsubOrders) unsubOrders(); };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();
      orders.forEach(o => { if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) { o.items.forEach(item => { const normName = normalizeString(item.name); const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId }; existing.qty += (Number(item.quantity) || 0); soldMap.set(normName, existing); }); } });
      const inventoryItems = products.map(p => { const normName = normalizeString(p.name); const soldData = soldMap.get(normName); if (soldData) soldMap.delete(normName); return { product: p, soldInBatch: soldData?.qty || 0, stock: p.stockQuantity || 0, isExternal: false }; });
      const externalItems = Array.from(soldMap.values()).map(ext => ({ product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product, soldInBatch: ext.qty, stock: 0, isExternal: true }));
      const allItems = [...inventoryItems, ...externalItems];
      return allItems.filter(item => { if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0; if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10; if (sidebarTab === 'SEARCH') { if (!sidebarSearch) return true; return normalizeString(item.product.name).includes(normalizeString(sidebarSearch)); } return false; }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ ...prev, customerName: res.customerName || prev.customerName, customerPhone: res.customerPhone || prev.customerPhone, address: res.address || prev.address, notes: res.notes || prev.notes }));
            if (res.parsedItems?.length) { setItems(res.parsedItems.map(pi => { const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName)); return { id: uuidv4(), name: matched ? matched.name : pi.productName, quantity: pi.quantity || 1, price: matched ? matched.defaultPrice : 0, productId: matched?.id }; })); }
        } catch (error) { toast.error("Lỗi AI"); } finally { setIsProcessingAI(false); }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => { if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; } const newItems = [...items]; newItems.splice(index, 1); setItems(newItems); };
  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => { const newItems = [...items]; newItems[index] = { ...newItems[index], [field]: value }; if (field === 'name') newItems[index].productId = undefined; setItems(newItems); };
  const selectProductForItem = (index: number, product: Product) => { const newItems = [...items]; newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice }; setItems(newItems); setActiveProductRow(null); };
  const addTagToNotes = (tag: string) => { setCustomerInfo(prev => ({ ...prev, notes: prev.notes ? `${prev.notes}, ${tag}` : tag })); };

  const handleQuickInsert = (product: Product) => {
    const existingIdx = items.findIndex(i => i.productId === product.id);
    if (existingIdx >= 0) {
      const newItems = [...items];
      newItems[existingIdx].quantity = (Number(newItems[existingIdx].quantity) || 0) + 1;
      setItems(newItems);
    } else {
      const emptyIdx = items.findIndex(i => !i.name && !i.productId);
      if (emptyIdx >= 0) {
        const newItems = [...items];
        newItems[emptyIdx] = { ...newItems[emptyIdx], productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 };
        setItems(newItems);
      } else {
        setItems([...items, { id: uuidv4(), productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 }]);
      }
    }
    toast.success(`Đã thêm ${product.name}`);
  };

  const handleSaveProduct = async (data: Product, isImport: boolean = false, qty: number = 0) => {
    if (isImport && editingProduct) {
      await storageService.adjustStockAtomic(editingProduct.id, qty, { price: data.importPrice || 0, note: 'Nhập hàng' });
      if (data.name !== editingProduct.name || data.defaultPrice !== editingProduct.defaultPrice) {
        await storageService.saveProduct({ ...editingProduct, name: data.name, defaultPrice: data.defaultPrice, importPrice: data.importPrice });
      }
      toast.success("Đã nhập hàng");
    } else {
      await storageService.saveProduct(data);
      toast.success(editingProduct ? 'Đã cập nhật' : 'Đã tạo hàng mới');
    }
    setShowProductModal(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Thiếu thông tin'); return; }
    const newOrder: Order = { id: uuidv4().slice(0, 8).toUpperCase(), customerId: customerInfo.customerId, batchId: batchId, customerName: customerInfo.customerName, customerPhone: customerInfo.customerPhone, address: customerInfo.address, items: validItems, notes: customerInfo.notes, totalPrice: totalPrice, paymentMethod: PaymentMethod.CASH, status: OrderStatus.PENDING, createdAt: Date.now(), updatedAt: Date.now(), orderIndex: Date.now() };
    await storageService.saveOrder(newOrder);
    toast.success('Đã lưu đơn thành công!');
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
    if (nameInputRef.current) nameInputRef.current.focus();
  };

  const inputBaseClass = "w-full p-2.5 bg-white border-2 border-black rounded-xl outline-none text-sm font-black text-black placeholder-gray-300 focus:ring-4 focus:ring-eco-50 transition-all uppercase";

  return (
    <div className="flex flex-col h-[calc(100vh-6rem)] bg-white rounded-3xl shadow-vivid border-2 border-black overflow-hidden relative">
        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-200 border-t-black rounded-full animate-spin"></div>
                    <span className="mt-4 text-[10px] font-black text-black tracking-widest uppercase italic">AI Đang phân tích...</span>
                </div>
            </div>
        )}

        <div className="sm:hidden flex border-b-2 border-black bg-white shrink-0">
            <button onClick={() => setMobileTab('FORM')} className={`flex-1 py-4 text-[10px] font-black transition-all ${mobileTab === 'FORM' ? 'bg-black text-white' : 'text-gray-400'}`}>TẠO ĐƠN</button>
            <button onClick={() => setMobileTab('STATS')} className={`flex-1 py-4 text-[10px] font-black transition-all ${mobileTab === 'STATS' ? 'bg-black text-white' : 'text-gray-400'}`}>THỐNG KÊ LÔ</button>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden">
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[65%] flex-col h-full overflow-hidden relative border-r-2 border-black`}>
                <div className="flex flex-col shrink-0 bg-white z-20 border-b-2 border-black">
                    <div className="px-4 py-2 flex justify-between items-center bg-gray-50/80">
                       <div ref={batchWrapperRef} className="relative">
                            <div className="flex items-center bg-white border-2 border-black rounded-lg px-2 py-1 shadow-vivid-sm cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                                <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-28 text-[10px] font-black text-black outline-none bg-transparent uppercase" placeholder="LÔ HÀNG..." />
                                <i className="fas fa-chevron-down text-[8px] ml-2"></i>
                            </div>
                            {showBatchSuggestions && (
                                <div className="absolute top-full left-0 mt-1 w-56 bg-white border-2 border-black rounded-xl shadow-vivid-lg z-[100] overflow-hidden">
                                    {existingBatches.map(b => <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-4 py-3 hover:bg-gray-100 cursor-pointer text-xs font-black text-black border-b border-gray-100 last:border-0">{b}</div>)}
                                </div>
                            )}
                       </div>
                       <button onClick={handleVoiceInput} disabled={isListening} className={`w-10 h-10 rounded-xl border-2 border-black flex items-center justify-center transition-all shadow-vivid-sm ${isListening ? 'bg-red-600 text-white animate-pulse' : 'bg-white text-gray-800 hover:bg-gray-50'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'}`}></i></button>
                    </div>
                    <div className="px-4 py-4 flex gap-4 items-center bg-white">
                        <div className="flex-col min-w-[100px]">
                            <div className="text-[9px] text-gray-400 font-black uppercase tracking-widest">Tổng thu:</div>
                            <div className="text-3xl font-black text-eco-700 tracking-tighter leading-none italic">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-[10px] text-gray-400 ml-1 font-bold">đ</span></div>
                        </div>
                        <button onClick={handleSubmit} className="flex-grow bg-black hover:bg-gray-800 text-white rounded-2xl py-4 px-6 font-black text-xs shadow-vivid active:translate-y-[2px] active:shadow-none transition-all uppercase tracking-widest italic">LƯU ĐƠN NGAY <i className="fas fa-check-circle ml-2"></i></button>
                    </div>
                </div>

                <form onSubmit={handleSubmit} className="flex-grow overflow-y-auto p-4 space-y-6 pb-24 bg-gray-50/30">
                    <div className="bg-white p-6 rounded-3xl border-2 border-black shadow-vivid-sm space-y-5">
                        <div className="grid grid-cols-12 gap-4" ref={customerWrapperRef}>
                            <div className="col-span-7 relative">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-widest">Người nhận hàng</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputBaseClass} placeholder="Tên khách hàng..." />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-30 w-full bg-white border-2 border-black rounded-xl shadow-vivid-lg mt-1 max-h-48 overflow-y-auto no-scrollbar">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).slice(0, 5).map(s => <li key={s.id} onClick={() => { setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes }); setShowCustomerSuggestions(false); }} className="px-4 py-3 hover:bg-eco-50 cursor-pointer border-b border-gray-100 flex flex-col"><span className="text-sm font-black text-black">{s.name}</span><span className="text-[9px] text-gray-400 font-bold uppercase">{s.phone} • {s.address}</span></li>)}
                                    </ul>
                                )}
                            </div>
                            <div className="col-span-5">
                                <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-widest">Số điện thoại</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputBaseClass} placeholder="09xxxx" />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-widest">Địa chỉ giao hàng</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputBaseClass} placeholder="Số nhà, đường, quận..." />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1 tracking-widest">Ghi chú nhanh</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputBaseClass} placeholder="Giao hẻm, gọi trước..." />
                            <div className="flex flex-wrap gap-2 mt-3">
                                {quickTags.map(tag => <button key={tag} type="button" onClick={() => addTagToNotes(tag)} className="px-3 py-1.5 bg-white hover:bg-black hover:text-white text-gray-600 rounded-lg text-[9px] font-black border-2 border-black uppercase transition-all shadow-vivid-sm active:translate-y-[1px] active:shadow-none">{tag}</button>)}
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <h3 className="text-[10px] font-black text-black uppercase tracking-widest flex items-center gap-2 italic"><i className="fas fa-shopping-basket"></i> Danh sách hàng</h3>
                            <button type="button" onClick={addItemRow} className="text-[10px] font-black text-eco-700 bg-white px-4 py-2 rounded-xl border-2 border-black uppercase shadow-vivid-sm active:translate-y-[1px] active:shadow-none transition-all">+ Dòng mới</button>
                        </div>
                        {items.map((item, idx) => (
                            <div key={item.id} className="flex items-center gap-3 bg-white p-4 rounded-2xl border-2 border-black shadow-vivid-sm relative">
                                <div className="flex-grow relative">
                                    <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-3 bg-gray-50 border-2 border-transparent rounded-xl text-sm font-black text-black outline-none focus:bg-white focus:border-black uppercase placeholder-gray-300" placeholder="Tên hàng..." />
                                    {activeProductRow === idx && (
                                        <div className="absolute top-full left-0 right-0 mt-1 bg-white border-2 border-black rounded-xl shadow-vivid-lg z-50 max-h-48 overflow-y-auto no-scrollbar">
                                            {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-4 py-3 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-100"><div className="flex flex-col"><span className="text-sm font-black text-gray-800 uppercase">{p.name}</span><span className="text-[9px] text-gray-400 font-black uppercase">Tồn: {p.stockQuantity} sp</span></div><span className="text-xs font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</span></div>)}
                                            <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-3 bg-gray-100 text-center text-[10px] font-black text-eco-600 hover:bg-eco-100 border-t-2 border-black uppercase italic">+ Tạo hàng mới vào kho</div>
                                        </div>
                                    )}
                                </div>
                                <div className="w-20">
                                    <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-3 text-center bg-gray-50 border-2 border-transparent rounded-xl text-sm font-black text-eco-700 outline-none focus:bg-white focus:border-black" placeholder="SL" />
                                </div>
                                <div className="w-28">
                                    <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-3 text-right bg-gray-50 border-2 border-transparent rounded-xl text-sm font-black text-black outline-none focus:bg-white focus:border-black" placeholder="GIÁ" />
                                </div>
                                <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-600 transition-colors"><i className="fas fa-times-circle text-2xl"></i></button>
                            </div>
                        ))}
                    </div>
                </form>
            </div>

            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[35%] flex-col bg-gray-50/50 h-full overflow-hidden`}>
                <div className="p-4 bg-white border-b-2 border-black">
                    <div className="flex gap-2 p-1 bg-gray-100 rounded-xl mb-3 border-2 border-black shadow-vivid-sm">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-2 text-[10px] font-black rounded-lg transition-all ${sidebarTab === tab ? 'bg-black text-white' : 'text-gray-400'}`}>{tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'CẢNH BÁO' : 'TÌM KHO'}</button>)}
                    </div>
                    {sidebarTab === 'SEARCH' && (
                        <div className="relative">
                            <input value={sidebarSearch} onChange={e => setSidebarSearch(e.target.value)} className="w-full pl-8 pr-3 py-3 bg-white border-2 border-black rounded-xl text-[10px] font-black outline-none uppercase shadow-vivid-sm" placeholder="Tìm tên hoặc mã hàng..." />
                            <i className="fas fa-search absolute left-3 top-4 text-gray-300 text-[9px]"></i>
                        </div>
                    )}
                </div>
                <div className="flex-grow overflow-y-auto p-2 space-y-1.5 no-scrollbar">
                    {filteredSidebarProducts.length === 0 ? <div className="flex flex-col items-center justify-center h-60 text-gray-300 opacity-50 italic"><i className="fas fa-layer-group text-3xl mb-3"></i><p className="text-[10px] font-black uppercase tracking-widest text-center leading-relaxed">Chưa có giao dịch<br/>trong lô này</p></div> : filteredSidebarProducts.map((item) => (
                        <div key={item.product.id + (item.isExternal ? '-ext' : '')} className={`flex items-center gap-3 p-3 hover:bg-white rounded-2xl transition-all border-2 ${item.isExternal ? 'border-orange-500 bg-orange-50/30' : 'border-gray-100 bg-white hover:border-black hover:shadow-vivid-sm'} group`}>
                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-[11px] font-black shrink-0 border-2 border-black shadow-vivid-sm ${item.isExternal ? 'bg-orange-600 text-white' : item.soldInBatch > 0 ? 'bg-eco-600 text-white' : 'bg-white text-gray-400'}`}>{item.soldInBatch > 0 ? item.soldInBatch : '0'}</div>
                            <div className="flex-grow min-w-0 flex items-center justify-between gap-2">
                                <div onClick={() => handleQuickInsert(item.product)} className={`text-[11px] font-black truncate cursor-pointer hover:text-eco-600 uppercase tracking-tighter italic ${item.isExternal ? 'text-orange-700' : 'text-black'}`}>{item.product.name}</div>
                                <div className="flex items-center gap-2 shrink-0">
                                    {!item.isExternal && <div className={`text-[10px] font-black uppercase ${item.stock < 5 ? 'text-red-500' : 'text-gray-400'}`}>T:{item.stock}</div>}
                                    <button onClick={() => { setEditingProduct(item.product); setEditMode('IMPORT'); setShowProductModal(true); }} className="opacity-0 group-hover:opacity-100 text-[9px] text-blue-600 font-black uppercase tracking-widest transition-opacity underline">Sửa</button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

export default OrderForm;

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Product, Order, ImportRecord } from '../types';
import { storageService, generateProductSku } from '../services/storageService';
import ConfirmModal from './ConfirmModal';

interface ProductDetailModalProps {
    isOpen: boolean;
    onClose: () => void;
    product: Product;
    onImport: () => void;
    onAdjust: () => void;
    onDelete?: () => void;
}

export const ProductDetailModal: React.FC<ProductDetailModalProps> = ({ isOpen, onClose, product, onImport, onAdjust, onDelete }) => {
    const [history, setHistory] = useState<{order: Order, quantity: number}[]>([]);
    const [activeTab, setActiveTab] = useState<'EXPORT' | 'IMPORT'>('EXPORT');

    useEffect(() => {
        if(isOpen && product) {
            setHistory(storageService.getProductOrderHistory(product.id));
        }
    }, [isOpen, product]);

    const batchExportHistory = useMemo(() => {
        const groups = new Map<string, { batchId: string, quantity: number, date: number, orderCount: number }>();
        history.forEach(item => {
            const batchId = item.order.batchId || 'Chưa phân lô';
            if (!groups.has(batchId)) { groups.set(batchId, { batchId, quantity: 0, date: item.order.createdAt, orderCount: 0 }); }
            const group = groups.get(batchId)!;
            group.quantity += Number(item.quantity) || 0;
            group.orderCount += 1;
            group.date = Math.max(group.date, item.order.createdAt);
        });
        return Array.from(groups.values()).sort((a, b) => b.date - a.date);
    }, [history]);

    const importHistory = useMemo(() => {
        const records = product.importHistory || [];
        return [...records].sort((a, b) => b.date - a.date);
    }, [product]);

    if (!isOpen) return null;

    const totalSold = batchExportHistory.reduce((sum, b) => sum + b.quantity, 0);
    const currentStock = product.stockQuantity || 0;
    const historyImportTotal = importHistory.reduce((sum, r) => sum + r.quantity, 0);
    const hasHistory = historyImportTotal > 0;
    const calculatedTotalImported = hasHistory ? historyImportTotal : (product.totalImported || (currentStock + totalSold));
    const profitPerUnit = product.defaultPrice - (product.importPrice || 0);
    const totalProfit = totalSold * profitPerUnit;
    const percent = calculatedTotalImported > 0 ? Math.min(100, (currentStock / calculatedTotalImported) * 100) : 0;
    const isLow = currentStock < 5;

    return (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white rounded-[2.5rem] shadow-vivid-lg border-4 border-black w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] animate-scale-in">
                <div className="p-6 border-b-2 border-black flex justify-between items-start bg-gray-50">
                    <div>
                        <div className="flex items-center gap-3">
                            <h3 className="font-black text-2xl text-black uppercase tracking-tighter italic">{product.name}</h3>
                            <button onClick={onAdjust} className="w-8 h-8 rounded-xl border-2 border-black bg-white text-black hover:bg-gray-100 flex items-center justify-center transition-all shadow-vivid-sm active:translate-y-[1px] active:shadow-none"><i className="fas fa-pen text-xs"></i></button>
                        </div>
                        <div className="text-[10px] text-gray-400 font-black mt-2 uppercase tracking-widest">ID: {product.id}</div>
                    </div>
                    <button onClick={onClose} className="w-10 h-10 rounded-full bg-white border-2 border-black text-gray-400 hover:text-black flex items-center justify-center shadow-vivid-sm active:translate-y-[1px] active:shadow-none"><i className="fas fa-times"></i></button>
                </div>

                <div className="flex-grow overflow-y-auto p-8 space-y-8 no-scrollbar">
                    <div className="bg-white rounded-3xl border-2 border-black shadow-vivid p-6 relative overflow-hidden">
                        <div className="flex justify-between items-end mb-4">
                            <span className="text-[11px] font-black text-gray-400 uppercase tracking-widest">Số lượng tồn kho</span>
                            <div className="text-right">
                                <span className={`text-5xl font-black tracking-tighter italic ${isLow ? 'text-red-600' : 'text-black'}`}>{currentStock}</span>
                                <span className="text-xs text-gray-400 font-black uppercase ml-2 italic">/ {calculatedTotalImported}</span>
                            </div>
                        </div>
                        <div className="w-full bg-gray-100 rounded-full h-4 mb-6 border-2 border-black overflow-hidden p-0.5">
                            <div className={`h-full rounded-full transition-all duration-700 ${isLow ? 'bg-red-500' : 'bg-eco-500'}`} style={{ width: `${percent}%` }}></div>
                        </div>
                        <div className="grid grid-cols-3 gap-3 pt-2">
                             <div className="text-center p-2 bg-gray-50 rounded-xl border-2 border-black"><div className="text-[9px] text-gray-400 uppercase font-black tracking-widest mb-1">Giá Vốn</div><div className="text-xs font-black text-black">{new Intl.NumberFormat('vi-VN').format(product.importPrice || 0)}đ</div></div>
                             <div className="text-center p-2 bg-blue-50 rounded-xl border-2 border-black shadow-vivid-sm"><div className="text-[9px] text-blue-400 uppercase font-black tracking-widest mb-1">Giá Bán</div><div className="text-xs font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(product.defaultPrice)}đ</div></div>
                             <div className="text-center p-2 bg-eco-50 rounded-xl border-2 border-black shadow-vivid-sm"><div className="text-[9px] text-eco-400 uppercase font-black tracking-widest mb-1">Lãi/SP</div><div className="text-xs font-black text-eco-600">{new Intl.NumberFormat('vi-VN').format(profitPerUnit)}đ</div></div>
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-6">
                         <div className="bg-orange-50 p-5 rounded-3xl border-2 border-black shadow-vivid-sm">
                             <div className="text-[10px] font-black text-orange-400 uppercase tracking-widest">Đã xuất bán</div>
                             <div className="text-2xl font-black text-orange-700 mt-1 italic">{totalSold} <span className="text-xs font-bold not-italic">SP</span></div>
                         </div>
                         <div className="bg-eco-50 p-5 rounded-3xl border-2 border-black shadow-vivid-sm">
                             <div className="text-[10px] font-black text-eco-400 uppercase tracking-widest">Lợi nhuận gộp</div>
                             <div className="text-2xl font-black text-eco-700 mt-1 italic">{new Intl.NumberFormat('vi-VN').format(totalProfit)}<span className="text-xs font-bold not-italic">đ</span></div>
                         </div>
                    </div>

                    <div className="space-y-4">
                        <div className="flex gap-2 p-1 bg-gray-100 rounded-2xl border-2 border-black shadow-vivid-sm">
                            <button onClick={() => setActiveTab('EXPORT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest transition-all rounded-xl ${activeTab === 'EXPORT' ? 'bg-black text-white' : 'text-gray-400'}`}>Lịch sử Xuất</button>
                            <button onClick={() => setActiveTab('IMPORT')} className={`flex-1 py-2 text-[10px] font-black uppercase tracking-widest transition-all rounded-xl ${activeTab === 'IMPORT' ? 'bg-black text-white' : 'text-gray-400'}`}>Lịch sử Nhập</button>
                        </div>
                        <div className="bg-white rounded-2xl border-2 border-black shadow-vivid-sm overflow-hidden max-h-48 overflow-y-auto no-scrollbar">
                            <table className="w-full text-left">
                                <thead className="bg-black text-[9px] font-black text-white uppercase sticky top-0"><tr><th className="p-3">Thời gian</th><th className="p-3 text-center">{activeTab === 'EXPORT' ? 'Lô hàng' : 'Giá Vốn'}</th><th className="p-3 text-right">SL</th></tr></thead>
                                <tbody className="divide-y-2 divide-black/5">
                                    {(activeTab === 'EXPORT' ? batchExportHistory : importHistory).map((h: any, idx: number) => (
                                        <tr key={idx} className="hover:bg-gray-50 transition-colors">
                                            <td className="p-3 text-[11px] font-black text-gray-500">{new Date(h.date).toLocaleDateString('vi-VN')}</td>
                                            <td className="p-3 text-center text-[11px] font-black text-black italic">{activeTab === 'EXPORT' ? h.batchId : new Intl.NumberFormat('vi-VN').format(h.price)}</td>
                                            <td className={`p-3 text-right text-xs font-black ${activeTab === 'EXPORT' ? 'text-red-500' : 'text-eco-600'}`}>{activeTab === 'EXPORT' ? '-' : '+'}{h.quantity}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                <div className="p-6 bg-white border-t-2 border-black flex gap-4">
