                </div>
            </div>
        </div>
    );
};

interface ProductEditModalProps {
    isOpen: boolean;
    onClose: () => void;
    product: Product | null;
    onSave: (data: Product, isImport?: boolean, qty?: number) => Promise<void>;
    initialMode?: 'IMPORT' | 'SET';
}

export const ProductEditModal: React.FC<ProductEditModalProps> = ({ isOpen, onClose, product, onSave, initialMode = 'IMPORT' }) => {
    const [editTab, setEditTab] = useState<'IMPORT' | 'SET'>(initialMode);
    const [importAmount, setImportAmount] = useState<string>('');
    const [formData, setFormData] = useState<Partial<Product>>({ name: '', defaultPrice: 0, importPrice: 0, stockQuantity: 0, totalImported: 0 });
    const [frozenSold, setFrozenSold] = useState(0);

    useEffect(() => {
        if (isOpen) {
            setEditTab(initialMode); setImportAmount('');
            if (product) {
                setFormData({ name: product.name, defaultPrice: product.defaultPrice, importPrice: product.importPrice, stockQuantity: product.stockQuantity, totalImported: product.totalImported || product.stockQuantity });
                setFrozenSold(Math.max(0, (product.totalImported || 0) - (product.stockQuantity || 0)));
            } else {
                setFormData({ name: '', defaultPrice: 0, importPrice: 0, stockQuantity: 0, totalImported: 0 }); setFrozenSold(0); setEditTab('SET');
            }
        }
    }, [isOpen, product, initialMode]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.name) return;
        if (editTab === 'IMPORT' && product) {
            const qty = Number(importAmount) || 0;
            if (qty > 0) { await onSave({ ...product, name: formData.name || product.name, defaultPrice: Number(formData.defaultPrice) || 0, importPrice: Number(formData.importPrice) || 0 }, true, qty); onClose(); return; }
        }
        const total = Number(formData.totalImported) || 0;
        const finalStock = Math.max(0, total - frozenSold);
        await onSave({ id: product?.id || generateProductSku(formData.name!), name: formData.name!, defaultPrice: Number(formData.defaultPrice) || 0, importPrice: Number(formData.importPrice) || 0, defaultWeight: 1, stockQuantity: finalStock, totalImported: total, lastImportDate: Date.now(), importHistory: product?.importHistory || [] }, false, 0);
        onClose();
    };

    if (!isOpen) return null;
    const vInputClass = "w-full p-4 bg-white border-2 border-black rounded-2xl outline-none focus:ring-4 focus:ring-eco-50 font-black text-black text-sm transition-all shadow-vivid-sm";

    return (
        <div className="fixed inset-0 z-[110] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white rounded-[2.5rem] shadow-vivid-lg border-4 border-black w-full max-w-md overflow-hidden flex flex-col max-h-[90vh] animate-scale-in">
                <div className="p-6 border-b-2 border-black flex justify-between items-center bg-gray-50">
                    <h3 className="font-black text-black uppercase text-sm tracking-widest italic">{product ? 'Điều chỉnh kho hàng' : 'Thêm mặt hàng mới'}</h3>
                    <button onClick={onClose} className="w-10 h-10 rounded-full bg-white border-2 border-black text-gray-400 hover:text-black flex items-center justify-center shadow-vivid-sm active:translate-y-[1px] active:shadow-none"><i className="fas fa-times"></i></button>
                </div>
                <form onSubmit={handleSubmit} className="p-8 space-y-6 overflow-y-auto no-scrollbar">
                    <div>
                        <label className="text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 block tracking-widest">Tên sản phẩm *</label>
                        <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className={vInputClass} placeholder="VD: Gạo ST25..." />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 block tracking-widest">Giá bán</label>
                            <input type="number" value={formData.defaultPrice} onChange={e => setFormData({...formData, defaultPrice: Number(e.target.value)})} className={`${vInputClass} text-blue-600 italic`} />
                        </div>
                        <div>
                            <label className="text-[10px] font-black text-gray-400 uppercase mb-2 ml-1 block tracking-widest">Giá vốn</label>
                            <input type="number" value={formData.importPrice} onChange={e => setFormData({...formData, importPrice: Number(e.target.value)})} className={vInputClass} />
                        </div>
                    </div>
                    {product && (
                        <div className="flex bg-gray-100 p-1 rounded-2xl border-2 border-black shadow-vivid-sm">
                            <button type="button" onClick={() => setEditTab('IMPORT')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${editTab === 'IMPORT' ? 'bg-black text-white' : 'text-gray-400'}`}>Nhập thêm</button>
                            <button type="button" onClick={() => setEditTab('SET')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${editTab === 'SET' ? 'bg-black text-white' : 'text-gray-400'}`}>Sửa tồn</button>
                        </div>
                    )}
                    <div className={`p-6 rounded-3xl border-2 border-black shadow-vivid-sm ${editTab === 'IMPORT' ? 'bg-blue-50' : 'bg-orange-50'}`}>
                        {editTab === 'IMPORT' && product ? (
                            <>
                                <label className="text-[10px] font-black text-blue-600 uppercase mb-2 block tracking-widest">Số lượng nhập thêm (+)</label>
                                <input type="number" value={importAmount} onChange={e => setImportAmount(e.target.value)} className={`${vInputClass} text-center text-2xl italic`} placeholder="0" />
                            </>
                        ) : (
                            <div className="space-y-4">
                                <div>
                                    <label className="text-[10px] font-black text-orange-600 uppercase mb-2 block tracking-widest">Tổng số lượng đã nhập</label>
                                    <input type="number" value={formData.totalImported} onChange={e => setFormData({...formData, totalImported: Number(e.target.value)})} className={`${vInputClass} text-center italic`} />
                                </div>
                                <div className="flex justify-between items-center bg-white border-2 border-black p-3 rounded-2xl font-black text-xs uppercase tracking-tighter">
                                    <span className="text-gray-400">Tồn kho dự kiến:</span>
                                    <span className="text-xl text-orange-600">{Math.max(0, (Number(formData.totalImported) || 0) - frozenSold)}</span>
                                </div>
                            </div>
                        )}
                    </div>
                    <button type="submit" className="w-full py-5 bg-black text-white rounded-2xl font-black text-sm uppercase shadow-vivid-lg hover:bg-gray-800 active:translate-y-[2px] active:shadow-none transition-all mt-4 tracking-[0.2em] italic">Xác nhận lưu <i className="fas fa-check-circle ml-2"></i></button>
                </form>
            </div>
        </div>
    );
};

const InventoryManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
