    <div className="max-w-7xl mx-auto pb-24 animate-fade-in relative px-2">
      <div className="sticky top-16 z-30 bg-white border-b-2 border-black p-4 shadow-vivid-sm mb-6 rounded-2xl">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
