              <div className="flex items-center gap-4">
                  <div className="relative flex-grow md:w-72">
                      <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Tìm tên hàng hóa..." className="w-full pl-9 pr-3 py-3 bg-white border-2 border-black rounded-xl text-xs font-black outline-none shadow-vivid-sm" />
                      <i className="fas fa-search absolute left-3 top-4 text-gray-400 text-[10px]"></i>
                  </div>
                  <button onClick={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="bg-black text-white px-6 py-3.5 rounded-2xl font-black text-xs shadow-vivid hover:bg-gray-800 active:translate-y-[2px] active:shadow-none transition-all uppercase tracking-widest shrink-0 italic">+ Mặt hàng mới</button>
              </div>
          </div>
          <div className="flex gap-3 overflow-x-auto no-scrollbar mt-4 pb-1">
              <div className="flex items-center gap-2 bg-blue-50 border-2 border-black px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-vivid-sm whitespace-nowrap"><span className="text-blue-400">Vốn tồn:</span><span className="text-blue-700">{new Intl.NumberFormat('vi-VN').format(stats.capital)}đ</span></div>
              <div className="flex items-center gap-2 bg-eco-50 border-2 border-black px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-vivid-sm whitespace-nowrap"><span className="text-eco-400">Lãi dự kiến:</span><span className="text-eco-700">{new Intl.NumberFormat('vi-VN').format(stats.profit)}đ</span></div>
              <div className="flex items-center gap-2 bg-red-50 border-2 border-black px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-vivid-sm whitespace-nowrap"><span className="text-red-400">Sắp hết:</span><span className="text-red-700">{stats.low} SP</span></div>
          </div>
      </div>

      <div className="py-4">
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
              {filteredProducts.map(p => {
                  const current = p.stockQuantity || 0; const isLow = current < 5;
                  return (
                      <div key={p.id} onClick={() => setViewingProduct(p)} className="bg-white rounded-3xl border-2 border-black shadow-vivid hover:translate-x-[2px] hover:translate-y-[2px] hover:shadow-vivid-sm cursor-pointer transition-all overflow-hidden flex flex-col group relative">
                          <div className="p-5 flex-grow">
                              <h3 className="text-xs font-black text-black uppercase leading-tight line-clamp-2 h-8 group-hover:text-blue-600 transition-colors italic" title={p.name}>{p.name}</h3>
                              <div className="mt-6 flex justify-between items-end">
                                  <span className={`text-4xl font-black tracking-tighter italic ${isLow ? 'text-red-600' : 'text-black'}`}>{current}</span>
                                  <div className="text-right">
                                      <span className="text-[8px] font-black text-gray-400 uppercase block mb-1 tracking-widest">Giá Bán</span>
                                      <span className="text-sm font-black text-blue-600 italic">{new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(p.defaultPrice)}</span>
                                  </div>
                              </div>
                          </div>
                          <div className="bg-gray-50 border-t-2 border-black px-5 py-3 flex justify-between items-center group-hover:bg-gray-100 transition-colors">
                              <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] italic">Chi tiết <i className="fas fa-arrow-right ml-1 text-[8px]"></i></span>
                              <div className={`w-3 h-3 rounded-full border border-black ${isLow ? 'bg-red-500 animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.5)]' : 'bg-eco-500'}`}></div>
                          </div>
                      </div>
                  );
              })}
          </div>
      </div>

      {viewingProduct && <ProductDetailModal isOpen={!!viewingProduct} onClose={() => setViewingProduct(null)} product={viewingProduct} onImport={() => { setEditingProduct(viewingProduct); setEditMode('IMPORT'); setViewingProduct(null); setShowProductModal(true); }} onAdjust={() => { setEditingProduct(viewingProduct); setEditMode('SET'); setViewingProduct(null); setShowProductModal(true); }} onDelete={() => { setDeleteId(viewingProduct.id); setShowDeleteConfirm(true); setViewingProduct(null); }} />}
      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa mặt hàng?" message="Sản phẩm sẽ bị xóa vĩnh viễn khỏi kho hàng." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa Ngay" isDanger={true} />
    </div>
  );
};

