const dataURLtoFile = (dataurl: string, filename: string) => {
    const arr = dataurl.split(',');
    const mime = arr[0].match(/:(.*?);/)?.[1];
    const bstr = atob(arr[1]);
    let n = bstr.length;
    const u8arr = new Uint8Array(n);
    while (n--) {
        u8arr[n] = bstr.charCodeAt(n);
    }
    return new File([u8arr], filename, { type: mime });
};

const PaymentAudit: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [bankConfig, setBankConfig] = useState<any>(null);
  const [shopConfig, setShopConfig] = useState<ShopConfig | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedBatch, setSelectedBatch] = useState('ALL');
  const [selectedGroup, setSelectedGroup] = useState<CustomerDebtGroup | null>(null);
  const [confirmData, setConfirmData] = useState<{isOpen: boolean, ids: string[], message: string}>({ isOpen: false, ids: [], message: '' });
  const [isSharing, setIsSharing] = useState(false);
  const groupQrImgRef = useRef<HTMLImageElement | null>(null);

  useEffect(() => {
    const unsub = storageService.subscribeOrders((allOrders) => {
      const validOrders = new Map<string, Order>();
      const validIdRegex = /^[A-Z0-9]{8}$/;
      if (allOrders && Array.isArray(allOrders)) {
          allOrders.forEach(o => {
              if (!o || !o.id) return;
              if (!validIdRegex.test(o.id)) return;
              if (o.status === OrderStatus.CANCELLED) return;
              if (o.paymentMethod !== PaymentMethod.TRANSFER) return;
              if (o.paymentVerified) return;
              validOrders.set(o.id, o); 
          });
      }
      const sorted = Array.from(validOrders.values()).sort((a, b) => b.createdAt - a.createdAt);
      setOrders(sorted);
    });
    storageService.getBankConfig().then(setBankConfig);
    storageService.getShopConfig().then(setShopConfig);
    return () => { if (unsub) unsub(); };
  }, []);

  useEffect(() => {
      if (selectedGroup && bankConfig && bankConfig.accountNo) {
          const idsStr = selectedGroup.orders.map(o => o.id).join(' ');
          const desc = `DH ${idsStr}`;
          const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${selectedGroup.totalAmount}&addInfo=${encodeURIComponent(desc)}&accountName=${encodeURIComponent(bankConfig.accountName)}`;
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = qrUrl;
          img.onload = () => { groupQrImgRef.current = img; };
      } else { groupQrImgRef.current = null; }
  }, [selectedGroup, bankConfig]);

  const batches = useMemo(() => {
    const batchSet = new Set<string>();
    orders.forEach(o => { if (o.batchId) batchSet.add(o.batchId); });
    return Array.from(batchSet).sort();
  }, [orders]);

  const filteredOrders = useMemo(() => {
    return orders.filter(o => {
        const matchSearch = searchTerm === '' || o.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerPhone.includes(searchTerm) || o.id.includes(searchTerm.toUpperCase());
        const matchBatch = selectedBatch === 'ALL' || o.batchId === selectedBatch;
        return matchSearch && matchBatch;
    });
  }, [orders, searchTerm, selectedBatch]);

  const totalAmount = filteredOrders.reduce((sum, o) => sum + o.totalPrice, 0);

  const customerGroups = useMemo(() => {
      const groups: Record<string, CustomerDebtGroup> = {};
      const processedIds = new Set<string>(); 
      filteredOrders.forEach(o => {
          if (processedIds.has(o.id)) return;
          processedIds.add(o.id);
          let key = o.customerId ? `${o.customerId}_${normalizeString(o.customerName)}` : (o.customerPhone && o.customerPhone.length > 6 ? normalizePhone(o.customerPhone) : `${normalizeString(o.customerName)}|${normalizeString(o.address || 'unknown')}`);
          if (!groups[key]) { groups[key] = { key, customerId: o.customerId || '', customerName: o.customerName, customerPhone: o.customerPhone, orders: [], totalAmount: 0, maxReminders: 0 }; }
          else { if (!groups[key].customerId && o.customerId) groups[key].customerId = o.customerId; if ((!groups[key].customerPhone || groups[key].customerPhone.length < 8) && o.customerPhone) { groups[key].customerPhone = o.customerPhone; } }
          groups[key].orders.push(o);
          groups[key].totalAmount += (o.totalPrice || 0);
          groups[key].maxReminders = Math.max(groups[key].maxReminders || 0, o.reminderCount || 0);
      });
      return Object.values(groups).sort((a, b) => b.totalAmount - a.totalAmount);
  }, [filteredOrders]);

  const executeConfirm = async () => {
    if (confirmData.ids.length > 0) {
      const firstOrder = orders.find(o => o.id === confirmData.ids[0]);
      const promises = confirmData.ids.map(id => storageService.updatePaymentVerification(id, true, firstOrder ? { name: firstOrder.customerName } : undefined));
      await Promise.all(promises);
      toast.success(`Đã xác nhận tiền về!`);
      setConfirmData({ isOpen: false, ids: [], message: '' });
      setSelectedGroup(null);
    }
  };

  const handleConfirmGroup = (group: CustomerDebtGroup) => {
      const ids = group.orders.map(o => o.id);
      setConfirmData({ isOpen: true, ids: ids, message: `Xác nhận đã nhận đủ ${new Intl.NumberFormat('vi-VN').format(group.totalAmount)}đ từ khách ${group.customerName}?` });
  };

  const generateAndShareQR = async (amount: number, content: string, title: string, relatedIds: string[], customerName: string, orderCount: number, itemsSummary: Record<string, number>, preloadedImg?: HTMLImageElement) => {
    if (!bankConfig || !bankConfig.accountNo) { toast.error("Thiếu thông tin Ngân hàng"); return; }
    setIsSharing(true);
    const toastId = toast.loading("Đang ghim mã thanh toán...");
    try {
        let qrImg = preloadedImg;
        if (!qrImg) {
            const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${amount}&addInfo=${encodeURIComponent(content)}&accountName=${encodeURIComponent(bankConfig.accountName)}`;
            qrImg = new Image(); qrImg.crossOrigin = "Anonymous"; qrImg.src = qrUrl;
            await new Promise((resolve, reject) => { if(qrImg) { qrImg.onload = resolve; qrImg.onerror = reject; } });
        }
        const canvas = document.createElement('canvas'); const ctx = canvas.getContext('2d'); if (!ctx) throw new Error("Canvas error");
        const W = 800; const qrSize = 500; const qrRatio = qrImg ? (qrImg.naturalWidth / qrImg.naturalHeight) : 1; const drawHeight = qrSize / qrRatio;
        const itemsList = Object.entries(itemsSummary);
        let H = 0; H += 140; H += 40; H += 100; H += 40; H += drawHeight; H += 40; H += 150; H += 40; H += 60; H += (itemsList.length * 50); H += 40; H += 120; H += 50;
        canvas.width = W; canvas.height = H;
        ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);
        let cursorY = 0;
        ctx.fillStyle = '#2563eb'; ctx.fillRect(0, cursorY, W, 140);
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 40px Arial, sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText('THANH TOÁN CÔNG NỢ', W / 2, cursorY + 70);
        ctx.fillStyle = '#000'; ctx.font = 'bold 32px Arial, sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'top'; ctx.fillText((shopConfig?.shopName || 'ECOGO LOGISTICS').toUpperCase(), W / 2, cursorY + 140 + 20);
        cursorY += 140; cursorY += 40;
        ctx.fillStyle = '#eff6ff'; if ((ctx as any).roundRect) { ctx.beginPath(); (ctx as any).roundRect(100, cursorY, 600, 100, 20); ctx.fill(); } else { ctx.fillRect(100, cursorY, 600, 100); }
        ctx.strokeStyle = '#000'; ctx.lineWidth = 2; ctx.stroke();
        ctx.fillStyle = '#1e40af'; ctx.font = 'bold 60px Arial, sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText(`${new Intl.NumberFormat('vi-VN').format(amount)}đ`, W / 2, cursorY + 50);
        cursorY += 100; cursorY += 40;
        if (qrImg) { ctx.drawImage(qrImg, (W - qrSize) / 2, cursorY, qrSize, drawHeight); }
        cursorY += drawHeight; cursorY += 40;
        ctx.strokeStyle = '#000'; ctx.lineWidth = 2; ctx.setLineDash([10, 10]); ctx.beginPath(); ctx.moveTo(50, cursorY); ctx.lineTo(W - 50, cursorY); ctx.stroke(); ctx.setLineDash([]);
        cursorY += 40;
        ctx.fillStyle = '#1f2937'; ctx.textAlign = 'left'; ctx.textBaseline = 'top';
        ctx.font = 'normal 28px Arial, sans-serif'; ctx.fillStyle = '#6b7280'; ctx.fillText('Khách hàng:', 80, cursorY);
        ctx.font = 'bold 28px Arial, sans-serif'; ctx.fillStyle = '#111827'; ctx.fillText(customerName, 300, cursorY);
        cursorY += 50;
        ctx.font = 'normal 28px Arial, sans-serif'; ctx.fillStyle = '#6b7280'; ctx.fillText('Số lượng đơn:', 80, cursorY);
        ctx.font = 'bold 28px Arial, sans-serif'; ctx.fillStyle = '#111827'; ctx.fillText(`${orderCount} đơn hàng`, 300, cursorY);
        cursorY += 70;
        ctx.fillStyle = '#f3f4f6'; ctx.fillRect(50, cursorY, 700, 40);
        ctx.fillStyle = '#374151'; ctx.font = 'bold 24px Arial, sans-serif'; ctx.textAlign = 'left'; ctx.fillText('Chi tiết hàng hóa tổng hợp', 70, cursorY + 8);
        cursorY += 50;
        ctx.font = 'normal 26px Arial, sans-serif'; ctx.textBaseline = 'middle';
        itemsList.forEach(([name, qty], index) => {
            const rowCenterY = cursorY + 20;
            ctx.fillStyle = '#1f2937'; ctx.textAlign = 'left'; ctx.fillText(`${index + 1}. ${name.length > 35 ? name.substring(0, 32) + "..." : name}`, 70, rowCenterY);
            ctx.textAlign = 'right'; ctx.font = 'bold 26px Arial, sans-serif'; ctx.fillText(`x${qty}`, 730, rowCenterY); ctx.font = 'normal 26px Arial, sans-serif';
            ctx.beginPath(); ctx.strokeStyle = '#f3f4f6'; ctx.lineWidth = 1; ctx.moveTo(70, cursorY + 45); ctx.lineTo(730, cursorY + 45); ctx.stroke();
            cursorY += 50;
        });
        cursorY += 40;
        if (bankConfig) {
            const footerY = cursorY; ctx.fillStyle = '#f9fafb'; ctx.fillRect(0, footerY, W, 120);
            ctx.fillStyle = '#4b5563'; ctx.font = 'italic 24px Arial, sans-serif'; ctx.textAlign = 'center'; ctx.textBaseline = 'top';
            ctx.fillText(`${bankConfig.bankId}: ${bankConfig.accountNo}`, W / 2, footerY + 30); ctx.fillText(`${bankConfig.accountName}`, W / 2, footerY + 70);
        }
        const dataUrl = canvas.toDataURL('image/png'); const file = dataURLtoFile(dataUrl, `debt-${Date.now()}.png`);
        storageService.incrementReminderCount(relatedIds);
        if (navigator.share) { await navigator.share({ title: title, text: `Thanh toán công nợ ${customerName}`, files: [file] }); toast.success("Đã gửi mã!"); }
        else { const a = document.createElement('a'); a.href = dataUrl; a.download = `debt-${Date.now()}.png`; a.click(); toast.success("Đã tải ảnh xuống"); }
    } catch (e: any) { toast.error("Lỗi tạo phiếu"); } finally { setIsSharing(false); toast.dismiss(toastId); }
  };

  const handleShareGroupQR = (group: CustomerDebtGroup) => {
      const idsStr = group.orders.map(o => o.id).join(' '); const ids = group.orders.map(o => o.id);
      const itemsSummary: Record<string, number> = {};
      group.orders.forEach(o => { o.items.forEach(item => { const name = item.name.trim(); if (name) { itemsSummary[name] = (itemsSummary[name] || 0) + item.quantity; } }); });
      generateAndShareQR(group.totalAmount, `DH ${idsStr}`, `Thanh toán ${group.orders.length} đơn`, ids, group.customerName, group.orders.length, itemsSummary, groupQrImgRef.current || undefined);
  };

  const handleSMS = async (group: CustomerDebtGroup) => {
     const phone = group.customerPhone; if (!phone || !bankConfig?.accountNo) { toast.error("Thiếu SĐT hoặc TK Ngân hàng"); return; }
     const ids = group.orders.map(o => o.id); storageService.incrementReminderCount(ids);
     const msg = `Chào ${group.customerName}, tổng tiền ${group.orders.length} đơn là ${new Intl.NumberFormat('vi-VN').format(group.totalAmount)}đ. CK tới ${bankConfig.accountNo} (${bankConfig.bankId}). ND: DH ${ids.join(' ')}. Tks!`;
     const isIOS = /iphone|ipad|ipod/.test(navigator.userAgent.toLowerCase());
     window.open(`sms:${phone}${isIOS ? '&' : '?'}body=${encodeURIComponent(msg)}`, '_self');
  };

  return (
    <div className="max-w-7xl mx-auto pb-24 animate-fade-in px-2 sm:px-4">
      <div className="bg-white rounded-3xl p-6 border-2 border-black shadow-vivid mb-6 flex flex-col md:flex-row justify-between items-center gap-4 sticky top-16 z-30">
        <div className="flex items-center gap-5">
             <div className="w-14 h-14 rounded-2xl bg-eco-500 border-2 border-black text-white flex items-center justify-center text-2xl shadow-vivid-sm italic">
                 <i className="fas fa-hand-holding-usd"></i>
             </div>
             <div>
                 <h2 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">Tổng tiền chờ thu</h2>
                 <div className="text-3xl font-black text-black leading-none italic tracking-tighter">
                     {new Intl.NumberFormat('vi-VN').format(totalAmount)}<span className="text-sm text-gray-400 ml-1 font-bold not-italic">đ</span>
                 </div>
             </div>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="relative">
                <select value={selectedBatch} onChange={e => setSelectedBatch(e.target.value)} className="appearance-none bg-white border-2 border-black text-black py-3 pl-4 pr-10 rounded-xl text-xs font-black outline-none shadow-vivid-sm cursor-pointer uppercase italic">
                    <option value="ALL">📦 Tất cả Lô</option>
                    {batches.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
                <i className="fas fa-chevron-down absolute right-3 top-4 text-black text-[10px] pointer-events-none"></i>
            </div>
            <div className="relative flex-grow md:w-72">
                 <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Tìm khách hàng, SĐT..." className="w-full pl-10 pr-4 py-3 bg-white border-2 border-black rounded-xl text-xs font-black outline-none shadow-vivid-sm uppercase" />
                 <i className="fas fa-search absolute left-4 top-4 text-gray-400 text-[10px]"></i>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-vivid border-2 border-black overflow-hidden">
          {filteredOrders.length === 0 ? (
               <div className="text-center py-24 flex flex-col items-center justify-center text-gray-300 italic">
                   <i className="fas fa-check-circle text-6xl mb-4 opacity-10"></i>
                   <p className="text-[11px] font-black uppercase tracking-[0.3em]">Không có nợ tồn đọng</p>
               </div>
          ) : (
            <div className="overflow-x-auto no-scrollbar">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-black text-white font-black uppercase text-[10px] tracking-[0.15em] italic">
                        <tr>
                            <th className="p-4 text-center w-12 border-r border-white/20">#</th>
                            <th className="p-4">Khách Hàng</th>
                            <th className="p-4 hidden sm:table-cell">Liên hệ</th>
                            <th className="p-4 text-center">Đơn</th>
                            <th className="p-4 text-center hidden sm:table-cell">Đã nhắc</th>
                            <th className="p-4 text-right">Tổng nợ</th>
                            <th className="p-4 text-center w-16"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y-2 divide-black/5">
                        {customerGroups.map((group, idx) => (
                            <tr key={group.key} onClick={() => setSelectedGroup(group)} className="hover:bg-eco-50 cursor-pointer transition-colors group">
                                <td className="p-4 text-center font-black text-gray-300 text-xs border-r border-black/5">{idx + 1}</td>
                                <td className="p-4">
                                    <div className="font-black text-black text-sm uppercase italic tracking-tighter">{group.customerName}</div>
                                    <div className="sm:hidden text-[10px] font-bold text-gray-400 mt-1">{group.customerPhone}</div>
                                </td>
                                <td className="p-4 hidden sm:table-cell">
                                    <span className="text-[10px] font-black text-black bg-gray-100 border border-black px-2 py-1 rounded-lg uppercase">{group.customerPhone || 'N/A'}</span>
                                </td>
                                <td className="p-4 text-center">
                                    <span className="text-xs font-black text-black bg-white border-2 border-black px-3 py-1 rounded-xl shadow-vivid-sm">{group.orders.length}</span>
                                </td>
                                <td className="p-4 text-center hidden sm:table-cell">
                                    {group.maxReminders > 0 && <span className="inline-flex items-center gap-1 text-[10px] font-black px-2 py-1 rounded-lg bg-orange-600 text-white shadow-vivid-sm animate-bounce-slow"><i className="fas fa-bell text-[8px]"></i> {group.maxReminders}</span>}
                                </td>
                                <td className="p-4 text-right">
                                    <span className="font-black text-eco-600 text-sm italic">{new Intl.NumberFormat('vi-VN').format(group.totalAmount)}</span>
                                </td>
                                <td className="p-4 text-center">
                                    <button className="w-8 h-8 rounded-full border-2 border-black bg-white text-black shadow-vivid-sm group-hover:bg-black group-hover:text-white transition-all active:translate-y-[1px] active:shadow-none"><i className="fas fa-chevron-right text-[10px]"></i></button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
          )}
      </div>

      {selectedGroup && (
          <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={() => setSelectedGroup(null)}>
              <div className="bg-white rounded-[2.5rem] shadow-vivid-lg border-4 border-black w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] animate-scale-in" onClick={e => e.stopPropagation()}>
                  <div className="p-6 border-b-2 border-black flex justify-between items-start bg-gray-50">
                      <div>
                          <div className="flex items-center gap-3">
                              <h3 className="font-black text-2xl text-black uppercase italic tracking-tighter">{selectedGroup.customerName}</h3>
                              {selectedGroup.maxReminders > 0 && <span className="bg-orange-600 text-white text-[9px] font-black px-2 py-1 rounded-lg shadow-vivid-sm">ĐÃ NHẮC {selectedGroup.maxReminders} LẦN</span>}
                          </div>
                          <div className="text-xs font-black text-gray-400 mt-2 uppercase tracking-widest flex items-center gap-2 italic">
                              <i className="fas fa-phone-alt"></i> {selectedGroup.customerPhone || 'CHƯA CẬP NHẬT'}
                          </div>
                      </div>
                      <div className="text-right">
                          <div className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Tổng dư nợ</div>
                          <div className="text-2xl font-black text-eco-600 italic tracking-tighter">{new Intl.NumberFormat('vi-VN').format(selectedGroup.totalAmount)}đ</div>
                      </div>
                  </div>

                  <div className="flex-grow overflow-y-auto p-6 space-y-4 bg-gray-100/30 no-scrollbar">
                      <div className="text-[10px] font-black text-black uppercase tracking-[0.2em] mb-4 italic ml-2">Danh sách đơn nợ ({selectedGroup.orders.length})</div>
                      {selectedGroup.orders.map(o => (
                          <div key={o.id} className="bg-white p-4 rounded-2xl border-2 border-black shadow-vivid-sm group">
                              <div className="flex justify-between items-start mb-2">
                                  <div className="flex items-center gap-2">
                                      <span className="font-black text-blue-600 bg-blue-50 border border-blue-200 px-2 py-0.5 rounded text-[10px] italic">#{o.id}</span>
                                      {o.batchId && <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{o.batchId}</span>}
                                  </div>
                                  <span className="font-black text-black text-sm italic">{new Intl.NumberFormat('vi-VN').format(o.totalPrice)}</span>
                              </div>
                              <div className="text-[11px] font-bold text-gray-700 leading-relaxed italic border-l-2 border-black pl-3 py-1">
                                  {o.items.map(i => `${i.name} (x${i.quantity})`).join(', ')}
                              </div>
                              {o.notes && <div className="text-[9px] font-black text-orange-600 uppercase tracking-widest mt-2 flex items-center gap-2"><i className="fas fa-sticky-note"></i> {o.notes}</div>}
                          </div>
                      ))}
                  </div>

                  <div className="p-6 bg-white border-t-2 border-black grid grid-cols-2 gap-4">
                      <button onClick={() => handleConfirmGroup(selectedGroup)} className="col-span-2 py-5 bg-eco-600 hover:bg-eco-700 text-white font-black text-xs rounded-2xl border-2 border-black shadow-vivid transition-all active:translate-y-[2px] active:shadow-none uppercase tracking-[0.2em] italic flex items-center justify-center gap-2"><i className="fas fa-check-circle"></i> Đã thanh toán</button>
                      <button onClick={() => handleShareGroupQR(selectedGroup)} disabled={isSharing} className="py-4 bg-white border-2 border-black hover:bg-gray-50 text-blue-600 font-black rounded-2xl shadow-vivid transition-all active:translate-y-[2px] active:shadow-none uppercase text-[10px] tracking-widest italic flex items-center justify-center gap-2"><i className="fas fa-qrcode"></i> Gửi mã QR</button>
                      <button onClick={() => handleSMS(selectedGroup)} className="py-4 bg-white border-2 border-black hover:bg-gray-50 text-orange-600 font-black rounded-2xl shadow-vivid transition-all active:translate-y-[2px] active:shadow-none uppercase text-[10px] tracking-widest italic flex items-center justify-center gap-2"><i className="fas fa-comment-dots"></i> Nhắn SMS</button>
                  </div>
              </div>
          </div>
      )}

      <ConfirmModal isOpen={confirmData.isOpen} title="Chốt công nợ" message={confirmData.message} onConfirm={executeConfirm} onCancel={() => setConfirmData({ ...confirmData, isOpen: false })} confirmLabel="Đã nhận tiền" isDanger={false} />
    </div>
  );
};

export default PaymentAudit;

import React, { useState, useEffect, useRef, useDeferredValue } from 'react';
import toast from 'react-hot-toast';
import { Customer } from '../types';
import { storageService } from '../services/storageService';
import { verifyAddress } from '../services/geminiService';
import ConfirmModal from './ConfirmModal';
import { v4 as uuidv4 } from 'uuid';

const CustomerManager: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [filteredCustomers, setFilteredCustomers] = useState<Customer[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);

  const [formData, setFormData] = useState<Partial<Customer>>({ name: '', phone: '', address: '', priorityScore: 999, socialLink: '' });
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const [showImportModal, setShowImportModal] = useState(false);
  const [importText, setImportText] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [importMode, setImportMode] = useState<'TEXT' | 'JSON'>('TEXT');

  const [isListeningSearch, setIsListeningSearch] = useState(false);
  const [isVerifyingAddr, setIsVerifyingAddr] = useState(false);

  useEffect(() => { 
      const unsubscribe = storageService.subscribeCustomers(setCustomers); 
      return () => { if (unsubscribe) unsubscribe(); }; 
  }, []);

  useEffect(() => { 
      let result = customers;
      if (deferredSearchTerm) { 
          const lower = deferredSearchTerm.toLowerCase(); 
          result = customers.filter(c => c.name.toLowerCase().includes(lower) || (c.phone && c.phone.includes(lower)) || c.address.toLowerCase().includes(lower)); 
      }
      result.sort((a, b) => {
          const pA = a.priorityScore || 999;
          const pB = b.priorityScore || 999;
          if (pA !== pB) return pA - pB;
          return a.name.localeCompare(b.name);
      });
      setFilteredCustomers(result); 
  }, [customers, deferredSearchTerm]);

  const handleDeleteClick = (id: string) => { setDeleteId(id); setShowDeleteConfirm(true); };
  const confirmDelete = async () => { if (deleteId) { await storageService.deleteCustomer(deleteId); toast.success('Đã xóa khách hàng'); setShowDeleteConfirm(false); setDeleteId(null); } };

  const handleVoiceSearch = () => {
