      <ConfirmModal isOpen={showDeleteConfirm} title="Xóa khách hàng?" message="Thông tin liên hệ sẽ bị xóa vĩnh viễn khỏi hệ thống." onConfirm={confirmDelete} onCancel={() => setShowDeleteConfirm(false)} confirmLabel="Xóa Ngay" isDanger={true} />
    </div>
  );
};

