import React, { useEffect, useState, useMemo } from 'react';
import { Order, OrderStatus } from '../types';
import { storageService } from '../services/storageService';
import toast from 'react-hot-toast';

interface Props {
    isOpen: boolean;
    onClose: () => void;
}

interface BatchStats {
    id: string;
    date: number;
    orderCount: number;
    revenue: number;
    cost: number;
    profit: number;
}

const RevenueReport: React.FC<Props> = ({ isOpen, onClose }) => {
    const [loading, setLoading] = useState(false);
    const [orders, setOrders] = useState<Order[]>([]);

    useEffect(() => {
        if (isOpen) {
            setLoading(true);
            storageService.fetchLongTermStats()
                .then(data => setOrders(data))
                .catch(err => toast.error("Lỗi tải dữ liệu"))
                .finally(() => setLoading(false));
        }
    }, [isOpen]);

    const stats = useMemo(() => {
        const monthlyData: Record<string, number> = {};
        const batchDataMap: Record<string, BatchStats> = {};
        let totalRevenue = 0, totalProfit = 0;

        orders.forEach(o => {
            if (o.status === OrderStatus.CANCELLED) return;
            const date = new Date(o.createdAt);
            const monthKey = `${date.getMonth() + 1}/${date.getFullYear()}`;
            monthlyData[monthKey] = (monthlyData[monthKey] || 0) + o.totalPrice;

            const batchId = o.batchId || 'KHÔNG LÔ';
            if (!batchDataMap[batchId]) {
                batchDataMap[batchId] = { id: batchId, date: o.createdAt, orderCount: 0, revenue: 0, cost: 0, profit: 0 };
            }
            let orderCost = 0;
            o.items.forEach(it => { orderCost += (it.importPrice || 0) * it.quantity; });
            const orderProfit = o.totalPrice - orderCost;
            batchDataMap[batchId].orderCount += 1;
            batchDataMap[batchId].revenue += o.totalPrice;
            batchDataMap[batchId].cost += orderCost;
            batchDataMap[batchId].profit += orderProfit;
            batchDataMap[batchId].date = Math.max(batchDataMap[batchId].date, o.createdAt);
            totalRevenue += o.totalPrice;
            totalProfit += orderProfit;
        });

        const monthlyLabels = Object.keys(monthlyData).sort((a,b) => {
            const [mA, yA] = a.split('/').map(Number);
            const [mB, yB] = b.split('/').map(Number);
            return (yA - yB) || (mA - mB);
        });

        return {
            monthlyLabels,
            monthlyValues: monthlyLabels.map(k => monthlyData[k]),
            batchList: Object.values(batchDataMap).sort((a, b) => b.date - a.date),
            totalRevenue,
            totalProfit,
            margin: totalRevenue > 0 ? (totalProfit / totalRevenue) * 100 : 0
        };
    }, [orders]);

    const maxMonthly = Math.max(...stats.monthlyValues, 1);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] bg-slate-50 flex flex-col animate-fade-in overflow-hidden">
            {/* Header Vivid */}
            <div className="bg-white border-b-4 border-black px-8 py-6 flex justify-between items-center shadow-vivid-sm">
                <div>
                    <h2 className="text-2xl font-black text-black uppercase italic tracking-tighter">Báo cáo <span className="text-eco-600">Logistics</span></h2>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">Phân tích hiệu suất kinh doanh</p>
                </div>
                <button onClick={onClose} className="w-12 h-12 rounded-full bg-white border-2 border-black flex items-center justify-center shadow-vivid-sm active:translate-y-[2px] transition-all"><i className="fas fa-times text-black"></i></button>
            </div>

            <div className="flex-grow overflow-y-auto p-6 md:p-10 space-y-10">
                {loading ? (
                    <div className="flex flex-col items-center justify-center h-64"><div className="w-12 h-12 border-4 border-black border-t-eco-500 rounded-full animate-spin"></div></div>
                ) : (
                    <>
                        {/* Metrics Grid */}
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
                            {[
                                { label: 'Doanh Thu', val: stats.totalRevenue, color: 'text-blue-600', bg: 'bg-blue-50' },
                                { label: 'Lợi Nhuận', val: stats.totalProfit, color: 'text-eco-600', bg: 'bg-eco-50' },
                                { label: '% Biên Lãi', val: stats.margin.toFixed(1) + '%', color: 'text-purple-600', bg: 'bg-purple-50' },
                                { label: 'Tổng Lô', val: stats.batchList.length, color: 'text-black', bg: 'bg-gray-100' }
                            ].map((m, i) => (
                                <div key={i} className={`${m.bg} p-6 rounded-3xl border-2 border-black shadow-vivid`}>
                                    <div className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-2">{m.label}</div>
                                    <div className={`text-3xl font-black ${m.color} tracking-tighter italic`}>
                                        {typeof m.val === 'number' ? new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(m.val) : m.val}
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Chart Area */}
                        <div className="bg-white p-8 rounded-[2.5rem] border-4 border-black shadow-vivid">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-10 italic">Tăng trưởng theo tháng</h3>
                            <div className="flex items-end gap-3 h-64 w-full overflow-x-auto pb-4 no-scrollbar">
                                {stats.monthlyValues.map((val, idx) => (
                                    <div key={idx} className="flex flex-col items-center flex-1 min-w-[60px] group">
                                        <div className="relative w-full flex justify-center items-end h-full">
                                            <div className="w-full bg-black hover:bg-eco-500 transition-all rounded-xl relative border-2 border-black shadow-vivid-sm group-hover:scale-105" style={{ height: `${(val / maxMonthly) * 100}%` }}>
                                                <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-black text-white text-[9px] px-2 py-1 rounded-lg border border-white opacity-0 group-hover:opacity-100 transition-all whitespace-nowrap z-10 font-black">
                                                    {new Intl.NumberFormat('vi-VN').format(val)}đ
                                                </div>
                                            </div>
                                        </div>
                                        <div className="text-[9px] font-black text-black mt-4 uppercase tracking-tighter italic">{stats.monthlyLabels[idx]}</div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Detailed Table */}
                        <div className="bg-white rounded-[2.5rem] border-4 border-black shadow-vivid overflow-hidden">
                            <div className="p-6 border-b-2 border-black bg-gray-50"><h3 className="font-black text-black uppercase italic text-sm tracking-tighter">Hiệu quả từng lô hàng</h3></div>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left">
                                    <thead className="bg-black text-white text-[10px] font-black uppercase tracking-widest italic">
                                        <tr>
                                            <th className="p-5">Tên Lô</th>
                                            <th className="p-5 text-center">Đã bán</th>
                                            <th className="p-5 text-right">Doanh thu</th>
                                            <th className="p-5 text-right">Lợi nhuận</th>
                                            <th className="p-5 text-right">% Lãi</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y-2 divide-black/5">
                                        {stats.batchList.map(batch => (
                                            <tr key={batch.id} className="hover:bg-eco-50 transition-colors">
                                                <td className="p-5 font-black text-black uppercase italic tracking-tighter text-sm">{batch.id}</td>
                                                <td className="p-5 text-center font-black text-gray-500 text-xs">{batch.orderCount} đơn</td>
                                                <td className="p-5 text-right font-black text-blue-600 text-sm">{new Intl.NumberFormat('vi-VN').format(batch.revenue)}đ</td>
                                                <td className="p-5 text-right font-black text-eco-700 text-sm">{new Intl.NumberFormat('vi-VN').format(batch.profit)}đ</td>
                                                <td className="p-5 text-right">
                                                    <span className="font-black text-xs text-purple-600 italic">{(batch.revenue > 0 ? (batch.profit / batch.revenue) * 100 : 0).toFixed(1)}%</span>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

