              </div>
          </div>

          {showCompactPaymentChoice && (<div className="fixed inset-0 z-[99999] bg-gray-900/50 backdrop-blur-sm flex items-center justify-center p-4" onClick={(e) => { e.stopPropagation(); setShowCompactPaymentChoice(false); }}><div className="bg-white w-full max-w-xs rounded-xl shadow-2xl p-4" onClick={e => e.stopPropagation()}><h3 className="text-center font-bold text-gray-800 mb-3 text-sm uppercase">Hoàn tất đơn hàng</h3><div className="grid grid-cols-2 gap-3"><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.CASH); }} className="p-3 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 rounded-lg text-center"><span className="block text-xl">💵</span><span className="text-xs font-bold text-emerald-700">TIỀN MẶT</span></button><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.TRANSFER); }} className="p-3 bg-blue-50 hover:bg-blue-100 border border-blue-200 rounded-lg text-center"><span className="block text-xl">💳</span><span className="text-xs font-bold text-blue-700">CHUYỂN KHOẢN</span></button></div></div></div>)}
          </>
      );
  }

  // DEFAULT VIEW (CARD STYLE) - REFACTORED
  return (
    <div 
        className={`bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition-all h-full flex flex-col relative select-none group ${isSelected ? 'ring-2 ring-eco-500 bg-eco-50' : ''}`}
        onClick={handleCardClick}
        onTouchStart={handleTouchStartSelection}
        onTouchMove={handleTouchMoveSelection}
        onTouchEnd={handleTouchEndSelection}
    >
      <CheckboxOverlay />
      <DragHandle />

      {/* BLOCK 1: CUSTOMER INFO */}
      <div className="p-3 pb-2 flex justify-between items-start">
        <div className="flex-grow min-w-0 pr-2">
            {/* Row 1: Checkbox + Name + Badge */}
            <div className="flex items-center gap-2">
                <SelectTrigger />
                <h3 className="font-bold text-gray-800 text-sm truncate leading-tight" title={order.customerName}>
                    {order.customerName}
                </h3>
                <CustomerBadge customer={customerData} isNew={isNewCustomer} />
            </div>

            {/* Row 2: Address + Phone (Combined Line) */}
            <div className="mt-1 pl-7 text-xs text-gray-600">
                <div className="flex flex-wrap items-center gap-x-3 gap-y-1">
                    <div className="flex items-center gap-1.5 font-medium shrink-1 min-w-0">
                        <i className="fas fa-map-marker-alt text-gray-400 shrink-0" style={{ fontSize: '10px' }}></i>
                        <span className="leading-snug truncate max-w-[180px] sm:max-w-xs" title={order.address}>{order.address}</span>
                    </div>

                    {order.customerPhone && (
                        <a 
                            href={`tel:${order.customerPhone}`}
                            onClick={(e) => e.stopPropagation()}
                            className="flex items-center gap-1 font-mono text-gray-500 hover:text-blue-600 bg-gray-50 px-1.5 rounded border border-gray-100 hover:border-blue-200 transition-colors"
                        >
                            <i className="fas fa-phone-alt text-[9px]"></i>
                            <span>{order.customerPhone}</span>
                        </a>
                    )}
                    {customerData?.socialLink && (
                        <button 
                            onClick={handleMessengerClick}
                            className="text-blue-500 hover:text-blue-700"
                            title="Mạng xã hội"
                        >
                            <i className="fab fa-facebook-messenger"></i>
                        </button>
                    )}
                </div>
            </div>
        </div>

        {/* Status Badge Top Right */}
        <div className="flex flex-col items-end gap-1 shrink-0">
            <div className="flex items-center gap-1">
                <HeaderPaymentBadge />

                {order.carrierData ? (
                    <CarrierInfoBadge />
                ) : (
                    <span className={`text-[9px] font-bold uppercase px-2 py-0.5 rounded border border-transparent ${config.bg} ${config.color}`}>
                        {config.label}
                    </span>
                )}
            </div>
            {isSortMode && index !== undefined && (
                <span className="text-[10px] font-mono text-gray-400 bg-gray-100 px-1 rounded">#{index + 1}</span>
            )}
        </div>
      </div>

      {/* BLOCK 2: ITEMS LIST */}
      <div className="px-3 py-1 flex-grow">
        <div className="bg-gray-50 rounded-lg p-2 border border-gray-100 space-y-1">
            {order.items.map((item, idx) => (
                <div key={idx} className="flex justify-between items-start text-xs text-gray-700">
                    <span className="font-medium truncate mr-2 leading-relaxed">{item.name}</span>
                    <span className="font-bold text-gray-900 whitespace-nowrap">x{item.quantity}</span>
                </div>
            ))}
        </div>
        {order.notes && (
            <div className="flex items-start gap-1.5 mt-1.5 ml-1">
                <i className="fas fa-sticky-note text-yellow-500 text-[10px] mt-0.5"></i>
                <p className="text-[10px] text-yellow-700 italic line-clamp-2 leading-tight">{order.notes}</p>
            </div>
        )}
      </div>

      {/* BLOCK 3: FINANCIALS */}
      <div className="px-3 py-2 mt-auto border-t border-gray-50">
          <div className="flex justify-between items-end">
              <span className="text-[10px] font-bold text-gray-400 uppercase mb-1">Tổng thu:</span>
              <div className="text-right">
                  <div className="font-black text-gray-900 text-lg leading-none">
                      {new Intl.NumberFormat('vi-VN').format(order.totalPrice)}<span className="text-xs text-gray-400 font-normal ml-0.5">đ</span>
                  </div>
                  {/* Hide duplicate payment badge if completed (already shown in header) */}
                  {!isCompleted && (
                      <div className="flex justify-end mt-1">
                          <PaymentBadge />
                      </div>
                  )}
              </div>
          </div>
      </div>

      {/* BLOCK 4: ACTIONS & FOOTER */}
      <div className="p-3 pt-0">
          {/* Action Buttons Grid - Added QR */}
          <div className="grid grid-cols-[1fr_1fr_1fr_2fr] gap-2 mb-2">
              <button 
                  onClick={handleMessengerClick}
                  className="flex items-center justify-center py-2 rounded-lg bg-blue-50 text-blue-600 hover:bg-blue-100 transition-colors"
                  title="Nhắn tin"
              >
                  <i className="fas fa-comment-dots"></i>
              </button>

              <button 
                  onClick={(e) => { e.stopPropagation(); handlePrint(); }} 
                  className="flex items-center justify-center py-2 rounded-lg bg-gray-100 text-gray-600 hover:bg-gray-200 transition-colors"
                  title="In phiếu"
              >
                  <i className="fas fa-print"></i>
              </button>

              {/* Carrier Button Logic */}
              {onShip && !order.carrierData && !isCompleted ? (
                  <button 
                      onClick={(e) => { e.stopPropagation(); onShip(order); }} 
                      className="flex items-center justify-center py-2 rounded-lg bg-orange-50 text-orange-600 hover:bg-orange-100 transition-colors"
                      title="Gửi vận chuyển"
                  >
                      <i className="fas fa-truck"></i>
                  </button>
              ) : (
                  <button 
                      onClick={(e) => { e.stopPropagation(); requestQR(e); }} 
                      className="flex items-center justify-center py-2 rounded-lg bg-gray-100 text-gray-600 hover:bg-blue-50 hover:text-blue-600 transition-colors"
                      title="Mã QR"
                  >
                      <i className="fas fa-qrcode"></i>
                  </button>
              )}

              <button 
                  onClick={nextStatus}
                  className={`flex items-center justify-center gap-2 py-2 rounded-lg font-bold text-xs text-white shadow-sm transition-all active:scale-95 ${order.status === OrderStatus.DELIVERED ? 'bg-green-500 hover:bg-green-600' : 'bg-gray-800 hover:bg-gray-900'}`}
              >
                  {order.status === OrderStatus.DELIVERED ? (
                      <>Hoàn tất <i className="fas fa-check"></i></>
                  ) : (
                      <>Tiếp theo <i className="fas fa-arrow-right"></i></>
                  )}
              </button>
          </div>

          {/* Footer Info & Secondary Actions */}
          <div className="flex justify-between items-center text-[10px] text-gray-400 pt-1 border-t border-gray-50">
               <div className="font-mono">{order.batchId || 'NO-BATCH'}</div>
               <div className="flex gap-3">
                   {order.status !== OrderStatus.DELIVERED && onSplitBatch && (
                       <button onClick={(e) => { e.stopPropagation(); onSplitBatch(order); }} className="hover:text-orange-500 font-bold transition-colors" title="Chuyển sang lô sau">
                           Hoãn
                       </button>
                   )}
                   {onMoveBatch && (
                       <button onClick={(e) => { e.stopPropagation(); onMoveBatch(order); }} className="hover:text-indigo-500 font-bold transition-colors" title="Chuyển lô">
                           Chuyển
                       </button>
                   )}
               </div>
          </div>
      </div>

      {showCompactPaymentChoice && (<div className="fixed inset-0 z-[99999] bg-gray-900/50 backdrop-blur-sm flex items-center justify-center p-4" onClick={(e) => { e.stopPropagation(); setShowCompactPaymentChoice(false); }}><div className="bg-white w-full max-w-xs rounded-xl shadow-2xl p-4" onClick={e => e.stopPropagation()}><h3 className="text-center font-bold text-gray-800 mb-3 text-sm uppercase">Hoàn tất đơn hàng</h3><div className="grid grid-cols-2 gap-3"><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.CASH); }} className="p-3 bg-emerald-50 hover:bg-emerald-100 border border-emerald-200 rounded-lg text-center"><span className="block text-xl">💵</span><span className="text-xs font-bold text-emerald-700">TIỀN MẶT</span></button><button onClick={(e) => { e.stopPropagation(); handleFinishOrder(PaymentMethod.TRANSFER); }} className="p-3 bg-blue-50 hover:bg-blue-100 border border-blue-200 rounded-lg text-center"><span className="block text-xl">💳</span><span className="text-xs font-bold text-blue-700">CHUYỂN KHOẢN</span></button></div></div></div>)}
    </div>
  );
}

export enum OrderStatus {
  PENDING = 'PENDING',       // Chờ xử lý
  PICKED_UP = 'PICKED_UP',   // Đã lấy hàng
  IN_TRANSIT = 'IN_TRANSIT', // Đang giao
  DELIVERED = 'DELIVERED',   // Đã giao
  CANCELLED = 'CANCELLED'    // Đã hủy
}

export enum PaymentMethod {
  CASH = 'CASH',       // Tiền mặt (COD)
  TRANSFER = 'TRANSFER', // Chuyển khoản
  PAID = 'PAID'        // Đã thanh toán trước
}

export interface CarrierData {
  carrierId: string; // 'GHTK' | 'GHN' | 'VTP' | 'AHA'
  carrierName: string;
  trackingCode: string;
  fee: number;
  weight: number;
  cod: number;
  createdAt: number;
}

export interface OrderItem {
  id: string;
  productId?: string; // Link to inventory
  name: string;
  quantity: number;
  price: number;
  importPrice?: number; // NEW: Cost price at the moment of sale
}

export interface Order {
  id: string;
  customerId?: string; // NEW: Link directly to customer ID for 100% accuracy
  batchId: string;
  customerName: string;
  customerPhone: string;
  address: string;
  items: OrderItem[]; 
  notes: string;
  totalPrice: number; 
  paymentMethod: PaymentMethod;
  paymentVerified?: boolean; // New: Check if transfer received
  status: OrderStatus;
  createdAt: number;
  updatedAt: number;
  orderIndex: number; 
  deliveryProof?: string;
  lastUpdatedBy?: string; // Tên người xử lý trạng thái cuối cùng
  reminderCount?: number; // NEW: Number of times payment reminder sent
  carrierData?: CarrierData; // NEW: Shipment info
}

export interface ImportRecord {
  id: string;
  date: number;
  quantity: number;
  price: number; // Import price at time of entry
  note?: string;
}

export interface Product {
  id: string;
  name: string;
  defaultPrice: number; // Selling Price
  importPrice?: number; // NEW: Cost Price (Optional)
  defaultWeight: number; // kg per unit
  stockQuantity: number; // Current Stock
  totalImported?: number; // Total Imported History
  lastImportDate: number; 
  importHistory?: ImportRecord[]; // NEW: Track distinct import batches
  updatedAt?: number; // NEW: Timestamp for Delta Sync optimization
}

export interface Customer {
  id: string;
  name: string;
  phone: string;
  address: string;
  lastOrderDate: number;
  priorityScore?: number; // 1 is highest priority, 999 is normal
  totalOrders?: number;
  updatedAt?: number; // Timestamp for Delta Sync
  isLegacy?: boolean; // NEW: Manually marked as "Old Customer" regardless of order count
  socialLink?: string; // NEW: Link to Facebook/Zalo/Messenger conversation
}

export interface SmartParseResult {
  customerName: string;
  customerPhone: string;
  address: string;
  itemsString?: string; 
  parsedItems?: { productName: string, quantity: number }[]; // Structured items
  price?: number;
  notes?: string;
  paymentMethod?: PaymentMethod;
}

export interface BankConfig {
  bankId: string;       // Mã ngân hàng (VD: MB, VCB)
  accountNo: string;    // Số tài khoản
  accountName: string;  // Tên chủ tài khoản
  template: string;     // compact2 (mặc định)
  sepayApiToken?: string; // Token SePay để check biến động
}

export interface ShopConfig {
  shopName: string;
  hotline: string;
  address: string; // NEW: Pickup address for API carriers
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
  isRead: boolean;
  createdAt: number;
  relatedOrderId?: string;
}

// Interface for PDF Import Module
export interface RawPDFImportData {
  unit_price: number;      // e.g. 120 (means 120,000)
  customer_name: string;
  address: string;
  phone?: string;
  items_raw: string;       // e.g. "đỏ2 xanh1"
}

import React, { useState, useEffect } from 'react';
import { BankConfig, ShopConfig } from '../types';
import { storageService } from '../services/storageService';
import { dataImportService } from '../services/dataImportService';
import toast from 'react-hot-toast';

interface Props {
  isOpen: boolean;
  onClose: () => void;
}

const BANKS = [
    { id: 'MB', name: 'MB Bank (Quân Đội)' },
    { id: 'VCB', name: 'Vietcombank' },
    { id: 'TCB', name: 'Techcombank' },
    { id: 'ACB', name: 'ACB (Á Châu)' },
    { id: 'VPB', name: 'VPBank' },
    { id: 'TPB', name: 'TPBank' },
    { id: 'VIB', name: 'VIB' },
    { id: 'BIDV', name: 'BIDV' },
    { id: 'CTG', name: 'VietinBank' },
    { id: 'STB', name: 'Sacombank' },
    { id: 'MSB', name: 'MSB (Hàng Hải)' },
];

const SettingsModal: React.FC<Props> = ({ isOpen, onClose }) => {
  const [config, setConfig] = useState<BankConfig>({
      bankId: 'MB',
      accountNo: '',
      accountName: '',
      template: 'compact2'
  });
  const [shopConfig, setShopConfig] = useState<ShopConfig>({
      shopName: 'ECOGO LOGISTICS',
      hotline: '',
      address: ''
  });
  const [testResult, setTestResult] = useState<string>('');
  const [isRunningTest, setIsRunningTest] = useState(false);

  const [quickTags, setQuickTags] = useState<string[]>([]);
  const [newTag, setNewTag] = useState('');
  const [logo, setLogo] = useState<string | null>(null);
  const [showPdfImport, setShowPdfImport] = useState(false);
  const [pdfJsonData, setPdfJsonData] = useState('');
  const [importBatchName, setImportBatchName] = useState('');

  useEffect(() => {
      if (isOpen) {
          const load = async () => {
              const saved = await storageService.getBankConfig();
              if (saved) setConfig(saved);

              const savedShop = await storageService.getShopConfig();
              if (savedShop) setShopConfig({ ...savedShop, address: savedShop.address || '' });

              const tags = storageService.getQuickTags();
              setQuickTags(tags);

              const savedLogo = storageService.getLogo();
              setLogo(savedLogo);

              storageService.fetchQuickTagsFromCloud().then(t => setQuickTags(t));

              const today = new Date().toISOString().slice(0, 10);
              setImportBatchName(`PDF-${today}`);
          };
          load();
      }
  }, [isOpen]);

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      await storageService.saveBankConfig(config);
      await storageService.saveShopConfig(shopConfig);
      await storageService.saveQuickTags(quickTags);
      toast.success("Đã lưu tất cả cài đặt!");
      onClose();
  };

  const addTag = (e: React.FormEvent) => {
      e.preventDefault();
      const tag = newTag.trim();
      if (tag && !quickTags.includes(tag)) {
          setQuickTags([...quickTags, tag]);
          setNewTag('');
      } else if (quickTags.includes(tag)) {
          toast.error("Thẻ này đã tồn tại");
      }
  };

  const removeTag = (tagToRemove: string) => {
      setQuickTags(quickTags.filter(t => t !== tagToRemove));
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          if (file.size > 1024 * 1024) { toast.error("Ảnh quá lớn! Vui lòng chọn ảnh < 1MB"); return; }
          const reader = new FileReader();
          reader.onloadend = () => {
              const base64 = reader.result as string;
              storageService.saveLogo(base64);
              setLogo(base64);
              toast.success("Đã cập nhật Logo");
          };
          reader.readAsDataURL(file);
      }
  };

  const handleRemoveLogo = () => {
      storageService.removeLogo();
      setLogo(null);
      toast.success("Đã xóa Logo");
  };

  const runStressTest = async () => {
      setIsRunningTest(true);
      setTestResult('Đang tạo 10,000 khách hàng...');
      setTimeout(async () => {
          try {
              const result = await storageService.generatePerformanceData(10000);
              setTestResult(`Hoàn tất! Tạo ${result.count} khách trong ${result.duration}ms.`);
              toast.success(`Stress test OK: ${result.duration}ms`);
          } catch (e: any) { setTestResult('Lỗi: ' + (e?.message || e)); } finally { setIsRunningTest(false); }
      }, 100);
  };

  const handleMarkOld = async () => {
      if (window.confirm("Đánh dấu tất cả là Khách Cũ?")) {
          setIsRunningTest(true);
          try {
              const count = await storageService.markAllCustomersAsOld();
              setTestResult(`Đã cập nhật xong ${count} khách hàng.`);
              toast.success(`Xong! ${count} khách hàng đã thành Khách Cũ.`);
          } catch (e: any) { setTestResult('Lỗi: ' + (e?.message || e)); } finally { setIsRunningTest(false); }
      }
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      setIsRunningTest(true);
      const loading = toast.loading("AI đang đọc PDF...");
      try {
          const parsedData = await dataImportService.parsePdfFile(file);
          setPdfJsonData(JSON.stringify(parsedData, null, 2));
          toast.success(`Đã đọc được ${parsedData.length} dòng!`);
      } catch (error: any) { toast.error("Lỗi đọc PDF"); } finally { toast.dismiss(loading); setIsRunningTest(false); e.target.value = ''; }
  };

  const handlePdfImport = async () => {
      if (!pdfJsonData.trim() || !importBatchName.trim()) { toast.error("Thiếu thông tin"); return; }
      setIsRunningTest(true);
      try {
          const rawData = JSON.parse(pdfJsonData);
          const msg = await dataImportService.processImportData(rawData, importBatchName);
          setTestResult(msg);
          toast.success("Import thành công!");
          setPdfJsonData('');
      } catch (e: any) { toast.error("Lỗi Import"); } finally { setIsRunningTest(false); }
  };

  if (!isOpen) return null;

  const vInputClass = "w-full p-2.5 bg-white border-2 border-gray-800 rounded-xl outline-none focus:ring-4 focus:ring-eco-50 font-black text-black placeholder-gray-300 transition-all";

  return (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-sm animate-fade-in">
      <div className="bg-white rounded-2xl shadow-2xl max-w-md w-full overflow-hidden flex flex-col max-h-[90vh]">
        <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
            <h3 className="text-lg font-black text-gray-800 uppercase tracking-tighter">Cài đặt hệ thống</h3>
            <button onClick={onClose} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center border border-gray-100"><i className="fas fa-times"></i></button>
        </div>

        <div className="overflow-y-auto p-6 space-y-8">
            <form onSubmit={handleSave} className="space-y-6">

                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-eco-600 uppercase tracking-widest flex items-center gap-2">
                        <i className="fas fa-store"></i> Thông tin Shop
                    </h4>
                    <div className="space-y-3">
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Tên Cửa hàng / Đầu phiếu</label>
                            <input value={shopConfig.shopName} onChange={e => setShopConfig({...shopConfig, shopName: e.target.value})} className={vInputClass} placeholder="ECOGO LOGISTICS" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Hotline lấy hàng</label>
                            <input value={shopConfig.hotline} onChange={e => setShopConfig({...shopConfig, hotline: e.target.value})} className={vInputClass} placeholder="09xxxxxx" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Địa chỉ lấy hàng (Quan trọng cho Ahamove)</label>
                            <textarea value={shopConfig.address} onChange={e => setShopConfig({...shopConfig, address: e.target.value})} className={`${vInputClass} text-xs font-bold h-20 resize-none`} placeholder="Nhập địa chỉ chính xác để tài xế qua lấy..." />
                        </div>
                        <div className="flex items-center gap-4 p-3 bg-gray-50 rounded-xl border border-dashed border-gray-300">
                            <div className="w-12 h-12 bg-white rounded-lg flex items-center justify-center border-2 border-gray-800 overflow-hidden shrink-0">
                                {logo ? <img src={logo} alt="Logo" className="w-full h-full object-contain" /> : <i className="fas fa-image text-gray-300"></i>}
                            </div>
                            <div className="flex-grow">
                                <label className="block text-[10px] font-black text-blue-600 cursor-pointer hover:underline uppercase">
                                    <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                                    <i className="fas fa-upload mr-1"></i> Tải ảnh Logo
                                </label>
                                {logo && <button type="button" onClick={handleRemoveLogo} className="text-[10px] font-black text-red-500 hover:text-red-600 uppercase mt-1"><i className="fas fa-trash mr-1"></i> Xóa Logo</button>}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-2">
                        <i className="fas fa-university"></i> Tài khoản nhận tiền
                    </h4>
                    <div className="space-y-3">
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Chọn Ngân hàng</label>
                            <select value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} className={`${vInputClass} appearance-none`}>
                                {BANKS.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1 ml-1">Số tài khoản (STK)</label>
