        let cleanPickupPhone = (shopConfig?.hotline || "84346722755").replace(/\D/g, '');

        let finalAddress = order.address.trim();
        if (finalAddress.length < 20) finalAddress = `${finalAddress}, Thành phố Hồ Chí Minh`;

        const payload = {
            order_time: 0, 
            service_id: "SGN-BIKE",
            path: [
                { address: pickupAddr, name: pickupName, mobile: cleanPickupPhone, remarks: "Lấy hàng" },
                { address: finalAddress, name: order.customerName, mobile: order.customerPhone.replace(/\D/g, ''), cod: Math.round(cod), item_value: Math.max(Math.round(cod), 500000) }
            ],
            items: order.items.map(i => ({ name: i.name, num: Math.round(i.quantity), price: Math.round(i.price) })),
            payment_method: "CASH", 
            remarks: `Order #${order.id}`,
            package_detail: [{ weight: weight / 1000 }]
        };

        const targetUrl = buildTarget();
        const bodyStr = JSON.stringify(payload);
        let lastError = "";

        // THỬ LẦN LƯỢT CÁC PROXY VỚI CHIẾN THUẬT GIẢM THIỂU HEADERS
        for (const proxyBase of PROXY_LIST) {
            try {
                const proxiedUrl = `${proxyBase}${encodeURIComponent(targetUrl)}`;

                /**
                 * ĐÂY LÀ PHẦN QUAN TRỌNG NHẤT:
                 * Sử dụng 'application/x-www-form-urlencoded' để biến nó thành một "Simple Request".
                 * Các trình duyệt như Brave/Chrome sẽ KHÔNG gửi OPTIONS request, giúp vượt qua 90% lỗi Fetch.
                 */
                const response = await fetch(proxiedUrl, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/x-www-form-urlencoded', // Lừa trình duyệt bỏ qua Preflight
                    },
                    body: bodyStr, // Gửi JSON thô trong Content-Type Form
                    mode: 'cors',
                    cache: 'no-store'
                });

                const text = await response.text();

                if (!response.ok) {
                    lastError = `Proxy trả về lỗi ${response.status}`;
                    continue;
                }

                const result = JSON.parse(text);
                const orderId = result.order_id || result.order?.order_id;

                if (orderId) {
                    return {
                        carrierId: 'AHA', carrierName: 'AhaMove',
                        trackingCode: orderId,
                        fee: result.total_fee || result.order?.total_fee || 35000,
                        weight, cod, createdAt: Date.now()
                    };
                } else {
                    lastError = result.description || "Lỗi dữ liệu API";
                }
            } catch (err: any) {
                console.warn(`Thất bại tại ${proxyBase}:`, err.message);
                lastError = err.message;
                // Nếu lỗi là 'Failed to fetch', có nghĩa là trình duyệt chặn ngay tại cổng.
                // Chúng ta tiếp tục thử proxy tiếp theo.
            }
        }

        // HƯỚNG DẪN CHI TIẾT KHI TẤT CẢ THẤT BẠI
        if (lastError.toLowerCase().includes("failed to fetch")) {
            throw new Error(
                "TRÌNH DUYỆT ĐANG CHẶN KẾT NỐI (Failed to fetch).\n\n" +
                "Cách xử lý dứt điểm:\n" +
                "1. Tắt 'Brave Shield' (Nếu dùng Brave) hoặc AdBlock/uBlock.\n" +
                "2. Kiểm tra xem mạng công ty/wifi có chặn Ahamove không.\n" +
                "3. Hãy thử tải lại trang hoặc dùng trình duyệt Ẩn danh."
            );
        }

        throw new Error(`AhaMove: ${lastError}`);
    },

    printWaybill: (order: Order) => {
        if (!order.carrierData) return;
        const { carrierData } = order;
        const w = window.open('', '_blank', 'width=400,height=600');
        if (!w) return;
        w.document.write(`<html><body style="font-family:sans-serif;padding:20px;border:2px dashed #000;text-align:center;"><h2>AhaMove</h2><h3>${carrierData.trackingCode}</h3><p>Người nhận: ${order.customerName}</p><p>SĐT: ${order.customerPhone}</p><p>Địa chỉ: ${order.address}</p><h3>COD: ${new Intl.NumberFormat('vi-VN').format(carrierData.cod)}đ</h3><script>window.print();</script></body></html>`);
        w.document.close();
    }
};

