interface CustomerDebtGroup {
    key: string;
    customerId: string;
    customerName: string;
    customerPhone: string;
    orders: Order[];
    totalAmount: number;
    maxReminders: number;
    oldestOrderDate: number;
    daysOld: number;
}

const dataURLtoFile = (dataurl: string, filename: string) => {
    const arr = dataurl.split(',');
    const mime = arr[0].match(/:(.*?);/)?.[1];
    const bstr = atob(arr[1]);
    let n = bstr.length;
    const u8arr = new Uint8Array(n);
    while (n--) u8arr[n] = bstr.charCodeAt(n);
    return new File([u8arr], filename, { type: mime });
};

const PaymentAudit: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [bankConfig, setBankConfig] = useState<any>(null);
  const [shopConfig, setShopConfig] = useState<ShopConfig | null>(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedBatch, setSelectedBatch] = useState('ALL');
  const [minDebt, setMinDebt] = useState<number>(0);

  const [selectedGroup, setSelectedGroup] = useState<CustomerDebtGroup | null>(null);
  const [showPasteModal, setShowPasteModal] = useState(false);
  const [pasteText, setPasteText] = useState('');

  const [confirmData, setConfirmData] = useState<{isOpen: boolean, ids: string[], message: string}>({
      isOpen: false, ids: [], message: ''
  });

  const [isSharing, setIsSharing] = useState(false);
  const groupQrImgRef = useRef<HTMLImageElement | null>(null);

  useEffect(() => {
    const unsub = storageService.subscribeOrders((allOrders) => {
      const filtered = (allOrders || [])
        .filter(o => o.paymentMethod === PaymentMethod.TRANSFER && !o.paymentVerified && o.status !== OrderStatus.CANCELLED)
        .sort((a, b) => b.createdAt - a.createdAt);
      setOrders(filtered);
    });
    storageService.getBankConfig().then(setBankConfig);
    storageService.getShopConfig().then(setShopConfig);
    return () => { if (unsub) unsub(); };
  }, []);

  useEffect(() => {
      if (selectedGroup && bankConfig?.accountNo) {
          const idsStr = selectedGroup.orders.map(o => o.id).join(' ');
          const qrUrl = `https://img.vietqr.io/image/${bankConfig.bankId}-${bankConfig.accountNo}-${bankConfig.template || 'compact2'}.png?amount=${selectedGroup.totalAmount}&addInfo=${encodeURIComponent(`DH ${idsStr}`)}&accountName=${encodeURIComponent(bankConfig.accountName)}`;
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = qrUrl;
          img.onload = () => { groupQrImgRef.current = img; };
      }
  }, [selectedGroup, bankConfig]);

  const batches = useMemo(() => {
    const batchSet = new Set<string>();
    orders.forEach(o => { if (o.batchId) batchSet.add(o.batchId); });
    return Array.from(batchSet).sort();
  }, [orders]);

  const customerGroups = useMemo(() => {
      const groups: Record<string, CustomerDebtGroup> = {};
      const now = Date.now();

      orders.forEach(o => {
          const matchSearch = searchTerm === '' || o.customerName.toLowerCase().includes(searchTerm.toLowerCase()) || o.customerPhone.includes(searchTerm) || o.id.includes(searchTerm.toUpperCase());
          const matchBatch = selectedBatch === 'ALL' || o.batchId === selectedBatch;
          if (!matchSearch || !matchBatch) return;

          let key = o.customerId ? `${o.customerId}` : normalizePhone(o.customerPhone) || `${normalizeString(o.customerName)}|${normalizeString(o.address)}`;

          if (!groups[key]) {
              groups[key] = {
                  key,
                  customerId: o.customerId || '',
                  customerName: o.customerName,
                  customerPhone: o.customerPhone,
                  orders: [],
                  totalAmount: 0,
                  maxReminders: 0,
                  oldestOrderDate: o.createdAt,
                  daysOld: 0
              };
          }
          groups[key].orders.push(o);
          groups[key].totalAmount += o.totalPrice;
          groups[key].maxReminders = Math.max(groups[key].maxReminders, o.reminderCount || 0);
          groups[key].oldestOrderDate = Math.min(groups[key].oldestOrderDate, o.createdAt);
          groups[key].daysOld = differenceInDays(now, groups[key].oldestOrderDate);
      });

      return Object.values(groups)
        .filter(g => g.totalAmount >= minDebt)
        .sort((a, b) => b.daysOld - a.daysOld);
  }, [orders, searchTerm, selectedBatch, minDebt]);

  const handleQuickPasteRec = () => {
      if (!pasteText.trim()) return;
      const result = reconciliationService.reconcileFromText(pasteText, orders);
      if (result.matchedOrders.length > 0) {
          const ids = result.matchedOrders.map(o => o.id);
          setConfirmData({
              isOpen: true,
              ids,
              message: `AI đã tìm thấy ${ids.length} đơn hàng khớp trong đoạn văn bản. Xác nhận tiền về cho các đơn này?`
          });
          setShowPasteModal(false);
          setPasteText('');
      } else {
          toast.error("Không tìm thấy mã đơn hàng nào trong nội dung này.");
      }
  };

  const executeConfirm = async () => {
    const promises = confirmData.ids.map(id => storageService.updatePaymentVerification(id, true));
    await Promise.all(promises);
    toast.success(`Đã xử lý xong ${confirmData.ids.length} đơn!`);
    setConfirmData({ isOpen: false, ids: [], message: '' });
    setSelectedGroup(null);
  };

  const handleShareGroupQR = async (group: CustomerDebtGroup) => {
    if (!bankConfig?.accountNo) { toast.error("Thiếu thông tin Ngân hàng"); return; }
    setIsSharing(true);
    const toastId = toast.loading("Đang tạo phiếu nợ...");
    try {
        const qrImg = groupQrImgRef.current;
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx || !qrImg) throw new Error("QR Error");

        const W = 800;
        const qrSize = 500;
        const itemsList = Array.from(new Set(group.orders.flatMap(o => o.items.map(i => i.name))));
        let H = 600 + (itemsList.length * 40);
        canvas.width = W; canvas.height = H;

        ctx.fillStyle = '#ffffff'; ctx.fillRect(0, 0, W, H);
        ctx.fillStyle = '#1e3a8a'; ctx.fillRect(0, 0, W, 120);
        ctx.fillStyle = '#ffffff'; ctx.font = 'bold 36px Arial'; ctx.textAlign = 'center';
        ctx.fillText('PHIẾU THANH TOÁN CÔNG NỢ', W/2, 70);

        ctx.fillStyle = '#1e40af'; ctx.font = 'bold 60px Arial';
