                  <div className="p-4 bg-white border-t-2 border-gray-100 flex gap-2">
                      <button onClick={() => setConfirmData({isOpen: true, ids: selectedGroup.orders.map(o => o.id), message: `Xác nhận đã nhận đủ ${new Intl.NumberFormat('vi-VN').format(selectedGroup.totalAmount)}đ cho toàn bộ ${selectedGroup.orders.length} đơn?`})} className="flex-[2] py-4 bg-black text-white rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 transition-all">Xác nhận đã trả nợ <i className="fas fa-check-double ml-1"></i></button>
