import React, { useEffect, useState, useMemo } from 'react';
import { NavLink } from 'react-router-dom';
import { Order, Product, OrderStatus, PaymentMethod } from '../types';
import { storageService } from '../services/storageService';
import RevenueReport from './RevenueReport';
import toast from 'react-hot-toast';

const DashboardHome: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [showReport, setShowReport] = useState(false);
  const currentUser = storageService.getCurrentUser() || 'Admin';

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);
    return () => {
      if (unsubOrders) unsubOrders();
      if (unsubProducts) unsubProducts();
    };
  }, []);

  const stats = useMemo(() => {
    const now = Date.now();
    const todayStart = new Date().setHours(0,0,0,0);

    const todaysOrders = orders.filter(o => o.createdAt >= todayStart);
    const pendingOrders = orders.filter(o => o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP);

    // Đơn chuyển khoản nhưng chưa xác nhận tiền về
    const unverifiedTransfers = orders.filter(o => 
        o.paymentMethod === PaymentMethod.TRANSFER && 
        !o.paymentVerified && 
        o.status !== OrderStatus.CANCELLED
    );

    const todayRevenue = todaysOrders
        .filter(o => o.status !== OrderStatus.CANCELLED)
        .reduce((sum, o) => sum + o.totalPrice, 0);

    const lowStockCount = products.filter(p => p.stockQuantity < 5).length;

    return {
      todayCount: todaysOrders.length,
      todayRevenue,
      pendingCount: pendingOrders.length,
      lowStockCount,
      unverifiedTransfers,
      unverifiedAmount: unverifiedTransfers.reduce((sum, o) => sum + o.totalPrice, 0)
    };
  }, [orders, products]);

  const handleQuickVerify = async (id: string) => {
      await storageService.updatePaymentVerification(id, true);
      toast.success("Đã xác nhận tiền về!");
  };

  const StatCard = ({ title, value, subValue, icon, color, to }: any) => (
    <NavLink to={to} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-all group">
      <div className="flex justify-between items-start mb-2">
        <div className={`w-10 h-10 rounded-full flex items-center justify-center ${color} text-white text-lg shadow-md group-hover:scale-110 transition-transform`}>
          <i className={`fas ${icon}`}></i>
        </div>
        {subValue && <span className="text-xs font-bold text-gray-400 bg-gray-50 px-2 py-1 rounded-full">{subValue}</span>}
      </div>
      <div className="text-2xl font-black text-gray-800 mt-2">{value}</div>
      <div className="text-sm font-medium text-gray-500">{title}</div>
    </NavLink>
  );

  return (
    <div className="max-w-6xl mx-auto pb-10 animate-fade-in px-2">
      {/* Header */}
      <div className="mb-6 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
            <h1 className="text-2xl font-black text-gray-800 tracking-tight">Xin chào, {currentUser}! 👋</h1>
            <p className="text-gray-500 text-sm">Hôm nay có gì mới không?</p>
        </div>
        <button 
            onClick={() => setShowReport(true)}
            className="bg-white border border-gray-200 text-gray-700 hover:text-blue-600 px-4 py-2 rounded-xl font-bold text-sm shadow-sm flex items-center gap-2"
        >
            <i className="fas fa-chart-pie"></i> Báo Cáo
        </button>
      </div>

      {/* EMERGENCY WIDGET: CHƯA XÁC NHẬN TIỀN */}
      {stats.unverifiedTransfers.length > 0 && (
          <div className="mb-8 bg-gradient-to-r from-red-600 to-orange-600 rounded-[2rem] p-6 text-white shadow-xl shadow-red-100 relative overflow-hidden">
              <div className="absolute right-[-20px] top-[-20px] opacity-10 text-9xl rotate-12">
                  <i className="fas fa-hand-holding-usd"></i>
              </div>
              <div className="relative z-10">
                  <div className="flex items-center gap-2 mb-4">
                      <span className="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Cần xác nhận ngay</span>
                      <span className="animate-pulse w-2 h-2 bg-white rounded-full"></span>
                  </div>
                  <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                      <div>
                          <div className="text-4xl font-black tracking-tighter leading-none mb-2">
                              {new Intl.NumberFormat('vi-VN').format(stats.unverifiedAmount)}đ
                          </div>
                          <p className="text-red-100 font-bold text-sm">Bạn có {stats.unverifiedTransfers.length} đơn chuyển khoản chưa xác nhận tiền đã vào túi.</p>
                      </div>
                      <NavLink to="/audit" className="bg-white text-red-600 px-6 py-3 rounded-2xl font-black text-xs uppercase shadow-lg hover:bg-red-50 transition-all flex items-center gap-2">
                          Đi đối soát ngay <i className="fas fa-chevron-right"></i>
                      </NavLink>
                  </div>

                  {/* Danh sách xử lý nhanh */}
                  <div className="mt-6 grid grid-cols-1 sm:grid-cols-2 gap-3">
                      {stats.unverifiedTransfers.slice(0, 2).map(o => (
                          <div key={o.id} className="bg-black/20 backdrop-blur-md rounded-2xl p-3 flex justify-between items-center border border-white/10 group">
                              <div className="min-w-0">
                                  <div className="font-black text-xs truncate uppercase">{o.customerName}</div>
                                  <div className="text-[10px] text-red-100 font-bold">#{o.id} • {new Intl.NumberFormat('vi-VN').format(o.totalPrice)}đ</div>
                              </div>
                              <button 
                                onClick={() => handleQuickVerify(o.id)}
                                className="bg-white text-red-600 w-8 h-8 rounded-full flex items-center justify-center shadow-md active:scale-90 transition-all"
                              >
                                  <i className="fas fa-check text-xs"></i>
                              </button>
                          </div>
                      ))}
                  </div>
              </div>
          </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <StatCard title="Đơn hôm nay" value={stats.todayCount} icon="fa-calendar-day" color="bg-blue-500" to="/tracking" />
        <StatCard title="Doanh thu" value={new Intl.NumberFormat('vi-VN', { notation: "compact" }).format(stats.todayRevenue)} icon="fa-coins" color="bg-green-500" to="/tracking" />
        <StatCard title="Cần đóng gói" value={stats.pendingCount} icon="fa-box" color="bg-yellow-500" to="/tracking" />
        <StatCard title="Sắp hết hàng" value={stats.lowStockCount} icon="fa-exclamation-triangle" color="bg-orange-500" to="/inventory" />
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-gray-900 rounded-[2rem] p-8 text-white shadow-xl flex flex-col justify-between items-start relative overflow-hidden group">
           <div className="absolute right-[-20px] top-[-20px] text-gray-700 opacity-20 text-9xl group-hover:scale-110 transition-transform rotate-12">
              <i className="fas fa-plus-circle"></i>
           </div>
           <div className="relative z-10">
             <h3 className="text-2xl font-black mb-2 tracking-tight">TẠO ĐƠN MỚI</h3>
             <p className="text-gray-400 text-sm mb-6 max-w-xs font-medium">Lên đơn nhanh chóng bằng AI, tự động trừ kho và tính doanh thu.</p>
           </div>
           <NavLink to="/order" className="relative z-10 bg-eco-500 text-white px-8 py-3 rounded-2xl font-black text-sm hover:bg-eco-600 transition-all shadow-lg uppercase tracking-widest">
              Bắt đầu <i className="fas fa-arrow-right ml-2"></i>
           </NavLink>
        </div>

        <div className="bg-white rounded-[2rem] p-8 border-2 border-gray-100 shadow-sm flex flex-col">
            <h3 className="text-xl font-black text-gray-800 mb-4 flex items-center gap-2 uppercase tracking-tight">
               <i className="fas fa-shipping-fast text-blue-600"></i> Quản lý kho
            </h3>
            <div className="flex-1 bg-blue-50/50 rounded-2xl p-4 border border-blue-100 flex items-center justify-between">
                <div>
                    <div className="text-xs font-black text-blue-400 uppercase mb-1">Tổng sản phẩm</div>
                    <div className="text-3xl font-black text-blue-600 tracking-tighter">{products.length}</div>
                </div>
                <NavLink to="/inventory" className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-blue-600 shadow-sm hover:shadow-md transition-all">
                    <i className="fas fa-arrow-right"></i>
                </NavLink>
            </div>
        </div>
      </div>

      <RevenueReport isOpen={showReport} onClose={() => setShowReport(false)} />
    </div>
  );
};

export default DashboardHome;

import React, { useState, useEffect, useRef } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { storageService } from '../services/storageService';
import toast from 'react-hot-toast';
import { db } from '../firebaseConfig';
import ConfirmModal from './ConfirmModal';
import SettingsModal from './SettingsModal';
import NotificationMenu from './NotificationMenu';
import { Order, OrderStatus, PaymentMethod } from '../types';

declare const __APP_VERSION__: string;

interface Props {
  onLogout: () => void;
}

const Navbar: React.FC<Props> = ({ onLogout }) => {
  const [isSyncing, setIsSyncing] = useState(false);
  const [showConfirmSync, setShowConfirmSync] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showNotif, setShowNotif] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [logo, setLogo] = useState<string | null>(null);
  const [unreadCount, setUnreadCount] = useState(0);
  const [unverifiedCount, setUnverifiedCount] = useState(0);

  const mobileMenuRef = useRef<HTMLDivElement>(null);
  const notifBtnRef = useRef<HTMLButtonElement>(null); 
  const location = useLocation();
  const isOnline = !!db;

  const appVersion = typeof __APP_VERSION__ !== 'undefined' ? __APP_VERSION__ : '1.2.2';

  useEffect(() => {
    // Theo dõi đơn chưa xác nhận tiền
    const unsubOrders = storageService.subscribeOrders((orders) => {
        const count = orders.filter(o => 
            o.paymentMethod === PaymentMethod.TRANSFER && 
            !o.paymentVerified && 
            o.status !== OrderStatus.CANCELLED
        ).length;
        setUnverifiedCount(count);
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (mobileMenuRef.current && !mobileMenuRef.current.contains(event.target as Node)) {
        setIsMobileMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    const unsubNotif = storageService.subscribeNotifications((notifs) => {
        setUnreadCount(notifs.filter(n => !n.isRead).length);
    });

    const loadLogo = () => setLogo(storageService.getLogo());
    loadLogo();
    window.addEventListener('logo_updated', loadLogo);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      window.removeEventListener('logo_updated', loadLogo);
      if (unsubNotif) unsubNotif();
      if (unsubOrders) unsubOrders();
    };
  }, []);

  useEffect(() => {
      setIsMobileMenuOpen(false);
      setShowNotif(false);
  }, [location]);

  const handleSyncClick = () => {
    if (!isOnline) { toast.error("Chưa kết nối mạng"); return; }
    setShowConfirmSync(true);
  };

  const confirmSync = async () => {
    setShowConfirmSync(false);
    setIsSyncing(true);
    try {
        const count = await storageService.syncLocalToCloud();
        toast.success(`Đã đồng bộ ${count} dữ liệu!`);
    } catch (e) { toast.error("Lỗi đồng bộ."); } finally { setIsSyncing(false); }
  };

  const desktopLinkClass = (isActive: boolean) =>
    `flex items-center px-3 py-2 rounded-xl transition-all duration-300 relative ${
      isActive
        ? 'bg-white text-eco-800 font-bold shadow-lg transform scale-105'
        : 'text-eco-100 hover:bg-eco-700/50 hover:text-white font-medium'
    }`;

  const mobileLinkClass = (isActive: boolean) => 
    `p-3 rounded-xl transition-all flex items-center justify-center relative ${
        isActive 
        ? 'bg-white text-eco-800 shadow-md' 
        : 'text-eco-100 hover:bg-eco-800'
    }`;

  const menuItemClass = "flex items-center gap-3 w-full px-4 py-3 text-left hover:bg-gray-50 text-gray-700 font-medium transition-colors rounded-lg relative";

  return (
    <>
      <nav className="bg-gradient-to-r from-eco-800 to-eco-900 shadow-xl sticky top-0 z-50 border-b border-eco-700 select-none">
        <div className="container mx-auto px-4">
          <div className="flex justify-between items-center h-16">

            {/* Logo Area */}
            <div className="flex items-center space-x-3">
              <NavLink to="/dashboard" className="w-9 h-9 bg-white rounded-xl shadow-md flex items-center justify-center text-eco-700 overflow-hidden">
                {logo ? <img src={logo} alt="Logo" className="w-full h-full object-cover" /> : <i className="fas fa-shipping-fast"></i>}
              </NavLink>
              <div className="flex flex-col">
                 <span className="text-white text-lg font-black leading-tight tracking-tighter">EcoGo</span>
                 <div className="flex items-center gap-1.5 opacity-90">
                     <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-green-400' : 'bg-gray-400'}`}></span>
                     <span className="text-eco-200 text-[9px] font-bold uppercase tracking-widest">{isOnline ? 'Cloud' : 'Local'} v{appVersion}</span>
                 </div>
              </div>
            </div>

            {/* DESKTOP MENU */}
            <div className="hidden md:flex items-center space-x-1">
                <NavLink to="/dashboard" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-th-large mr-2"></i> Tổng Quan</NavLink>
                <NavLink to="/order" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-plus-circle mr-2"></i> Tạo Đơn</NavLink>
                <NavLink to="/tracking" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-tasks mr-2"></i> Theo Dõi</NavLink>
                <NavLink to="/audit" className={({ isActive }) => desktopLinkClass(isActive)}>
                    <i className="fas fa-file-invoice-dollar mr-2"></i> Đối Soát
                    {unverifiedCount > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-eco-800">{unverifiedCount}</span>}
                </NavLink>
                <NavLink to="/inventory" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-warehouse mr-2"></i> Kho</NavLink>

                <div className="w-px h-6 bg-eco-700 mx-2"></div>

                <div className="relative">
                    <button ref={notifBtnRef} onClick={(e) => {e.stopPropagation(); setShowNotif(!showNotif)}} className={`p-2 rounded-lg relative ${showNotif ? 'bg-eco-900 text-white' : 'text-eco-200 hover:text-white'}`}>
                        <i className="fas fa-bell"></i>
                        {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-eco-900"></span>}
                    </button>
                    <NotificationMenu isOpen={showNotif} onClose={() => setShowNotif(false)} ignoreRef={notifBtnRef} />
                </div>
                <button onClick={() => setShowSettings(true)} className="p-2 text-eco-200 hover:text-white"><i className="fas fa-cog"></i></button>
                <button onClick={onLogout} className="p-2 text-eco-200 hover:text-red-300"><i className="fas fa-sign-out-alt"></i></button>
            </div>

            {/* MOBILE ACTION BAR */}
            <div className="md:hidden flex items-center gap-2">
                <NavLink to="/order" className={({ isActive }) => mobileLinkClass(isActive)}><i className="fas fa-plus-circle text-xl"></i></NavLink>
                <NavLink to="/audit" className={({ isActive }) => mobileLinkClass(isActive)}>
                    <i className="fas fa-file-invoice-dollar text-xl"></i>
                    {unverifiedCount > 0 && <span className="absolute top-1.5 right-1.5 bg-red-500 text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-eco-800 shadow-sm">{unverifiedCount}</span>}
                </NavLink>
                <button onClick={(e) => { e.stopPropagation(); setIsMobileMenuOpen(!isMobileMenuOpen); }} className={`p-3 rounded-xl ${isMobileMenuOpen ? 'bg-eco-700 text-white' : 'text-eco-100'}`}><i className="fas fa-bars text-xl"></i></button>
            </div>
          </div>
        </div>

        {/* MOBILE DROPDOWN */}
        {isMobileMenuOpen && (
            <div ref={mobileMenuRef} className="absolute top-16 right-2 w-64 bg-white rounded-2xl shadow-2xl z-[100] border border-gray-100 overflow-hidden animate-fade-in-down origin-top-right md:hidden">
                <div className="p-2 space-y-1">
                    <NavLink to="/dashboard" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-th-large w-6"></i> Tổng Quan</NavLink>
                    <NavLink to="/tracking" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-tasks w-6"></i> Theo Dõi Đơn</NavLink>
                    <NavLink to="/audit" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}>
                        <i className="fas fa-file-invoice-dollar w-6"></i> Đối Soát CK
                        {unverifiedCount > 0 && <span className="absolute right-4 bg-red-500 text-white text-[10px] font-black px-2 rounded-full">{unverifiedCount} đơn</span>}
                    </NavLink>
                    <NavLink to="/inventory" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-warehouse w-6"></i> Kho Hàng</NavLink>
                    <NavLink to="/customers" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-users w-6"></i> Khách Hàng</NavLink>
                    <hr className="my-2 border-gray-100" />
                    <button onClick={() => { setShowSettings(true); setIsMobileMenuOpen(false); }} className={menuItemClass}><i className="fas fa-cog w-6"></i> Cài đặt</button>
                    <button onClick={onLogout} className={`${menuItemClass} text-red-600`}><i className="fas fa-sign-out-alt w-6"></i> Đăng xuất</button>
                </div>
            </div>
        )}
      </nav>

      <ConfirmModal 
        isOpen={showConfirmSync} title="Đồng bộ dữ liệu" message="Dữ liệu sẽ được đẩy lên Cloud."
        onConfirm={confirmSync} onCancel={() => setShowConfirmSync(false)}
      />
      <SettingsModal isOpen={showSettings} onClose={() => setShowSettings(false)} />
    </>
  );
};

export default Navbar;

import React, { useState, useEffect, useRef } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { storageService } from '../services/storageService';
import toast from 'react-hot-toast';
import { db } from '../firebaseConfig';
import ConfirmModal from './ConfirmModal';
import SettingsModal from './SettingsModal';
import NotificationMenu from './NotificationMenu';
import { Order, OrderStatus, PaymentMethod } from '../types';

declare const __APP_VERSION__: string;

interface Props {
  onLogout: () => void;
}

const Navbar: React.FC<Props> = ({ onLogout }) => {
  const [isSyncing, setIsSyncing] = useState(false);
  const [showConfirmSync, setShowConfirmSync] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showNotif, setShowNotif] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [logo, setLogo] = useState<string | null>(null);
  const [unreadCount, setUnreadCount] = useState(0);
  const [unverifiedCount, setUnverifiedCount] = useState(0);

  const mobileMenuRef = useRef<HTMLDivElement>(null);
  const notifBtnRef = useRef<HTMLButtonElement>(null); 
  const mobileNotifBtnRef = useRef<HTMLButtonElement>(null);
  const location = useLocation();
  const isOnline = !!db;

  const appVersion = typeof __APP_VERSION__ !== 'undefined' ? __APP_VERSION__ : '1.2.2';

  useEffect(() => {
    // Theo dõi đơn chưa xác nhận tiền
    const unsubOrders = storageService.subscribeOrders((orders) => {
        const count = orders.filter(o => 
            o.paymentMethod === PaymentMethod.TRANSFER && 
            !o.paymentVerified && 
            o.status !== OrderStatus.CANCELLED
        ).length;
        setUnverifiedCount(count);
    });

    const handleClickOutside = (event: MouseEvent) => {
      if (mobileMenuRef.current && !mobileMenuRef.current.contains(event.target as Node)) {
        setIsMobileMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    const unsubNotif = storageService.subscribeNotifications((notifs) => {
        setUnreadCount(notifs.filter(n => !n.isRead).length);
    });

    const loadLogo = () => setLogo(storageService.getLogo());
    loadLogo();
    window.addEventListener('logo_updated', loadLogo);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      window.removeEventListener('logo_updated', loadLogo);
      if (unsubNotif) unsubNotif();
      if (unsubOrders) unsubOrders();
    };
  }, []);

  useEffect(() => {
      setIsMobileMenuOpen(false);
      setShowNotif(false);
  }, [location]);

  const handleSyncClick = () => {
    if (!isOnline) { toast.error("Chưa kết nối mạng"); return; }
    setShowConfirmSync(true);
  };

  const confirmSync = async () => {
    setShowConfirmSync(false);
    setIsSyncing(true);
    try {
        const count = await storageService.syncLocalToCloud();
        toast.success(`Đã đồng bộ ${count} dữ liệu!`);
    } catch (e) { toast.error("Lỗi đồng bộ."); } finally { setIsSyncing(false); }
  };

  const desktopLinkClass = (isActive: boolean) =>
    `flex items-center px-3 py-2 rounded-xl transition-all duration-300 relative ${
      isActive
        ? 'bg-white text-eco-800 font-bold shadow-lg transform scale-105'
        : 'text-eco-100 hover:bg-eco-700/50 hover:text-white font-medium'
    }`;

  const mobileLinkClass = (isActive: boolean) => 
    `p-3 rounded-xl transition-all flex items-center justify-center relative ${
        isActive 
        ? 'bg-white text-eco-800 shadow-md' 
        : 'text-eco-100 hover:bg-eco-800'
    }`;

  const menuItemClass = "flex items-center gap-3 w-full px-4 py-3 text-left hover:bg-gray-50 text-gray-700 font-medium transition-colors rounded-lg relative";

  return (
    <>
      <nav className="bg-gradient-to-r from-eco-800 to-eco-900 shadow-xl sticky top-0 z-50 border-b border-eco-700 select-none">
        <div className="container mx-auto px-4">
          <div className="flex justify-between items-center h-16">

            {/* Logo Area */}
            <div className="flex items-center space-x-3">
              <NavLink to="/dashboard" className="w-9 h-9 bg-white rounded-xl shadow-md flex items-center justify-center text-eco-700 overflow-hidden">
                {logo ? <img src={logo} alt="Logo" className="w-full h-full object-cover" /> : <i className="fas fa-shipping-fast"></i>}
              </NavLink>
              <div className="flex flex-col">
                 <span className="text-white text-lg font-black leading-tight tracking-tighter">EcoGo</span>
                 <div className="flex items-center gap-1.5 opacity-90">
                     <span className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-green-400' : 'bg-gray-400'}`}></span>
                     <span className="text-eco-200 text-[9px] font-bold uppercase tracking-widest">{isOnline ? 'Cloud' : 'Local'} v{appVersion}</span>
                 </div>
              </div>
            </div>

            {/* DESKTOP MENU */}
            <div className="hidden md:flex items-center space-x-1">
                <NavLink to="/dashboard" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-th-large mr-2"></i> Tổng Quan</NavLink>
                <NavLink to="/order" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-plus-circle mr-2"></i> Tạo Đơn</NavLink>
                <NavLink to="/tracking" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-tasks mr-2"></i> Theo Dõi</NavLink>
                <NavLink to="/audit" className={({ isActive }) => desktopLinkClass(isActive)}>
                    <i className="fas fa-file-invoice-dollar mr-2"></i> Đối Soát
                    {unverifiedCount > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-eco-800">{unverifiedCount}</span>}
                </NavLink>
                <NavLink to="/inventory" className={({ isActive }) => desktopLinkClass(isActive)}><i className="fas fa-warehouse mr-2"></i> Kho</NavLink>

                <div className="w-px h-6 bg-eco-700 mx-2"></div>

                <div className="relative">
                    <button ref={notifBtnRef} onClick={(e) => {e.stopPropagation(); setShowNotif(!showNotif)}} className={`p-2 rounded-lg relative ${showNotif ? 'bg-eco-900 text-white' : 'text-eco-200 hover:text-white'}`}>
                        <i className="fas fa-bell"></i>
                        {unreadCount > 0 && <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border border-eco-900"></span>}
                    </button>
                    <NotificationMenu isOpen={showNotif} onClose={() => setShowNotif(false)} ignoreRef={notifBtnRef} />
                </div>
                <button onClick={() => setShowSettings(true)} className="p-2 text-eco-200 hover:text-white"><i className="fas fa-cog"></i></button>
                <button onClick={onLogout} className="p-2 text-eco-200 hover:text-red-300"><i className="fas fa-sign-out-alt"></i></button>
            </div>

            {/* MOBILE ACTION BAR */}
            <div className="md:hidden flex items-center gap-1 sm:gap-2">
                <NavLink to="/order" className={({ isActive }) => mobileLinkClass(isActive)}><i className="fas fa-plus-circle text-xl"></i></NavLink>

                <NavLink to="/audit" className={({ isActive }) => mobileLinkClass(isActive)}>
                    <i className="fas fa-file-invoice-dollar text-xl"></i>
                    {unverifiedCount > 0 && <span className="absolute top-1.5 right-1.5 bg-red-500 text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-eco-800 shadow-sm">{unverifiedCount}</span>}
                </NavLink>

                {/* NÚT THÔNG BÁO CHO MOBILE */}
                <button 
                    ref={mobileNotifBtnRef}
                    onClick={(e) => { e.stopPropagation(); setShowNotif(!showNotif); setIsMobileMenuOpen(false); }}
                    className={`p-3 rounded-xl transition-all flex items-center justify-center relative ${showNotif ? 'bg-white text-eco-800 shadow-md' : 'text-eco-100 hover:bg-eco-800'}`}
                >
                    <i className="fas fa-bell text-xl"></i>
                    {unreadCount > 0 && <span className="absolute top-1.5 right-1.5 bg-red-500 text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-eco-800 shadow-sm">{unreadCount}</span>}
                </button>

                <button onClick={(e) => { e.stopPropagation(); setIsMobileMenuOpen(!isMobileMenuOpen); setShowNotif(false); }} className={`p-3 rounded-xl ${isMobileMenuOpen ? 'bg-eco-700 text-white' : 'text-eco-100'}`}><i className="fas fa-bars text-xl"></i></button>
            </div>
          </div>
        </div>

        {/* NOTIFICATION MENU MODAL-LIKE FOR MOBILE */}
        <NotificationMenu 
            isOpen={showNotif} 
            onClose={() => setShowNotif(false)} 
            ignoreRef={mobileNotifBtnRef} 
        />

        {/* MOBILE DROPDOWN */}
        {isMobileMenuOpen && (
            <div ref={mobileMenuRef} className="absolute top-16 right-2 w-64 bg-white rounded-2xl shadow-2xl z-[100] border border-gray-100 overflow-hidden animate-fade-in-down origin-top-right md:hidden">
                <div className="p-2 space-y-1">
                    <NavLink to="/dashboard" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-th-large w-6"></i> Tổng Quan</NavLink>
                    <NavLink to="/tracking" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-tasks w-6"></i> Theo Dõi Đơn</NavLink>
                    <NavLink to="/audit" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}>
                        <i className="fas fa-file-invoice-dollar w-6"></i> Đối Soát CK
                        {unverifiedCount > 0 && <span className="absolute right-4 bg-red-500 text-white text-[10px] font-black px-2 rounded-full">{unverifiedCount} đơn</span>}
                    </NavLink>
                    <NavLink to="/inventory" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-warehouse w-6"></i> Kho Hàng</NavLink>
                    <NavLink to="/customers" className={({isActive}) => `${menuItemClass} ${isActive ? 'bg-eco-50 text-eco-700 font-bold' : ''}`}><i className="fas fa-users w-6"></i> Khách Hàng</NavLink>
                    <hr className="my-2 border-gray-100" />
                    <button onClick={() => { setShowSettings(true); setIsMobileMenuOpen(false); }} className={menuItemClass}><i className="fas fa-cog w-6"></i> Cài đặt</button>
                    <button onClick={onLogout} className={`${menuItemClass} text-red-600`}><i className="fas fa-sign-out-alt w-6"></i> Đăng xuất</button>
                </div>
            </div>
        )}
      </nav>

      <ConfirmModal 
        isOpen={showConfirmSync} title="Đồng bộ dữ liệu" message="Dữ liệu sẽ được đẩy lên Cloud."
        onConfirm={confirmSync} onCancel={() => setShowConfirmSync(false)}
      />
      <SettingsModal isOpen={showSettings} onClose={() => setShowSettings(false)} />
    </>
  );
};

export default Navbar;

import React, { useEffect, useState, useMemo } from 'react';
import { NavLink } from 'react-router-dom';
import { Order, Product, OrderStatus, PaymentMethod } from '../types';
import { storageService } from '../services/storageService';
import RevenueReport from './RevenueReport';
import toast from 'react-hot-toast';

const DashboardHome: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [showReport, setShowReport] = useState(false);
  const [showInstallGuide, setShowInstallGuide] = useState(false);

  const currentUser = storageService.getCurrentUser() || 'Admin';

  useEffect(() => {
    const unsubOrders = storageService.subscribeOrders(setOrders);
    const unsubProducts = storageService.subscribeProducts(setProducts);

    // Kiểm tra nếu chưa cài đặt App (PWA)
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;
    if (!isStandalone) {
        const timer = setTimeout(() => setShowInstallGuide(true), 2000);
        return () => clearTimeout(timer);
    }

    return () => {
      if (unsubOrders) unsubOrders();
      if (unsubProducts) unsubProducts();
    };
  }, []);

  const stats = useMemo(() => {
    const todayStart = new Date().setHours(0,0,0,0);
    const todaysOrders = orders.filter(o => o.createdAt >= todayStart && o.status !== OrderStatus.CANCELLED);

    const unverifiedTransfers = orders.filter(o => 
        o.paymentMethod === PaymentMethod.TRANSFER && 
        !o.paymentVerified && 
        o.status !== OrderStatus.CANCELLED
    );

    return {
      todayCount: todaysOrders.length,
      todayRevenue: todaysOrders.reduce((sum, o) => sum + o.totalPrice, 0),
      pendingCount: orders.filter(o => o.status === OrderStatus.PENDING || o.status === OrderStatus.PICKED_UP).length,
      lowStockCount: products.filter(p => p.stockQuantity < 5).length,
      unverifiedTransfers,
      unverifiedAmount: unverifiedTransfers.reduce((sum, o) => sum + o.totalPrice, 0)
    };
  }, [orders, products]);

  const handleQuickVerify = async (id: string, e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      await storageService.updatePaymentVerification(id, true);
      toast.success("Đã khớp tiền! ✅");
  };

  return (
    <div className="max-w-6xl mx-auto pb-24 animate-fade-in px-2">

      {/* GREETING & REPORT BUTTON */}
      <div className="mb-6 flex justify-between items-end px-2">
        <div>
            <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest mb-1">Hệ thống EcoGo</p>
            <h1 className="text-3xl font-black text-gray-900 tracking-tighter">Chào {currentUser}!</h1>
        </div>
        <button 
            onClick={() => setShowReport(true)}
            className="w-12 h-12 bg-white border-2 border-gray-900 rounded-2xl shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] flex items-center justify-center text-gray-900 active:translate-x-[2px] active:translate-y-[2px] active:shadow-none transition-all"
        >
            <i className="fas fa-chart-bar"></i>
        </button>
      </div>

      {/* PWA INSTALL NUDGE (Cảm giác như Widget thật) */}
      {showInstallGuide && (
          <div className="mb-6 mx-2 p-4 bg-blue-600 rounded-[2rem] text-white flex items-center justify-between shadow-xl animate-bounce-subtle">
              <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center text-lg">
                      <i className="fas fa-mobile-alt"></i>
                  </div>
                  <p className="text-xs font-black leading-tight uppercase">Cài đặt App ra màn hình<br/>để dùng như Widget</p>
              </div>
              <button onClick={() => setShowInstallGuide(false)} className="bg-white text-blue-600 px-4 py-2 rounded-xl font-black text-[10px] uppercase">OK</button>
          </div>
      )}

      {/* MAIN WIDGET GRID */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6 px-2">

          {/* Revenue Widget */}
          <div className="col-span-2 bg-white p-5 rounded-[2.5rem] border-2 border-gray-900 shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] relative overflow-hidden group">
              <div className="relative z-10">
                  <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Doanh thu hôm nay</div>
                  <div className="text-3xl font-black text-gray-900 tracking-tighter leading-none mb-1">
                      {new Intl.NumberFormat('vi-VN').format(stats.todayRevenue)}đ
                  </div>
                  <div className="flex items-center gap-1 text-[10px] font-bold text-eco-600 uppercase">
                      <i className="fas fa-arrow-up"></i> {stats.todayCount} đơn hàng
                  </div>
              </div>
              <div className="absolute right-4 bottom-4 opacity-10 text-6xl group-hover:scale-110 transition-transform">
                  <i className="fas fa-wallet"></i>
              </div>
          </div>

          {/* Pending Widget */}
          <NavLink to="/tracking" className="bg-orange-100 p-5 rounded-[2.5rem] border-2 border-gray-900 shadow-[6px_6px_0px_0px_rgba(0,0,0,1)] flex flex-col justify-between">
              <i className="fas fa-box text-orange-600 text-xl"></i>
              <div>
                  <div className="text-2xl font-black text-gray-900">{stats.pendingCount}</div>
                  <div className="text-[9px] font-black text-orange-700 uppercase">Cần đóng</div>
              </div>
          </NavLink>

          {/* Low Stock Widget */}
          <NavLink to="/inventory" className="bg-red-100 p-5 rounded-[2.5rem] border-2 border-gray-100 shadow-sm flex flex-col justify-between">
              <i className="fas fa-exclamation-triangle text-red-600 text-xl"></i>
              <div>
                  <div className="text-2xl font-black text-red-600">{stats.lowStockCount}</div>
                  <div className="text-[9px] font-black text-red-400 uppercase">Hết hàng</div>
              </div>
          </NavLink>
      </div>

      {/* THE "DEBT WIDGET" - TIỀN CHƯA XÁC NHẬN */}
      {stats.unverifiedTransfers.length > 0 && (
          <div className="mx-2 mb-8">
              <div className="flex justify-between items-center mb-3 px-2">
                  <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Tiền đang treo (Widget)</h3>
                  <NavLink to="/audit" className="text-[10px] font-black text-blue-600 uppercase">Xem hết ({stats.unverifiedTransfers.length})</NavLink>
              </div>
              <div className="bg-gray-900 rounded-[3rem] p-6 text-white shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-4 opacity-10 text-8xl">
                      <i className="fas fa-hand-holding-usd"></i>
                  </div>

                  <div className="relative z-10">
                      <div className="flex items-center gap-2 mb-2">
                          <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Chưa xác nhận tiền về</span>
                      </div>
                      <div className="text-4xl font-black tracking-tighter mb-4">
                          {new Intl.NumberFormat('vi-VN').format(stats.unverifiedAmount)}đ
                      </div>

                      {/* Quick Scrollable Carousel of Debts */}
                      <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
                          {stats.unverifiedTransfers.slice(0, 5).map(o => (
                              <div key={o.id} className="min-w-[180px] bg-white/10 backdrop-blur-md border border-white/10 rounded-3xl p-4 flex flex-col justify-between h-28">
                                  <div className="min-w-0">
                                      <div className="text-[10px] font-black text-gray-400 uppercase truncate mb-1">{o.customerName}</div>
                                      <div className="text-sm font-black truncate">{new Intl.NumberFormat('vi-VN').format(o.totalPrice)}đ</div>
                                  </div>
                                  <button 
                                      onClick={(e) => handleQuickVerify(o.id, e)}
                                      className="w-full py-2 bg-white text-gray-900 rounded-xl font-black text-[10px] uppercase shadow-lg active:scale-95 transition-all"
                                  >
                                      Xác nhận ✅
                                  </button>
                              </div>
                          ))}
                          <NavLink to="/audit" className="min-w-[100px] bg-white/5 rounded-3xl flex flex-col items-center justify-center text-gray-400 hover:text-white transition-colors">
                               <i className="fas fa-arrow-right mb-2"></i>
                               <span className="text-[9px] font-black uppercase">Tất cả</span>
                          </NavLink>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* QUICK ACTIONS SECTION */}
      <div className="grid grid-cols-1 gap-4 px-2">
          <NavLink to="/order" className="bg-eco-500 p-8 rounded-[3rem] text-white flex items-center justify-between shadow-xl group">
              <div>
                  <h3 className="text-2xl font-black tracking-tight leading-none mb-2 uppercase">Lên đơn ngay</h3>
                  <p className="text-white/70 text-xs font-bold">Tự động trừ kho & tính lãi</p>
              </div>
              <div className="w-16 h-16 bg-white rounded-[2rem] flex items-center justify-center text-eco-600 text-2xl shadow-lg group-hover:rotate-12 transition-transform">
                  <i className="fas fa-plus"></i>
              </div>
          </NavLink>
      </div>

      <RevenueReport isOpen={showReport} onClose={() => setShowReport(false)} />
    </div>
  );
};

export default DashboardHome;

import React, { useState, useEffect } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { storageService } from '../services/storageService';
