export default OrderForm;

import { Order, OrderStatus, Product, Customer, BankConfig, Notification, ShopConfig, ImportRecord } from '../types';
import { db } from '../firebaseConfig';
import { v4 as uuidv4 } from 'uuid';
import { 
  collection, 
  setDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  onSnapshot, 
  query, 
  orderBy, 
  getDocs, 
  writeBatch, 
  deleteField, 
  limit, 
  getDoc, 
  where, 
  increment,
  runTransaction 
} from "firebase/firestore";

const ORDER_KEY = 'ecogo_orders_v3'; 
const PRODUCT_KEY = 'ecogo_products_v1';
const CUSTOMER_KEY = 'ecogo_customers_v1';
const USER_KEY = 'ecogo_current_user';
const BANK_KEY = 'ecogo_bank_config';
const SHOP_KEY = 'ecogo_shop_config';
const NOTIF_KEY = 'ecogo_notifications_v1';
const TAGS_KEY = 'ecogo_quick_tags';
const QUOTA_KEY = 'ecogo_quota_status';
const LOGO_KEY = 'ecogo_company_logo';

const checkQuotaStatus = () => {
    try {
        const stored = localStorage.getItem(QUOTA_KEY);
        if (stored) {
            const { date, exhausted } = JSON.parse(stored);
            if (date === new Date().toDateString() && exhausted) return true;
        }
    } catch {}
    return false;
};

let _quotaExhausted = checkQuotaStatus();
const isOnline = () => !!db && !_quotaExhausted;

const markQuotaExhausted = () => {
    if (!_quotaExhausted) {
        _quotaExhausted = true;
        localStorage.setItem(QUOTA_KEY, JSON.stringify({ date: new Date().toDateString(), exhausted: true }));
        window.dispatchEvent(new Event('quota_exhausted'));
    }
};

let _memoryCustomers: Customer[] | null = null;
let _memoryOrders: Order[] | null = null;
let _memoryProducts: Product[] | null = null;

const ensureProductsLoaded = (): Product[] => {
    if (_memoryProducts) return _memoryProducts;
    try {
        const local = localStorage.getItem(PRODUCT_KEY);
        _memoryProducts = local ? (JSON.parse(local) as Product[]) : [];
    } catch { _memoryProducts = []; }
    return _memoryProducts || [];
};

const ensureOrdersLoaded = (): Order[] => {
    if (_memoryOrders) return _memoryOrders;
    try {
        const local = localStorage.getItem(ORDER_KEY);
        _memoryOrders = local ? (JSON.parse(local) as Order[]) : [];
    } catch { _memoryOrders = []; }
    return _memoryOrders || [];
};

const ensureCustomersLoaded = (): Customer[] => {
    if (_memoryCustomers) return _memoryCustomers;
    try {
        const local = localStorage.getItem(CUSTOMER_KEY);
        _memoryCustomers = local ? (JSON.parse(local) as Customer[]) : [];
    } catch { _memoryCustomers = []; }
    return _memoryCustomers || [];
};

export const normalizeString = (str: string): string => {
    if (!str) return "";
    return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
};

export const generateProductSku = (name: string): string => {
    if (!name) return uuidv4();
    const sku = name.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim().toUpperCase().replace(/[^A-Z0-9]+/g, "_");
    return sku.length < 2 ? uuidv4() : sku;
};

export const normalizePhone = (phone: string) => {
    if (!phone) return '';
    let p = phone.replace(/[^0-9]/g, '');
    if (p.startsWith('84')) p = '0' + p.slice(2);
    if (p.startsWith('+84')) p = '0' + p.slice(3);
    if (p.length === 9 && !p.startsWith('0')) p = '0' + p;
    return p;
};

const sanitize = <T>(obj: T): T => JSON.parse(JSON.stringify(obj));

const safeCloudOp = async (operation: () => Promise<any>) => {
    if (_quotaExhausted || !db) return;
    try { await operation(); } catch (error: any) {
        if (error.code === 'resource-exhausted') markQuotaExhausted();
    }
};

export const storageService = {
  login: (username: string) => localStorage.setItem(USER_KEY, username),
  logout: () => localStorage.removeItem(USER_KEY),
  getCurrentUser: () => localStorage.getItem(USER_KEY),

  getLogo: () => localStorage.getItem(LOGO_KEY),
  saveLogo: (base64: string) => { localStorage.setItem(LOGO_KEY, base64); window.dispatchEvent(new Event('logo_updated')); },
  removeLogo: () => { window.dispatchEvent(new Event('logo_updated')); localStorage.removeItem(LOGO_KEY); },

  getQuickTags: (): string[] => { try { const l = localStorage.getItem(TAGS_KEY); return l ? (JSON.parse(l) as string[]) : ["Dễ vỡ", "Gọi trước", "Cổng sau"]; } catch { return []; } },
  saveQuickTags: async (tags: string[]) => { localStorage.setItem(TAGS_KEY, JSON.stringify(tags)); await safeCloudOp(() => setDoc(doc(db, "settings", "quickTags"), { tags })); },
  fetchQuickTagsFromCloud: async () => { if (isOnline()) { try { const s = await getDoc(doc(db, "settings", "quickTags")); if (s.exists()) return s.data().tags as string[]; } catch {} } return storageService.getQuickTags(); },

  saveShopConfig: async (config: ShopConfig) => { localStorage.setItem(SHOP_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "shopConfig"), sanitize(config))); },
  getShopConfig: async (): Promise<ShopConfig | null> => { 
      if (isOnline()) {
          try {
              const s = await getDoc(doc(db, "settings", "shopConfig"));
              if (s.exists()) {
                  const data = s.data() as ShopConfig;
                  localStorage.setItem(SHOP_KEY, JSON.stringify(data));
                  return data;
              }
          } catch (e) { console.error("Cloud Shop Config Error:", e); }
      }
      const l = localStorage.getItem(SHOP_KEY); 
      if (l) return JSON.parse(l) as ShopConfig; 
      return null; 
  },

  saveBankConfig: async (config: BankConfig) => { localStorage.setItem(BANK_KEY, JSON.stringify(config)); await safeCloudOp(() => setDoc(doc(db, "settings", "bankConfig"), sanitize(config))); },
  getBankConfig: async (): Promise<BankConfig | null> => { 
      if (isOnline()) {
          try {
              const s = await getDoc(doc(db, "settings", "bankConfig"));
              if (s.exists()) {
                  const data = s.data() as BankConfig;
                  localStorage.setItem(BANK_KEY, JSON.stringify(data));
                  return data;
              }
          } catch (e) { console.error("Cloud Bank Config Error:", e); }
      }
      const l = localStorage.getItem(BANK_KEY); 
      if (l) return JSON.parse(l) as BankConfig; 
      return null; 
  },

  syncLocalToCloud: async () => {
    if (!isOnline()) throw new Error("Offline");
    const orders = ensureOrdersLoaded();
    const prods = ensureProductsLoaded();
    const batch = writeBatch(db);
    orders.forEach(o => batch.set(doc(db, "orders", o.id), sanitize(o)));
    prods.forEach(p => batch.set(doc(db, "products", p.id), sanitize(p)));
    await batch.commit();
    return orders.length + prods.length;
  },

  // --- NOTIFICATION ENGINE ---
  addNotification: async (notif: Omit<Notification, 'id' | 'isRead' | 'createdAt'>) => {
      const newNotif: Notification = {
          ...notif,
          id: uuidv4(),
          isRead: false,
          createdAt: Date.now()
      };
      // Lưu local trước để phản hồi nhanh
      try {
          const local = localStorage.getItem(NOTIF_KEY);
          const list = local ? JSON.parse(local) : [];
          list.unshift(newNotif);
          localStorage.setItem(NOTIF_KEY, JSON.stringify(list.slice(0, 50))); // Giữ tối đa 50 thông báo
      } catch {}

      // Đồng bộ Cloud
      await safeCloudOp(() => setDoc(doc(db, "notifications", newNotif.id), sanitize(newNotif)));
  },

  // --- CUSTOMER INTELLIGENCE (LEARNING) ---
  learnCustomerInfo: async (order: Order) => {
      const customers = ensureCustomersLoaded();
      const phone = normalizePhone(order.customerPhone);
      let existing = customers.find(c => c.id === order.customerId);

      if (!existing && phone.length > 8) {
          existing = customers.find(c => normalizePhone(c.phone) === phone);
      }

      const now = Date.now();
      if (existing) {
          const updated: Customer = {
              ...existing,
              address: order.address || existing.address,
              phone: order.customerPhone || existing.phone,
              lastOrderDate: now,
              totalOrders: (existing.totalOrders || 0) + 1,
              updatedAt: now
          };
          await storageService.upsertCustomer(updated);
      } else if (order.customerName) {
          const newCust: Customer = {
              id: order.customerId || uuidv4(),
              name: order.customerName,
              phone: order.customerPhone,
              address: order.address,
              lastOrderDate: now,
              totalOrders: 1,
              priorityScore: 999,
              updatedAt: now
          };
          await storageService.upsertCustomer(newCust);
      }
  },

  // --- PRODUCT MANAGEMENT ---
  subscribeProducts: (callback: (products: Product[]) => void) => {
    callback(ensureProductsLoaded());
    if (isOnline()) {
        const qry = query(collection(db, "products"), orderBy("updatedAt", "desc"), limit(500));
        return onSnapshot(qry, (snap) => {
            const list: Product[] = [];
            snap.forEach(d => list.push(d.data() as Product));
            if (list.length > 0) {
                _memoryProducts = list;
                localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
                callback(list);
            }
        });
    }
  },

  getAllProducts: () => ensureProductsLoaded(),
  getProductBySku: (sku: string) => ensureProductsLoaded().find(p => p.id === sku),

  saveProduct: async (product: Product) => {
      const pSave = { ...product, updatedAt: Date.now() };
      const list = ensureProductsLoaded();
      const idx = list.findIndex(p => p.id === pSave.id);
      if (idx >= 0) list[idx] = pSave; else list.unshift(pSave);
      _memoryProducts = list;
      localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
      window.dispatchEvent(new Event('storage_' + PRODUCT_KEY));
      await safeCloudOp(() => setDoc(doc(db, "products", pSave.id), sanitize(pSave)));
  },

  adjustStockAtomic: async (productId: string, delta: number, info?: { price: number, note?: string }) => {
      const now = Date.now();
      const list = ensureProductsLoaded();
      const p = list.find(x => x.id === productId);
      if (p) {
          const oldStock = p.stockQuantity || 0;
          p.stockQuantity = oldStock + delta;
          p.updatedAt = now;

          // Cảnh báo hết hàng tự động
          if (p.stockQuantity < 5 && oldStock >= 5) {
              storageService.addNotification({
                  title: 'Sắp hết hàng!',
                  message: `Sản phẩm "${p.name}" chỉ còn ${p.stockQuantity} món trong kho.`,
                  type: 'warning'
              });
          }

          if (delta > 0) {
              p.totalImported = (p.totalImported || 0) + delta;
              if (!p.importHistory) p.importHistory = [];
              p.importHistory.push({ id: uuidv4(), date: now, quantity: delta, price: info?.price || 0, note: info?.note });
          }
          localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
          window.dispatchEvent(new Event('storage_' + PRODUCT_KEY));
      }
      await safeCloudOp(() => runTransaction(db, async (tx) => {
          const ref = doc(db, "products", productId);
          const snap = await tx.get(ref);
          if (snap.exists()) {
              const data = snap.data() as Product;
              const updates: any = { stockQuantity: increment(delta), updatedAt: now };
              if (delta > 0) {
                  updates.totalImported = increment(delta);
                  const h = [...(data.importHistory || [])];
                  h.push({ id: uuidv4(), date: now, quantity: delta, price: info?.price || 0, note: info?.note });
                  updates.importHistory = h;
              }
              tx.update(ref, updates);
          }
      }));
  },

  deleteProduct: async (id: string) => {
      const list = ensureProductsLoaded().filter(p => p.id !== id);
      _memoryProducts = list;
      localStorage.setItem(PRODUCT_KEY, JSON.stringify(list));
      await safeCloudOp(() => deleteDoc(doc(db, "products", id)));
  },

  recalculateInventoryFromOrders: async () => {
      const prods = ensureProductsLoaded();
      const orders = ensureOrdersLoaded();
      const soldMap = new Map<string, number>();
      orders.forEach(o => {
          if (o.status === OrderStatus.CANCELLED) return;
          o.items.forEach(i => {
              if (i.productId) soldMap.set(i.productId, (soldMap.get(i.productId) || 0) + i.quantity);
          });
      });
      let updated = 0;
      for (const p of prods) {
          const sold = soldMap.get(p.id) || 0;
          const imported = p.totalImported || (p.stockQuantity + sold);
          const calcStock = Math.max(-100, imported - sold);
          if (p.stockQuantity !== calcStock) {
              p.stockQuantity = calcStock;
              p.totalImported = imported;
              p.updatedAt = Date.now();
              await storageService.saveProduct(p);
              updated++;
          }
      }
      return updated;
  },

  cleanAndMergeDuplicateProducts: async () => {
      const list = ensureProductsLoaded();
      const groups = new Map<string, Product[]>();
      list.forEach(p => {
          const k = generateProductSku(p.name);
          if (!groups.has(k)) groups.set(k, []);
          groups.get(k)!.push(p);
      });
      let merged = 0;
      for (const [key, group] of groups.entries()) {
          if (group.length <= 1) continue;
          group.sort((a,b) => b.stockQuantity - a.stockQuantity);
          const primary = group[0];
          const dups = group.slice(1);
          for (const d of dups) {
              primary.stockQuantity += d.stockQuantity;
              primary.totalImported = (primary.totalImported || 0) + (d.totalImported || 0);
              await storageService.deleteProduct(d.id);
              merged++;
          }
          primary.id = key;
          await storageService.saveProduct(primary);
      }
      return { mergedCount: merged, fixedOrders: 0 };
  },

  syncProductToPendingOrders: async (p: Product) => {
      const list = ensureOrdersLoaded();
      let updated = 0;
      list.forEach(o => {
          if (o.status === OrderStatus.PENDING) {
              o.items.forEach(i => {
                  if (i.productId === p.id) {
                      i.name = p.name;
                      i.price = p.defaultPrice;
                      i.importPrice = p.importPrice;
                      updated++;
                  }
              });
              if (updated > 0) {
                  o.totalPrice = o.items.reduce((s, it) => s + (it.price * it.quantity), 0);
              }
          }
      });
      if (updated > 0) {
          localStorage.setItem(ORDER_KEY, JSON.stringify(list));
          await storageService.syncLocalToCloud();
      }
      return updated;
  },

  // --- ORDER MANAGEMENT ---
  subscribeOrders: (callback: (orders: Order[]) => void) => {
    callback(ensureOrdersLoaded());
    if (isOnline()) {
        const q = query(collection(db, "orders"), orderBy("createdAt", "desc"), limit(400));
        return onSnapshot(q, (snap) => {
            const list: Order[] = [];
            snap.forEach(d => list.push(d.data() as Order));
            _memoryOrders = list;
            localStorage.setItem(ORDER_KEY, JSON.stringify(list));
            callback(list);
        });
    }
  },

  saveOrder: async (order: Order) => {
    const now = Date.now();
    const oSave = { ...order, updatedAt: now };
    const list = ensureOrdersLoaded();
    list.unshift(oSave);
    _memoryOrders = list;
    localStorage.setItem(ORDER_KEY, JSON.stringify(list));
    window.dispatchEvent(new Event('storage_' + ORDER_KEY));

    // THÔNG BÁO: Đơn mới
    storageService.addNotification({
        title: 'Đơn hàng mới',
        message: `Khách "${order.customerName}" vừa đặt ${order.items.length} món. Tổng: ${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ.`,
        type: 'success',
        relatedOrderId: order.id
    });

    // Learn from customer info automatically
    storageService.learnCustomerInfo(order);

    const prods = ensureProductsLoaded();
    order.items.forEach(item => {
        if (item.productId) {
            const p = prods.find(x => x.id === item.productId);
            if (p) { 
                const oldStock = p.stockQuantity;
                p.stockQuantity -= item.quantity; 
                p.updatedAt = now; 

                // Cảnh báo hết hàng ngay khi trừ kho
                if (p.stockQuantity < 5 && oldStock >= 5) {
                    storageService.addNotification({
                        title: 'Kho sắp cạn!',
                        message: `Hàng "${p.name}" chỉ còn ${p.stockQuantity} món sau đơn #${order.id}.`,
                        type: 'warning'
                    });
                }
            }
        }
    });
    localStorage.setItem(PRODUCT_KEY, JSON.stringify(prods));

    await safeCloudOp(() => runTransaction(db, async (tx) => {
        for (const item of order.items) {
            if (item.productId) {
                const ref = doc(db, "products", item.productId);
                tx.update(ref, { stockQuantity: increment(-item.quantity), updatedAt: now });
            }
        }
        tx.set(doc(db, "orders", oSave.id), sanitize(oSave));
    }));
  },

  updateOrderDetails: async (order: Order) => {
      const list = ensureOrdersLoaded();
      const idx = list.findIndex(o => o.id === order.id);
      if (idx >= 0) {
          list[idx] = { ...order, updatedAt: Date.now() };
          _memoryOrders = list;
          localStorage.setItem(ORDER_KEY, JSON.stringify(list));
          await safeCloudOp(() => setDoc(doc(db, "orders", order.id), sanitize(list[idx])));
      }
  },

  saveOrdersList: async (orders: Order[]) => {
      const list = ensureOrdersLoaded();
      orders.forEach(updatedOrder => {
          const idx = list.findIndex(o => o.id === updatedOrder.id);
          if (idx >= 0) list[idx] = { ...updatedOrder, updatedAt: Date.now() };
      });
      _memoryOrders = list;
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      if (isOnline()) {
          const batch = writeBatch(db);
          orders.forEach(o => batch.update(doc(db, "orders", o.id), { orderIndex: o.orderIndex, updatedAt: Date.now() }));
          await batch.commit();
      }
  },

  updateStatus: async (id: string, status: OrderStatus, proof?: string, cust?: any) => {
      const list = ensureOrdersLoaded();
      const idx = list.findIndex(o => o.id === id);
      if (idx >= 0) {
          list[idx] = { ...list[idx], status, updatedAt: Date.now(), deliveryProof: proof || list[idx].deliveryProof };
          _memoryOrders = list;
          localStorage.setItem(ORDER_KEY, JSON.stringify(list));
          await safeCloudOp(() => updateDoc(doc(db, "orders", id), { status, updatedAt: Date.now(), deliveryProof: proof || deleteField() }));
      }
  },

  deleteOrder: async (id: string, cust?: any) => {
      const list = ensureOrdersLoaded().filter(o => o.id !== id);
      _memoryOrders = list;
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      await safeCloudOp(() => deleteDoc(doc(db, "orders", id)));
  },

  deleteOrdersBatch: async (ids: string[]) => {
      const list = ensureOrdersLoaded().filter(o => !ids.includes(o.id));
      _memoryOrders = list;
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      if (isOnline()) {
          const batch = writeBatch(db);
          ids.forEach(id => batch.delete(doc(db, "orders", id)));
          await batch.commit();
      }
  },

  moveOrdersBatch: async (ids: string[], targetBatch: string) => {
      const list = ensureOrdersLoaded();
      ids.forEach(id => {
          const o = list.find(x => x.id === id);
          if (o) o.batchId = targetBatch;
      });
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      if (isOnline()) {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: targetBatch, updatedAt: Date.now() }));
          await batch.commit();
      }
  },

  splitOrderToNextBatch: async (id: string, currentBatchId: string) => {
      const today = new Date().toISOString().slice(0, 10);
      const nextBatch = currentBatchId.includes(today) ? `LÔ-SAU-${today}` : `LÔ-${today}-2`;
      await storageService.moveOrdersBatch([id], nextBatch);
  },

  splitOrdersBatch: async (items: {id: string, batchId: string}[]) => {
      const today = new Date().toISOString().slice(0, 10);
      const ids = items.map(i => i.id);
      const nextBatch = `LÔ-SAU-${today}`;
      await storageService.moveOrdersBatch(ids, nextBatch);
  },

  renameBatch: async (oldName: string, newName: string) => {
      const list = ensureOrdersLoaded();
      const ids: string[] = [];
      list.forEach(o => {
          if (o.batchId === oldName) {
              o.batchId = newName;
              ids.push(o.id);
          }
      });
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      if (isOnline() && ids.length > 0) {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { batchId: newName, updatedAt: Date.now() }));
          await batch.commit();
      }
  },

  updatePaymentVerification: async (id: string, verified: boolean, cust?: any) => {
      const list = ensureOrdersLoaded();
      const idx = list.findIndex(o => o.id === id);
      if (idx >= 0) {
          list[idx].paymentVerified = verified;
          localStorage.setItem(ORDER_KEY, JSON.stringify(list));

          // THÔNG BÁO: Tiền về
          if (verified) {
              storageService.addNotification({
                  title: 'Xác nhận tiền về',
                  message: `Đơn #${id} của khách "${list[idx].customerName}" đã được thanh toán ${new Intl.NumberFormat('vi-VN').format(list[idx].totalPrice)}đ.`,
                  type: 'info',
                  relatedOrderId: id
              });
          }

          await safeCloudOp(() => updateDoc(doc(db, "orders", id), { paymentVerified: verified, updatedAt: Date.now() }));
      }
  },

  incrementReminderCount: async (ids: string[]) => {
      const list = ensureOrdersLoaded();
      ids.forEach(id => {
          const o = list.find(x => x.id === id);
          if (o) o.reminderCount = (o.reminderCount || 0) + 1;
      });
      localStorage.setItem(ORDER_KEY, JSON.stringify(list));
      if (isOnline()) {
          const batch = writeBatch(db);
          ids.forEach(id => batch.update(doc(db, "orders", id), { reminderCount: increment(1) }));
          await batch.commit();
      }
  },

  deleteDeliveryProof: async (id: string) => {
      const list = ensureOrdersLoaded();
      const idx = list.findIndex(o => o.id === id);
      if (idx >= 0) {
          list[idx].deliveryProof = undefined;
          localStorage.setItem(ORDER_KEY, JSON.stringify(list));
          await safeCloudOp(() => updateDoc(doc(db, "orders", id), { deliveryProof: deleteField() }));
      }
  },

  getProductOrderHistory: (productId: string) => {
      const orders = ensureOrdersLoaded();
      const history: { order: Order, quantity: number }[] = [];
      orders.forEach(o => {
          o.items.forEach(i => {
              if (i.productId === productId) history.push({ order: o, quantity: i.quantity });
          });
      });
      return history;
  },

  learnRoutePriority: async (sortedOrders: Order[]) => {
      for (let i = 0; i < sortedOrders.length; i++) {
          const o = sortedOrders[i];
          if (o.customerId) {
              const custList = await storageService.getAllCustomers();
              const cust = custList.find(c => c.id === o.customerId);
              if (cust) {
                  cust.priorityScore = i + 1;
                  await storageService.upsertCustomer(cust);
              }
          }
      }
  },

  // --- CUSTOMER MANAGEMENT ---
  subscribeCustomers: (callback: (c: Customer[]) => void) => {
      callback(ensureCustomersLoaded());
      if (isOnline()) {
          return onSnapshot(collection(db, "customers"), (snap) => {
              const l: Customer[] = [];
              snap.forEach(d => l.push(d.data() as Customer));
              if (l.length > 0) {
                _memoryCustomers = l;
                localStorage.setItem(CUSTOMER_KEY, JSON.stringify(l));
                callback(l);
              }
          });
      }
  },

  getAllCustomers: async (): Promise<Customer[]> => {
      return ensureCustomersLoaded();
  },

  upsertCustomer: async (c: Customer) => {
      const list = ensureCustomersLoaded();
      const idx = list.findIndex(x => x.id === c.id);
      const cSave = { ...c, updatedAt: Date.now() };
      if (idx >= 0) list[idx] = cSave; else list.unshift(cSave);
      _memoryCustomers = list;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => setDoc(doc(db, "customers", c.id), sanitize(cSave)));
  },

  deleteCustomer: async (id: string) => {
      const list = ensureCustomersLoaded().filter(c => c.id !== id);
      _memoryCustomers = list;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(list));
      await safeCloudOp(() => deleteDoc(doc(db, "customers", id)));
  },

  importCustomersBatch: async (customers: Customer[], localOnly: boolean = false) => {
      const list = ensureCustomersLoaded();
      const newMap = new Map<string, Customer>(list.map(c => [c.id, c]));
      customers.forEach(c => newMap.set(c.id, { ...c, updatedAt: Date.now() }));
      const finalList = Array.from(newMap.values());
      _memoryCustomers = finalList;
      localStorage.setItem(CUSTOMER_KEY, JSON.stringify(finalList));
      if (!localOnly && isOnline()) {
          const chunks = [];
          for (let i = 0; i < customers.length; i += 400) {
              chunks.push(customers.slice(i, i + 400));
          }
          for (const chunk of chunks) {
              const batch = writeBatch(db);
              chunk.forEach(c => batch.set(doc(db, "customers", c.id), sanitize(c)));
              await batch.commit();
          }
      }
  },

  clearAllCustomers: async (localOnly: boolean = false) => {
      localStorage.removeItem(CUSTOMER_KEY);
      _memoryCustomers = [];
      if (!localOnly && isOnline()) {
          const snap = await getDocs(collection(db, "customers"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      }
  },

  markAllCustomersAsOld: async () => {
      const list = ensureCustomersLoaded();
      list.forEach(c => { c.isLegacy = true; c.totalOrders = (c.totalOrders || 0) + 1; });
      await storageService.importCustomersBatch(list);
      return list.length;
  },

  fixDuplicateCustomerIds: async () => {
      const list = ensureCustomersLoaded();
      const seen = new Set();
      let fixed = 0;
      for (const c of list) {
          if (seen.has(c.id)) {
              c.id = uuidv4();
              fixed++;
          }
          seen.add(c.id);
      }
      if (fixed > 0) await storageService.importCustomersBatch(list);
      return fixed;
  },

  mergeCustomersByPhone: async () => {
      const list = ensureCustomersLoaded();
      const phoneMap = new Map<string, Customer[]>();
      list.forEach(c => {
          if (c.phone) {
              const p = normalizePhone(c.phone);
              if (!phoneMap.has(p)) phoneMap.set(p, []);
              phoneMap.get(p)!.push(c);
          }
      });
      let mergedGroups = 0;
      for (const [phone, group] of phoneMap.entries()) {
          if (group.length > 1) {
              group.sort((a, b) => (b.totalOrders || 0) - (a.totalOrders || 0));
              const primary = group[0];
              for (let i = 1; i < group.length; i++) {
                  primary.totalOrders = (primary.totalOrders || 0) + (group[i].totalOrders || 0);
                  await storageService.deleteCustomer(group[i].id);
              }
              await storageService.upsertCustomer(primary);
              mergedGroups++;
          }
      }
      return mergedGroups;
  },

  isNewCustomer: (phone: string, addr: string, id?: string) => {
      const list = ensureOrdersLoaded();
      if (id) return !list.some(o => o.customerId === id);
      const p = normalizePhone(phone);
      if (p.length > 8) return !list.some(o => normalizePhone(o.customerPhone) === p);
      return !list.some(o => normalizeString(o.address) === normalizeString(addr));
  },

  findMatchingCustomer: (phone: string, addr: string, id?: string) => {
      const list = ensureCustomersLoaded();
      if (id) return list.find(c => c.id === id);
      const p = normalizePhone(phone);
      if (p.length > 8) return list.find(c => normalizePhone(c.phone) === p);
      const nAddr = normalizeString(addr);
      return list.find(c => normalizeString(c.address) === nAddr);
  },

  // --- NOTIFICATION MANAGEMENT ---
  subscribeNotifications: (callback: (notifs: Notification[]) => void) => {
      const load = () => {
          try {
              const local = localStorage.getItem(NOTIF_KEY);
              callback(local ? (JSON.parse(local) as Notification[]) : []);
          } catch { callback([]); }
      };
      load();
      if (isOnline()) {
          return onSnapshot(query(collection(db, "notifications"), orderBy("createdAt", "desc"), limit(50)), (snap) => {
              const list: Notification[] = [];
              snap.forEach(d => list.push(d.data() as Notification));
              localStorage.setItem(NOTIF_KEY, JSON.stringify(list));
              callback(list);
          });
      }
  },

  markNotificationRead: async (id: string) => {
      await safeCloudOp(() => updateDoc(doc(db, "notifications", id), { isRead: true }));
      window.dispatchEvent(new CustomEvent('local_notif_read', { detail: id }));
  },

  markAllNotificationsRead: async () => {
      if (isOnline()) {
          const snap = await getDocs(query(collection(db, "notifications"), where("isRead", "==", false)));
          const batch = writeBatch(db);
          snap.forEach(d => batch.update(d.ref, { isRead: true }));
          await batch.commit();
      }
      window.dispatchEvent(new Event('local_notif_read_all'));
  },

  clearAllNotifications: async () => {
      localStorage.removeItem(NOTIF_KEY);
      if (isOnline()) {
          const snap = await getDocs(collection(db, "notifications"));
          const batch = writeBatch(db);
          snap.forEach(d => batch.delete(d.ref));
          await batch.commit();
      }
      window.dispatchEvent(new Event('local_notif_clear_all'));
  },

  // --- UTILS ---
  fetchLongTermStats: async (): Promise<Order[]> => {
      if (isOnline()) {
          const snap = await getDocs(query(collection(db, "orders"), limit(2000)));
          return snap.docs.map(d => d.data() as Order);
      }
      return ensureOrdersLoaded();
  },

  generatePerformanceData: async (count: number) => {
      const start = Date.now();
      const fakeCustomers: Customer[] = [];
      for (let i = 0; i < count; i++) {
          const newCustomer: Customer = {
              id: uuidv4(),
              name: `Khách Hàng Ảo ${i}`,
              phone: `09${Math.floor(10000000 + Math.random() * 90000000)}`,
              address: `${i} Đường ABC, Quận XYZ, TP. HCM`,
              lastOrderDate: Date.now(),
              priorityScore: 999
          };
          fakeCustomers.push(newCustomer);
      }
      await storageService.importCustomersBatch(fakeCustomers, true);
      return { count, duration: Date.now() - start };
  }
};

import React, { useState, useEffect, useDeferredValue } from 'react';
import toast from 'react-hot-toast';
import { Customer } from '../types';
import { storageService, normalizePhone, normalizeString } from '../services/storageService';
import { verifyAddress } from '../services/geminiService';
import ConfirmModal from './ConfirmModal';
import { v4 as uuidv4 } from 'uuid';

const CustomerBadge: React.FC<{ count: number, isLegacy?: boolean }> = ({ count, isLegacy }) => {
    if (isLegacy || count === 0) return <span className="bg-blue-50 text-blue-600 text-[9px] font-black px-2 py-0.5 rounded-full border border-blue-100 uppercase tracking-tighter">Mới</span>;
    if (count >= 10) return <span className="bg-red-50 text-red-600 text-[9px] font-black px-2 py-0.5 rounded-full border border-red-100 uppercase tracking-tighter animate-pulse">💎 VIP</span>;
    if (count >= 5) return <span className="bg-eco-50 text-eco-600 text-[9px] font-black px-2 py-0.5 rounded-full border border-eco-100 uppercase tracking-tighter">🌟 Thân thiết</span>;
    return <span className="bg-gray-50 text-gray-500 text-[9px] font-black px-2 py-0.5 rounded-full border border-gray-100 uppercase tracking-tighter">Quen</span>;
};

const CustomerManager: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const deferredSearchTerm = useDeferredValue(searchTerm);

  const [isAdding, setIsAdding] = useState(false);
  const [formData, setFormData] = useState<Partial<Customer>>({ name: '', phone: '', address: '', priorityScore: 999 });
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);

  const [isListeningSearch, setIsListeningSearch] = useState(false);
  const [isVerifyingAddr, setIsVerifyingAddr] = useState(false);

  useEffect(() => { 
      const unsubscribe = storageService.subscribeCustomers(setCustomers); 
      return () => { if (unsubscribe) unsubscribe(); }; 
  }, []);

  const filteredCustomers = customers.filter(c => {
      if (!deferredSearchTerm) return true;
      const lower = deferredSearchTerm.toLowerCase();
      return normalizeString(c.name).includes(normalizeString(lower)) || 
             c.phone.includes(lower) || 
             normalizeString(c.address).includes(normalizeString(lower));
  }).sort((a, b) => (b.totalOrders || 0) - (a.totalOrders || 0));

  const handleDeleteClick = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setDeleteId(id);
    setShowDeleteConfirm(true);
  };

  const confirmDelete = async () => {
    if (deleteId) {
      await storageService.deleteCustomer(deleteId);
      toast.success('Đã xóa khách hàng');
      setShowDeleteConfirm(false);
      setDeleteId(null);
    }
  };

  const handleVoiceSearch = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListeningSearch(true);
    recognition.onend = () => setIsListeningSearch(false);
    recognition.onresult = (event: any) => { setSearchTerm(event.results[0][0].transcript); };
    recognition.start();
  };

  const handleVerifyAddress = async () => {
      if (!formData.address || formData.address.length < 5) { toast.error("Nhập địa chỉ trước"); return; }
      setIsVerifyingAddr(true);
      try {
          const result = await verifyAddress(formData.address);
          setFormData(prev => ({ ...prev, address: result.address }));
          toast.success("Đã ghim vị trí!");
      } catch (e: any) { toast.error("Không tìm thấy"); } finally { setIsVerifyingAddr(false); }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) { toast.error('Nhập tên khách'); return; }
    const cleanPhone = normalizePhone(formData.phone || '');
    const newId = cleanPhone.length > 8 ? cleanPhone : uuidv4();
    await storageService.upsertCustomer({
        id: newId,
        name: formData.name,
        phone: cleanPhone,
        address: formData.address || '',
        lastOrderDate: Date.now(),
        priorityScore: formData.priorityScore || 999,
        totalOrders: 0,
        updatedAt: Date.now()
    });
    setFormData({ name: '', phone: '', address: '', priorityScore: 999 });
    setIsAdding(false);
    toast.success('Đã thêm khách hàng mới');
  };

  const handleInlineUpdate = async (customer: Customer, field: keyof Customer, value: any) => { 
      if (customer[field] === value) return; 
      await storageService.upsertCustomer({ ...customer, [field]: value, updatedAt: Date.now() }); 
      toast.success("Đã cập nhật", { duration: 1000 });
  };

  const contactActions = {
      call: (phone: string) => window.open(`tel:${phone}`, '_self'),
      zalo: (phone: string) => window.open(`https://zalo.me/${normalizePhone(phone).replace(/^0/, '84')}`, '_blank'),
      sms: (phone: string) => window.open(`sms:${phone}`, '_self'),
      maps: (addr: string) => window.open(`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(addr)}`, '_blank')
  };

  return (
    <div className="max-w-6xl mx-auto pb-32 animate-fade-in px-3">

      {/* HEADER SECTION */}
      <div className="flex flex-col gap-4 mb-6 sticky top-16 z-30 bg-gray-50/95 py-3 backdrop-blur-sm">
          <div className="flex items-center justify-between">
              <div>
                  <h1 className="text-2xl font-black text-gray-900 tracking-tighter uppercase italic">Danh bạ <span className="text-eco-600">Thông minh</span></h1>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Quản lý {customers.length} khách hàng</p>
              </div>
              <button 
                  onClick={() => setIsAdding(!isAdding)} 
                  className={`w-12 h-12 rounded-2xl shadow-lg flex items-center justify-center transition-all active:scale-95 ${isAdding ? 'bg-red-500 text-white' : 'bg-black text-white'}`}
              >
                  <i className={`fas ${isAdding ? 'fa-times' : 'fa-user-plus'}`}></i>
              </button>
          </div>

          <div className="relative group">
              <i className="fas fa-search absolute left-4 top-3.5 text-gray-400 group-focus-within:text-eco-600 transition-colors"></i>
              <input 
                  value={searchTerm} 
                  onChange={e => setSearchTerm(e.target.value)}
                  placeholder="Tìm tên, sđt hoặc địa chỉ..." 
                  className="w-full pl-12 pr-12 py-4 bg-white border-2 border-gray-100 rounded-2xl shadow-sm outline-none focus:border-eco-500 focus:ring-4 focus:ring-eco-50 font-bold text-gray-800 transition-all"
              />
              <button 
                  onClick={handleVoiceSearch}
                  className={`absolute right-3 top-2.5 w-9 h-9 rounded-xl flex items-center justify-center transition-all ${isListeningSearch ? 'bg-red-500 text-white animate-pulse' : 'text-gray-400 hover:bg-gray-100'}`}
              >
                  <i className={`fas ${isListeningSearch ? 'fa-microphone-slash' : 'fa-microphone'}`}></i>
              </button>
          </div>
      </div>

      {/* ADD FORM (CONDITIONAL) */}
      {isAdding && (
          <div className="mb-8 bg-white p-6 rounded-[2.5rem] border-4 border-gray-900 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] animate-scale-in">
              <h3 className="text-xs font-black text-gray-400 uppercase mb-4 tracking-widest flex items-center gap-2">
                  <i className="fas fa-magic text-eco-600"></i> Thêm khách hàng nhanh
              </h3>
              <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="md:col-span-1">
                      <input 
                          value={formData.name} 
                          onChange={e => setFormData({ ...formData, name: e.target.value })}
                          className="w-full p-3 bg-gray-50 border-2 border-gray-200 rounded-xl font-bold outline-none focus:border-black"
                          placeholder="Họ và Tên khách *"
                      />
                  </div>
                  <div className="md:col-span-1">
                      <input 
                          value={formData.phone} 
                          onChange={e => setFormData({ ...formData, phone: e.target.value })}
                          className="w-full p-3 bg-gray-50 border-2 border-gray-200 rounded-xl font-bold outline-none focus:border-black"
                          placeholder="Số điện thoại"
                      />
                  </div>
                  <div className="md:col-span-2 relative">
                      <input 
                          value={formData.address} 
                          onChange={e => setFormData({ ...formData, address: e.target.value })}
                          className="w-full p-3 bg-gray-50 border-2 border-gray-200 rounded-xl font-bold outline-none focus:border-black pr-12"
                          placeholder="Địa chỉ giao hàng"
                      />
                      <button type="button" onClick={handleVerifyAddress} className="absolute right-3 top-2.5 w-8 h-8 text-red-500 hover:scale-110 transition-all">
                          <i className={`fas ${isVerifyingAddr ? 'fa-circle-notch fa-spin' : 'fa-map-marker-alt'}`}></i>
                      </button>
                  </div>
                  <button type="submit" className="md:col-span-2 py-4 bg-eco-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-eco-100 active:scale-95 transition-all">
                      Lưu thông tin <i className="fas fa-check-circle ml-2"></i>
                  </button>
              </form>
          </div>
      )}

      {/* CUSTOMER GRID */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredCustomers.length === 0 ? (
              <div className="col-span-full py-20 text-center text-gray-300">
                  <i className="fas fa-user-slash text-6xl mb-4 opacity-20"></i>
                  <p className="font-bold uppercase tracking-widest text-xs">Không tìm thấy khách hàng</p>
              </div>
          ) : (
              filteredCustomers.map(customer => (
                  <div 
                    key={customer.id} 
                    className="bg-white rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 overflow-hidden group"
                  >
                      <div className="p-5">
                          <div className="flex justify-between items-start mb-3">
                              <div className="flex gap-3 items-center">
                                  <div className="w-12 h-12 bg-gradient-to-br from-gray-100 to-gray-200 rounded-2xl flex items-center justify-center text-gray-500 font-black text-lg border-2 border-white shadow-inner group-hover:from-eco-500 group-hover:to-eco-600 group-hover:text-white transition-all">
                                      {customer.name.charAt(0).toUpperCase()}
                                  </div>
                                  <div>
                                      <input 
                                          className="font-black text-gray-800 text-sm uppercase bg-transparent border-none p-0 outline-none w-full focus:text-eco-600"
                                          defaultValue={customer.name}
                                          onBlur={(e) => handleInlineUpdate(customer, 'name', e.target.value)}
                                      />
                                      <div className="flex items-center gap-2 mt-1">
                                          <CustomerBadge count={customer.totalOrders || 0} isLegacy={customer.isLegacy} />
                                          <span className="text-[10px] font-bold text-gray-400">{customer.totalOrders || 0} đơn</span>
                                      </div>
                                  </div>
                              </div>
                              <button 
                                onClick={(e) => handleDeleteClick(customer.id, e)}
                                className="w-8 h-8 rounded-full bg-gray-50 text-gray-300 hover:bg-red-50 hover:text-red-500 flex items-center justify-center transition-all opacity-0 group-hover:opacity-100"
                              >
                                  <i className="fas fa-trash-alt text-xs"></i>
                              </button>
                          </div>

                          <div className="space-y-2 mb-4">
                              <div className="flex items-center gap-3 p-2 bg-gray-50 rounded-xl border border-transparent hover:border-eco-100 transition-colors">
                                  <i className="fas fa-phone-alt text-eco-600 text-xs w-4 text-center"></i>
                                  <input 
                                      className="text-xs font-black text-gray-700 bg-transparent border-none p-0 outline-none flex-grow"
                                      defaultValue={customer.phone}
                                      placeholder="Chưa có SĐT"
                                      onBlur={(e) => handleInlineUpdate(customer, 'phone', e.target.value)}
                                  />
                              </div>
                              <div className="flex items-start gap-3 p-2 bg-gray-50 rounded-xl border border-transparent hover:border-eco-100 transition-colors">
                                  <i className="fas fa-map-marker-alt text-red-500 text-xs w-4 text-center mt-1"></i>
                                  <textarea 
                                      className="text-[11px] font-bold text-gray-500 bg-transparent border-none p-0 outline-none flex-grow resize-none leading-snug"
                                      rows={2}
                                      defaultValue={customer.address}
                                      placeholder="Chưa có địa chỉ"
                                      onBlur={(e) => handleInlineUpdate(customer, 'address', e.target.value)}
                                  />
                              </div>
                          </div>

                          <div className="grid grid-cols-4 gap-2">
                              <button 
                                onClick={() => contactActions.call(customer.phone)}
                                className="h-10 rounded-xl bg-green-50 text-green-600 hover:bg-green-600 hover:text-white transition-all flex items-center justify-center border border-green-100"
                                title="Gọi điện"
                              >
                                  <i className="fas fa-phone-alt"></i>
                              </button>
                              <button 
                                onClick={() => contactActions.zalo(customer.phone)}
                                className="h-10 rounded-xl bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white transition-all flex items-center justify-center border border-blue-100 font-black text-xs"
                                title="Zalo"
                              >
                                  Z
                              </button>
                              <button 
                                onClick={() => contactActions.sms(customer.phone)}
                                className="h-10 rounded-xl bg-orange-50 text-orange-600 hover:bg-orange-600 hover:text-white transition-all flex items-center justify-center border border-orange-100"
                                title="Gửi SMS"
                              >
                                  <i className="fas fa-comment-dots"></i>
                              </button>
                              <button 
                                onClick={() => contactActions.maps(customer.address)}
                                className="h-10 rounded-xl bg-red-50 text-red-500 hover:bg-red-600 hover:text-white transition-all flex items-center justify-center border border-red-100"
                                title="Chỉ đường"
                              >
                                  <i className="fas fa-directions"></i>
                              </button>
                          </div>
                      </div>
                      <div className="bg-gray-50 px-5 py-2 border-t border-gray-50 flex justify-between items-center group-hover:bg-eco-50 transition-colors">
                          <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Đã học dữ liệu</span>
                          <div className="flex gap-1">
                              {customer.priorityScore && customer.priorityScore < 100 && (
                                  <span className="w-2 h-2 bg-yellow-400 rounded-full"></span>
                              )}
                              <span className="w-2 h-2 bg-eco-400 rounded-full"></span>
                          </div>
                      </div>
                  </div>
              ))
          )}
      </div>

      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa khách hàng?" 
        message="Dữ liệu về khách hàng này sẽ bị gỡ bỏ khỏi danh bạ. Các đơn hàng cũ vẫn sẽ được giữ lại." 
        onConfirm={confirmDelete} 
        onCancel={() => setShowDeleteConfirm(false)} 
        confirmLabel="Xóa vĩnh viễn" 
        isDanger={true} 
      />
    </div>
  );
};

export default CustomerManager;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import toast from 'react-hot-toast';
import { Order, OrderStatus, Product, Customer, PaymentMethod, OrderItem } from '../types';
import { storageService, normalizeString } from '../services/storageService';
import { parseOrderText } from '../services/geminiService';
import { ProductEditModal } from './InventoryManager';

type SidebarTab = 'ACTIVE' | 'WARNING' | 'SEARCH';

const OrderForm: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); 
  const [quickTags, setQuickTags] = useState<string[]>([]);

  const [mobileTab, setMobileTab] = useState<'FORM' | 'STATS'>('FORM');
  const [sidebarTab, setSidebarTab] = useState<'ACTIVE' | 'WARNING' | 'SEARCH'>('ACTIVE');
  const [sidebarSearch, setSidebarSearch] = useState('');

  const [showCustomerSuggestions, setShowCustomerSuggestions] = useState(false);
  const [activeProductRow, setActiveProductRow] = useState<number | null>(null);

  const [batchId, setBatchId] = useState('');
  const [existingBatches, setExistingBatches] = useState<string[]>([]);
  const [showBatchSuggestions, setShowBatchSuggestions] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);

  const [showProductModal, setShowProductModal] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editMode, setEditMode] = useState<'IMPORT' | 'SET'>('IMPORT');

  const [customerInfo, setCustomerInfo] = useState({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
  const [items, setItems] = useState<Partial<OrderItem>[]>([ { id: uuidv4(), name: '', quantity: 1, price: 0 } ]);

  const customerWrapperRef = useRef<HTMLDivElement>(null);
  const productWrapperRef = useRef<HTMLDivElement>(null);
  const batchWrapperRef = useRef<HTMLDivElement>(null);
  const nameInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);
    setQuickTags(storageService.getQuickTags());
    const unsubOrders = storageService.subscribeOrders((loadedOrders) => {
        setOrders(loadedOrders);
        const batchActivity = new Map<string, number>();
        loadedOrders.forEach(o => { if (o.batchId) { batchActivity.set(o.batchId, Math.max(batchActivity.get(o.batchId) || 0, o.createdAt)); } });
        const sorted = Array.from(batchActivity.entries()).sort((a, b) => b[1] - a[1]).map(e => e[0]).slice(0, 15);
        setExistingBatches(sorted);
        setBatchId(prev => { if (prev) return prev; const today = new Date().toISOString().slice(0, 10); return sorted.find(b => b.includes(today)) || `LÔ-${today}`; });
    });
    const handleClickOutside = (e: MouseEvent) => {
      if (customerWrapperRef.current && !customerWrapperRef.current.contains(e.target as Node)) setShowCustomerSuggestions(false);
      if (productWrapperRef.current && !productWrapperRef.current.contains(e.target as Node)) setActiveProductRow(null);
      if (batchWrapperRef.current && !batchWrapperRef.current.contains(e.target as Node)) setShowBatchSuggestions(false);
    };
    document.addEventListener("mousedown", handleClickOutside);
    if (nameInputRef.current) nameInputRef.current.focus();
    return () => { document.removeEventListener("mousedown", handleClickOutside); if (unsubProducts) unsubProducts(); if (unsubCustomers) unsubCustomers(); if (unsubOrders) unsubOrders(); };
  }, []);

  const totalPrice = items.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);

  const filteredSidebarProducts = useMemo(() => {
      const soldMap = new Map<string, { name: string, qty: number, productId?: string }>();
      const currentBatch = batchId?.trim();
      orders.forEach(o => { if (o.batchId?.trim() === currentBatch && o.status !== OrderStatus.CANCELLED) { o.items.forEach(item => { const normName = normalizeString(item.name); const existing = soldMap.get(normName) || { name: item.name, qty: 0, productId: item.productId }; existing.qty += (Number(item.quantity) || 0); soldMap.set(normName, existing); }); } });
      const inventoryItems = products.map(p => { const normName = normalizeString(p.name); const soldData = soldMap.get(normName); if (soldData) soldMap.delete(normName); return { product: p, soldInBatch: soldData?.qty || 0, stock: p.stockQuantity || 0, isExternal: false }; });
      const externalItems = Array.from(soldMap.values()).map(ext => ({ product: { id: ext.productId || 'EXT', name: ext.name, defaultPrice: 0, stockQuantity: 0 } as Product, soldInBatch: ext.qty, stock: 0, isExternal: true }));
      const allItems = [...inventoryItems, ...externalItems];
      return allItems.filter(item => { if (sidebarTab === 'ACTIVE') return item.soldInBatch > 0; if (sidebarTab === 'WARNING') return !item.isExternal && item.stock < 10; if (sidebarTab === 'SEARCH') { if (!sidebarSearch) return true; return normalizeString(item.product.name).includes(normalizeString(sidebarSearch)); } return false; }).sort((a, b) => b.soldInBatch - a.soldInBatch);
  }, [orders, products, batchId, sidebarTab, sidebarSearch]);

  const handleVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitRecognition;
    if (!SpeechRecognition) { toast.error("Trình duyệt không hỗ trợ"); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = async (event: any) => {
        setIsProcessingAI(true);
        try {
            const transcript = event.results[0][0].transcript;
            const res = await parseOrderText(transcript, products, customers);
            setCustomerInfo(prev => ({ ...prev, customerName: res.customerName || prev.customerName, customerPhone: res.customerPhone || prev.customerPhone, address: res.address || prev.address, notes: res.notes || prev.notes }));
            if (res.parsedItems?.length) { setItems(res.parsedItems.map(pi => { const matched = products.find(p => normalizeString(p.name) === normalizeString(pi.productName)); return { id: uuidv4(), name: matched ? matched.name : pi.productName, quantity: pi.quantity || 1, price: matched ? matched.defaultPrice : 0, productId: matched?.id }; })); }
        } catch (error) { toast.error("Lỗi AI"); } finally { setIsProcessingAI(false); }
    };
    recognition.start();
  };

  const addItemRow = () => setItems([...items, { id: uuidv4(), name: '', quantity: 1, price: 0 }]);
  const removeItemRow = (index: number) => { if (items.length === 1) { setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]); return; } const newItems = [...items]; newItems.splice(index, 1); setItems(newItems); };
  const handleItemChange = (index: number, field: keyof OrderItem, value: any) => { const newItems = [...items]; newItems[index] = { ...newItems[index], [field]: value }; if (field === 'name') newItems[index].productId = undefined; setItems(newItems); };
  const selectProductForItem = (index: number, product: Product) => { const newItems = [...items]; newItems[index] = { ...newItems[index], productId: product.id, name: product.name, price: product.defaultPrice }; setItems(newItems); setActiveProductRow(null); };
  const addTagToNotes = (tag: string) => { setCustomerInfo(prev => ({ ...prev, notes: prev.notes ? `${prev.notes}, ${tag}` : tag })); };

  const handleSelectCustomer = (s: Customer) => {
      setCustomerInfo({ customerId: s.id, customerName: s.name, customerPhone: s.phone, address: s.address, notes: customerInfo.notes });
      setShowCustomerSuggestions(false);
      toast.success(`Đã tự động điền: ${s.name}`, { icon: '🧠', duration: 1000 });
  };

  const handleQuickInsert = (product: Product) => {
    const existingIdx = items.findIndex(i => i.productId === product.id);
    if (existingIdx >= 0) {
      const newItems = [...items];
      newItems[existingIdx].quantity = (Number(newItems[existingIdx].quantity) || 0) + 1;
      setItems(newItems);
    } else {
      const emptyIdx = items.findIndex(i => !i.name && !i.productId);
      if (emptyIdx >= 0) {
        const newItems = [...items];
        newItems[emptyIdx] = { ...newItems[emptyIdx], productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 };
        setItems(newItems);
      } else {
        setItems([...items, { id: uuidv4(), productId: product.id, name: product.name, price: product.defaultPrice, quantity: 1 }]);
      }
    }
    toast.success(`Thêm ${product.name}`, { duration: 800 });
  };

  const handleSaveProduct = async (data: Product, isImport: boolean = false, qty: number = 0) => {
    if (isImport && editingProduct) {
      await storageService.adjustStockAtomic(editingProduct.id, qty, { price: data.importPrice || 0, note: 'Nhập hàng' });
      if (data.name !== editingProduct.name || data.defaultPrice !== editingProduct.defaultPrice) {
        await storageService.saveProduct({ ...editingProduct, name: data.name, defaultPrice: data.defaultPrice, importPrice: data.importPrice });
      }
      toast.success("Đã nhập hàng");
    } else {
      await storageService.saveProduct(data);
      toast.success(editingProduct ? 'Đã cập nhật' : 'Đã tạo hàng mới');
    }
    setShowProductModal(false);
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    const validItems = items.filter(i => i.name && i.name.trim() !== '') as OrderItem[];
    if (!customerInfo.customerName || !customerInfo.address || validItems.length === 0) { toast.error('Vui lòng điền đủ thông tin'); return; }
    const newOrder: Order = { id: uuidv4().slice(0, 8).toUpperCase(), customerId: customerInfo.customerId, batchId: batchId, customerName: customerInfo.customerName, customerPhone: customerInfo.customerPhone, address: customerInfo.address, items: validItems, notes: customerInfo.notes, totalPrice: totalPrice, paymentMethod: PaymentMethod.CASH, status: OrderStatus.PENDING, createdAt: Date.now(), updatedAt: Date.now(), orderIndex: Date.now() };
    await storageService.saveOrder(newOrder);
    toast.success('Đã lưu đơn!', { icon: '✅' });
    setCustomerInfo({ customerId: '', customerName: '', customerPhone: '', address: '', notes: '' });
    setItems([{ id: uuidv4(), name: '', quantity: 1, price: 0 }]);
    if (nameInputRef.current) nameInputRef.current.focus();
  };

  const inputClass = "w-full p-2 bg-white border border-gray-200 rounded-lg outline-none text-sm font-bold text-gray-800 placeholder-gray-300 focus:border-eco-500 uppercase transition-all";

  return (
    <div className="flex flex-col h-[calc(100vh-4.5rem)] sm:h-[calc(100vh-6rem)] bg-white rounded-xl sm:rounded-3xl shadow-sm border border-gray-100 overflow-hidden relative">
        {isProcessingAI && (
            <div className="absolute inset-0 z-50 bg-white/80 backdrop-blur-md flex items-center justify-center">
                <div className="flex flex-col items-center">
                    <div className="w-12 h-12 border-4 border-eco-100 border-t-eco-600 rounded-full animate-spin"></div>
                    <span className="mt-4 text-[10px] font-black text-eco-800 uppercase tracking-widest italic">AI Đang phân tích...</span>
                </div>
            </div>
        )}

        {/* Top Header - Merged Toolbar */}
        <div className="flex items-center justify-between px-3 py-2 bg-gray-50 border-b border-gray-100 shrink-0">
            <div ref={batchWrapperRef} className="relative">
                <div className="flex items-center bg-white border border-gray-200 rounded-lg px-2 py-1 cursor-pointer" onClick={() => setShowBatchSuggestions(!showBatchSuggestions)}>
                    <input value={batchId} onChange={(e) => setBatchId(e.target.value)} className="w-28 text-[10px] font-black text-gray-700 outline-none uppercase bg-transparent" placeholder="LÔ HÀNG..." />
                    <i className="fas fa-chevron-down text-[8px] ml-1 text-gray-400"></i>
                </div>
                {showBatchSuggestions && (
                    <div className="absolute top-full left-0 mt-1 w-48 bg-white border border-gray-100 rounded-lg shadow-xl z-[60] max-h-48 overflow-y-auto no-scrollbar animate-scale-in">
                        {existingBatches.map(b => <div key={b} onClick={() => { setBatchId(b); setShowBatchSuggestions(false); }} className="px-3 py-2 hover:bg-eco-50 text-[10px] font-bold text-gray-700 border-b border-gray-50">{b}</div>)}
                    </div>
                )}
            </div>

            <div className="flex gap-2">
                <div className="sm:hidden flex bg-gray-200 p-0.5 rounded-lg">
                    <button onClick={() => setMobileTab('FORM')} className={`px-3 py-1 text-[9px] font-black rounded-md transition-all ${mobileTab === 'FORM' ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-500'}`}>ĐƠN</button>
                    <button onClick={() => setMobileTab('STATS')} className={`px-3 py-1 text-[9px] font-black rounded-md transition-all ${mobileTab === 'STATS' ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-500'}`}>KHO</button>
                </div>
                <button onClick={handleVoiceInput} disabled={isListening} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white border border-gray-200 text-gray-400'}`}><i className={`fas ${isListening ? 'fa-microphone-slash' : 'fa-microphone'} text-xs`}></i></button>
            </div>
        </div>

        <div className="flex flex-col sm:flex-row h-full overflow-hidden relative">
            {/* Form Column */}
            <div className={`${mobileTab === 'FORM' ? 'flex' : 'hidden'} sm:flex sm:w-[60%] flex-col h-full overflow-hidden relative`}>

                <form className="flex-grow overflow-y-auto p-3 space-y-3 pb-24 bg-gray-50/20">
                    {/* Customer Info Section - More compact */}
                    <div className="bg-white p-3 rounded-xl border border-gray-100 shadow-sm space-y-2">
                        <div className="flex gap-2" ref={customerWrapperRef}>
                            <div className="flex-grow relative">
                                <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Người nhận</label>
                                <input ref={nameInputRef} value={customerInfo.customerName} onChange={(e) => { setCustomerInfo({...customerInfo, customerName: e.target.value}); setShowCustomerSuggestions(true); }} required className={inputClass} placeholder="TÊN KHÁCH..." />
                                {showCustomerSuggestions && customerInfo.customerName && (
                                    <ul className="absolute z-40 w-full bg-white border border-gray-200 rounded-lg shadow-2xl mt-1 max-h-48 overflow-y-auto no-scrollbar">
                                        {customers.filter(c => c.name.toLowerCase().includes(customerInfo.customerName.toLowerCase())).sort((a,b) => (b.totalOrders || 0) - (a.totalOrders || 0)).slice(0, 5).map(s => (
                                            <li key={s.id} onClick={() => handleSelectCustomer(s)} className="px-3 py-2 hover:bg-eco-50 border-b border-gray-50 flex flex-col">
                                                <span className="text-xs font-black text-gray-800 uppercase">{s.name} {(s.totalOrders || 0) > 5 && '⭐'}</span>
                                                <span className="text-[9px] text-gray-400 truncate">{s.phone} • {s.address}</span>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                            <div className="w-[40%]">
                                <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Số ĐT</label>
                                <input value={customerInfo.customerPhone} onChange={(e) => setCustomerInfo({...customerInfo, customerPhone: e.target.value})} className={inputClass} placeholder="09XXX..." />
                            </div>
                        </div>
                        <div>
                            <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Địa chỉ giao</label>
                            <input value={customerInfo.address} onChange={(e) => setCustomerInfo({...customerInfo, address: e.target.value})} required className={inputClass} placeholder="SỐ NHÀ, TÊN ĐƯỜNG..." />
                        </div>
                        <div className="relative">
                            <label className="text-[9px] font-black text-gray-400 uppercase ml-1">Ghi chú</label>
                            <input value={customerInfo.notes} onChange={(e) => setCustomerInfo({...customerInfo, notes: e.target.value})} className={inputClass} placeholder="GHI CHÚ GIAO HÀNG..." />
                            <div className="flex flex-wrap gap-1.5 mt-2">
                                {quickTags.slice(0, 4).map(tag => <button key={tag} type="button" onClick={() => addTagToNotes(tag)} className="px-2 py-1 bg-gray-100 text-gray-500 rounded-md text-[8px] font-black uppercase">{tag}</button>)}
                            </div>
                        </div>
                    </div>

                    {/* Items Section - Slimmer rows */}
                    <div className="space-y-2" ref={productWrapperRef}>
                        <div className="flex justify-between items-center px-1">
                            <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest italic">Hàng hóa</span>
                            <button type="button" onClick={addItemRow} className="text-[9px] font-black text-eco-600 bg-white border border-eco-200 px-3 py-1 rounded-lg shadow-sm">+ Thêm món</button>
                        </div>
                        <div className="space-y-1.5">
                            {items.map((item, idx) => (
                                <div key={item.id} className="flex items-center gap-1.5 bg-white p-2 rounded-lg border border-gray-100 shadow-sm relative group">
                                    <div className="flex-grow relative">
                                        <input value={item.name} onChange={(e) => handleItemChange(idx, 'name', e.target.value)} onFocus={() => setActiveProductRow(idx)} className="w-full p-1.5 bg-gray-50 border-none rounded-md text-xs font-bold text-gray-800 outline-none uppercase placeholder-gray-300" placeholder="TÊN MÓN..." />
                                        {activeProductRow === idx && (
                                            <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-lg shadow-2xl z-50 max-h-48 overflow-y-auto no-scrollbar">
                                                {products.filter(p => !item.name || normalizeString(p.name).includes(normalizeString(item.name))).map(p => <div key={p.id} onMouseDown={() => selectProductForItem(idx, p)} className="px-3 py-2 hover:bg-blue-50 cursor-pointer flex justify-between items-center border-b border-gray-50"><div className="flex flex-col"><span className="text-[11px] font-bold text-gray-700 uppercase">{p.name}</span><span className="text-[9px] text-gray-400 uppercase">Tồn: {p.stockQuantity}</span></div><span className="text-[10px] font-black text-blue-600">{new Intl.NumberFormat('vi-VN').format(p.defaultPrice)}đ</span></div>)}
                                                <div onMouseDown={() => { setEditingProduct(null); setEditMode('SET'); setShowProductModal(true); }} className="p-2 bg-gray-50 text-center text-[9px] font-black text-eco-600 uppercase italic cursor-pointer">+ Tạo mới hàng</div>
                                            </div>
                                        )}
                                    </div>
                                    <div className="w-12">
                                        <input type="number" step="any" value={item.quantity === 0 ? '' : item.quantity} onChange={(e) => handleItemChange(idx, 'quantity', Number(e.target.value))} className="w-full p-1.5 text-center bg-gray-50 border-none rounded-md text-xs font-black text-eco-700 outline-none" placeholder="SL" />
                                    </div>
                                    <div className="w-20">
                                        <input type="number" value={item.price === 0 ? '' : item.price} onChange={(e) => handleItemChange(idx, 'price', Number(e.target.value))} className="w-full p-1.5 text-right bg-gray-50 border-none rounded-md text-xs font-black text-gray-800 outline-none" placeholder="GIÁ" />
                                    </div>
                                    <button type="button" onClick={() => removeItemRow(idx)} className="text-gray-300 hover:text-red-500 w-6 h-6 flex items-center justify-center"><i className="fas fa-times-circle"></i></button>
                                </div>
                            ))}
                        </div>
                    </div>
                </form>

                {/* Sticky Bottom Action Bar */}
                <div className="absolute bottom-0 left-0 right-0 bg-white border-t border-gray-100 p-3 flex gap-3 items-center shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-20">
                    <div className="shrink-0">
                        <div className="text-[8px] text-gray-400 font-black uppercase tracking-widest">TỔNG TIỀN</div>
                        <div className="text-xl font-black text-eco-700 italic leading-none">{new Intl.NumberFormat('vi-VN').format(totalPrice)}<span className="text-[9px] font-bold not-italic ml-0.5">đ</span></div>
                    </div>
                    <button onClick={() => handleSubmit()} className="flex-grow bg-gray-900 text-white rounded-xl py-3.5 px-4 font-black text-[11px] shadow-lg active:scale-[0.98] transition-all uppercase tracking-widest italic">LƯU ĐƠN HÀNG <i className="fas fa-check-circle ml-1"></i></button>
                </div>
            </div>

            {/* Sidebar Column - Tighter on Mobile */}
            <div className={`${mobileTab === 'STATS' ? 'flex' : 'hidden'} sm:flex sm:w-[40%] flex-col bg-gray-50 h-full overflow-hidden border-l border-gray-100`}>
                <div className="p-2 bg-white border-b border-gray-100">
                    <div className="flex gap-1 p-0.5 bg-gray-100 rounded-lg">
                        {(['ACTIVE', 'WARNING', 'SEARCH'] as SidebarTab[]).map(tab => <button key={tab} onClick={() => setSidebarTab(tab)} className={`flex-1 py-1.5 text-[9px] font-black rounded-md transition-all ${sidebarTab === tab ? 'bg-white text-eco-700 shadow-sm' : 'text-gray-400'}`}>{tab === 'ACTIVE' ? 'ĐANG BÁN' : tab === 'WARNING' ? 'SẮP HẾT' : 'TÌM KHO'}</button>)}
                    </div>
                </div>
                <div className="flex-grow overflow-y-auto p-2 space-y-1.5 no-scrollbar">
                    {filteredSidebarProducts.length === 0 ? (
                        <div className="py-10 text-center text-gray-300 italic text-[9px] uppercase font-black">Không có hàng</div>
                    ) : filteredSidebarProducts.map((item) => (
                        <div key={item.product.id + (item.isExternal ? '-ext' : '')} className={`flex items-center gap-2 p-2 bg-white rounded-lg border border-transparent shadow-sm hover:border-gray-200 group`}>
                            <div onClick={() => handleQuickInsert(item.product)} className={`w-7 h-7 rounded-md flex items-center justify-center text-[9px] font-black shrink-0 cursor-pointer ${item.isExternal ? 'bg-orange-600 text-white' : item.soldInBatch > 0 ? 'bg-eco-600 text-white' : 'bg-gray-100 text-gray-400'}`}>{item.soldInBatch > 0 ? item.soldInBatch : '+'}</div>
                            <div className="flex-grow min-w-0 flex items-center justify-between gap-1">
                                <div onClick={() => handleQuickInsert(item.product)} className={`text-[10px] font-bold truncate cursor-pointer uppercase ${item.isExternal ? 'text-orange-700' : 'text-gray-700'}`}>{item.product.name}</div>
                                <div className="flex items-center gap-1.5 shrink-0">
                                    {!item.isExternal && <span className={`text-[8px] font-black ${item.stock < 5 ? 'text-red-500' : 'text-gray-300'}`}>T:{item.stock}</span>}
                                    <button onClick={() => { setEditingProduct(item.product); setEditMode('IMPORT'); setShowProductModal(true); }} className="opacity-0 group-hover:opacity-100 text-[8px] text-blue-600 font-black uppercase">Sửa</button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      <ProductEditModal isOpen={showProductModal} onClose={() => setShowProductModal(false)} product={editingProduct} onSave={handleSaveProduct} initialMode={editMode} />
    </div>
  );
};

