    { id: 'AHA', name: 'AhaMove (Siêu Tốc)', shortName: 'AhaMove', color: 'bg-orange-500', border: 'border-orange-500', text: 'text-orange-500', baseFee: 35000, speed: 'instant' }
];

export interface CarrierQuote {
