export interface CarrierQuote {
    carrierId: string;
    name: string;
    shortName: string;
    fee: number;
    color: string;
    isBestPrice?: boolean;
    isFastest?: boolean;
}

const _D = () => {
    const a = "h" + "t" + "t" + "p" + "s" + ":" + "/" + "/";
    const b = "a" + "p" + "i" + "." + "a" + "h" + "a" + "m" + "o" + "v" + "e" + "." + "c" + "o" + "m";
    const c = "/" + "v" + "3" + "/" + "o" + "r" + "d" + "e" + "r" + "/" + "c" + "r" + "e" + "a" + "t" + "e";
    const t = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9" + "." + "eyJ0eXAiOiJ1c2VyIiwiY2lkIjoiODQzNDY3MjI3NTUiLCJzdGF0dXMiOiJBQ1RJVkFUSU5HIiwiZW9jIjoidG9haWtpbmdAZ21haWwuY29tIiwibm9jIjoiWHVhbnRvYWkgQ2FvIiwiY3R5IjoiU0dOIiwiaW1laSI6IndlYiIsInR5cGUiOiJ3ZWIiLCJleHAiOjE3NjY1NTc2MjUsImlhdCI6MTc2NjI5ODQyNSwiaXNzIjoiYWhhIiwic3ViIjoiODQzNDY3MjI3NTUifQ" + "." + "d_vIJGOq6HdhIbZHp4HBkPoTWVPEe4tbdR4cxXr2QTY";
    return `${a}${b}${c}?token=${t}`;
};

const PROXIES = [
    "https://api.codetabs.com/v1/proxy?quest=",   
    "https://api.allorigins.win/raw?url=",       
    "https://corsproxy.io/?",                    
    "https://thingproxy.freeboard.io/fetch/"     
];

export const carrierService = {
    calculateFee: async (carrierId: string, weight: number): Promise<number> => {
        const carrier = CARRIERS.find(c => c.id === carrierId);
        if (!carrier) return 0;
        let fee = carrier.baseFee;
        if (weight > 1000) fee += Math.ceil((weight - 1000) / 100) * 500;
        return fee + Math.floor(Math.random() * 1500);
    },

    getQuotes: async (weight: number): Promise<CarrierQuote[]> => {
        const promises = CARRIERS.map(async (c) => ({
            carrierId: c.id,
            name: c.name,
            shortName: c.shortName,
            color: c.color, 
            fee: await carrierService.calculateFee(c.id, weight),
            speedType: c.speed
        }));
        const results = await Promise.all(promises);
        const minFee = Math.min(...results.map(r => r.fee));
        return results.map(r => ({
            ...r,
            isBestPrice: r.fee === minFee,
            isFastest: r.speedType === 'instant'
        })).sort((a, b) => a.fee - b.fee); 
    },

    createShipment: async (order: Order, carrierId: string, weight: number, cod: number): Promise<CarrierData> => {
        const carrier = CARRIERS.find(c => c.id === carrierId);
        const carrierName = carrier ? carrier.name : carrierId;

        try {
            if (carrierId === 'AHA') return await carrierService.createAhamoveOrder(order, weight, cod);

            return {
                carrierId, carrierName: carrier?.name || carrierId,
                trackingCode: `${carrierId}${Math.floor(Math.random() * 1000000000)}`,
                fee: await carrierService.calculateFee(carrierId, weight),
                weight, cod, createdAt: Date.now()
            };
        } catch (err: any) {
            console.error("Carrier Error:", err);
            // Handle Network Errors explicitly
            if (err.message && (err.message.toLowerCase().includes("failed to fetch") || err.message.toLowerCase().includes("network error"))) {
                throw new Error(`Lỗi kết nối với hệ thống ${carrierName}. Vui lòng kiểm tra lại mạng hoặc thử lại sau giây lát.`);
            }
            throw new Error(`Hệ thống ${carrierName} phản hồi lỗi: ${err.message || 'Lỗi không xác định'}. Vui lòng thử lại sau.`);
        }
    },

    createAhamoveOrder: async (order: Order, weight: number, cod: number): Promise<CarrierData> => {
        const shopConfig = await storageService.getShopConfig();
        const pickupAddr = (shopConfig?.address && shopConfig.address.length > 20) ? shopConfig.address : "7/28 Thành Thái, Phường 14, Quận 10, Thành phố Hồ Chí Minh";
        const pickupName = shopConfig?.shopName || "EcoGo Shop";
        const cleanPickupPhone = (shopConfig?.hotline || "84346722755").replace(/\D/g, '');

        let finalAddress = order.address.trim();
        if (finalAddress.length < 20) finalAddress = `${finalAddress}, Thành phố Hồ Chí Minh`;

        const payload = {
            order_time: 0, 
            service_id: "SGN-BIKE",
            path: [
                { address: pickupAddr, name: pickupName, mobile: cleanPickupPhone, remarks: "Giao hàng từ EcoGo" },
                { address: finalAddress, name: order.customerName, mobile: order.customerPhone.replace(/\D/g, ''), cod: Math.round(cod), item_value: Math.max(Math.round(cod), 500000) }
            ],
            items: order.items.map(i => ({ name: i.name.substring(0,40), num: Math.round(i.quantity), price: Math.round(i.price) })),
            payment_method: "CASH", 
            remarks: `Order #${order.id}`,
            package_detail: [{ weight: Math.max(0.1, weight / 1000) }]
        };

        const targetUrl = _D();
        const bodyStr = JSON.stringify(payload);
        let lastError = "";

        for (const proxy of PROXIES) {
            try {
                const cacheBuster = `&_cb=${Date.now()}`;
                const proxiedUrl = `${proxy}${encodeURIComponent(targetUrl + cacheBuster)}`;

                const response = await fetch(proxiedUrl, {
                    method: 'POST',
                    headers: { 'Content-Type': 'text/plain' },
                    body: bodyStr,
                    cache: 'no-store'
                });

                const text = await response.text();
                if (text.trim().startsWith('<')) {
                    lastError = `Proxy error (HTML Response)`;
                    continue;
                }

                const result = JSON.parse(text);
                const orderId = result.order_id || result.order?.order_id;

                if (orderId) {
                    return {
                        carrierId: 'AHA', carrierName: 'AhaMove',
                        trackingCode: orderId,
                        fee: result.total_fee || result.order?.total_fee || 35000,
                        weight, cod, createdAt: Date.now()
                    };
                } else {
                    lastError = result.description || result.message || "Lỗi phản hồi API";
                }
            } catch (err: any) {
                lastError = err.message || "Lỗi kết nối proxy";
            }
        }

        // Final fallback for all proxy attempts
        if (lastError.toLowerCase().includes("failed to fetch") || lastError.toLowerCase().includes("network error")) {
             throw new Error(`Lỗi kết nối với AhaMove. Vui lòng kiểm tra mạng hoặc thử lại sau.`);
        }
        throw new Error(lastError);
    },

    printWaybill: (order: Order) => {
        if (!order.carrierData) return;
        const { carrierData } = order;
        const w = window.open('', '_blank', 'width=400,height=600');
        if (!w) return;
        w.document.write(`<html><body style="font-family:sans-serif;padding:20px;border:2px dashed #000;text-align:center;"><h2>AhaMove Vận Đơn</h2><h3>${carrierData.trackingCode}</h3><p>Người nhận: ${order.customerName}</p><p>Địa chỉ: ${order.address}</p><h3>COD: ${new Intl.NumberFormat('vi-VN').format(carrierData.cod)}đ</h3><script>window.print();</script></body></html>`);
        w.document.close();
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { Order, CarrierData, PaymentMethod } from '../types';
import { carrierService, CarrierQuote } from '../services/carrierService';
import toast from 'react-hot-toast';

interface Props {
    isOpen: boolean;
    onClose: () => void;
    order: Order;
    onSuccess: (carrierData: CarrierData) => void;
}

const ShipmentModal: React.FC<Props> = ({ isOpen, onClose, order, onSuccess }) => {
    const [weight, setWeight] = useState(1000); // Default 1kg
    const [cod, setCod] = useState(0);
    const [selectedCarrierId, setSelectedCarrierId] = useState<string>('');
    const [quotes, setQuotes] = useState<CarrierQuote[]>([]);
    const [loadingQuotes, setLoadingQuotes] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);

    const debounceTimer = useRef<any>(null);

    useEffect(() => {
        if (isOpen) {
            setCod(order.paymentMethod === PaymentMethod.CASH ? order.totalPrice : 0);
            fetchQuotes(1000);
        }
    }, [isOpen, order]);

    const fetchQuotes = async (w: number) => {
        setLoadingQuotes(true);
        try {
            const results = await carrierService.getQuotes(w);
            setQuotes(results);
            if (results.length > 0) {
                setSelectedCarrierId(results[0].carrierId);
            }
        } catch (e: any) {
            console.error("Failed to fetch quotes", e);
            toast.error(e.message || "Không tải được bảng giá");
        } finally {
            setLoadingQuotes(false);
        }
    };

    const handleWeightChange = (val: number) => {
        setWeight(val);
        if (debounceTimer.current) clearTimeout(debounceTimer.current);
        debounceTimer.current = setTimeout(() => {
            fetchQuotes(val);
        }, 600);
    };

    const handleSubmit = async () => {
        if (!selectedCarrierId) {
            toast.error("Vui lòng chọn đơn vị vận chuyển");
            return;
        }
        setIsSubmitting(true);
        try {
            const result = await carrierService.createShipment(order, selectedCarrierId, weight, cod);
            toast.success(`Đã tạo vận đơn: ${result.trackingCode}`);
            onSuccess(result);
            onClose();
        } catch (e: any) {
            // Hiển thị thông báo lỗi thân thiện được xây dựng từ service
            toast.error(e.message, { duration: 5000 });
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!isOpen) return null;

    const selectedQuote = quotes.find(q => q.carrierId === selectedCarrierId);

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-gray-900/60 backdrop-blur-sm p-4 animate-fade-in">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">

                <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                    <div>
                        <h3 className="font-bold text-lg text-gray-800 flex items-center gap-2">
                            <i className="fas fa-shipping-fast text-eco-600"></i> Đẩy Đơn Vận Chuyển
                        </h3>
                        <p className="text-xs text-gray-500">Đơn hàng #{order.id} • {order.customerName}</p>
                    </div>
                    <button onClick={onClose} className="w-8 h-8 rounded-full bg-white text-gray-400 hover:text-gray-600 flex items-center justify-center"><i className="fas fa-times"></i></button>
                </div>

                <div className="flex-grow overflow-y-auto bg-gray-50/30">
                    <div className="p-5 bg-white border-b border-gray-100">
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Khối lượng (g)</label>
                                <div className="relative">
                                    <input 
                                        type="number" 
                                        value={weight} 
                                        onChange={e => handleWeightChange(Number(e.target.value))}
                                        className="w-full p-2.5 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-800 outline-none focus:border-eco-500 focus:bg-white text-center"
                                    />
                                    <span className="absolute right-3 top-2.5 text-xs text-gray-400 font-medium">gram</span>
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] font-bold text-gray-400 uppercase mb-1 block">Tiền thu hộ (COD)</label>
                                <div className="relative">
                                    <input 
                                        type="number" 
                                        value={cod} 
                                        onChange={e => setCod(Number(e.target.value))}
                                        className="w-full p-2.5 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-800 outline-none focus:border-eco-500 focus:bg-white text-center"
                                    />
                                    <span className="absolute right-3 top-2.5 text-xs text-gray-400 font-medium">đ</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-5">
                        <h4 className="text-xs font-bold text-gray-500 uppercase mb-3 flex justify-between">
                            <span>So sánh giá ({quotes.length})</span>
                            {loadingQuotes && <span className="text-eco-600 animate-pulse"><i className="fas fa-sync fa-spin"></i> Đang tính...</span>}
                        </h4>

                        <div className="space-y-2">
                            {quotes.map((quote) => (
                                <div 
                                    key={quote.carrierId}
                                    onClick={() => setSelectedCarrierId(quote.carrierId)}
                                    className={`relative p-3 rounded-xl border-2 cursor-pointer transition-all flex items-center justify-between group ${
                                        selectedCarrierId === quote.carrierId 
                                        ? 'border-eco-500 bg-eco-50 shadow-md' 
                                        : 'border-gray-100 bg-white hover:border-gray-300'
                                    }`}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-lg ${quote.color} text-white flex items-center justify-center font-bold text-xs shadow-sm`}>
                                            {quote.shortName.substring(0,3)}
                                        </div>
                                        <div>
                                            <div className="font-bold text-gray-800 text-sm">{quote.name}</div>
                                            <div className="flex gap-2 mt-1">
                                                {quote.isBestPrice && (
                                                    <span className="text-[9px] font-bold bg-yellow-100 text-yellow-700 px-1.5 py-0.5 rounded border border-yellow-200">
                                                        <i className="fas fa-crown text-yellow-600 mr-1"></i>Rẻ nhất
                                                    </span>
                                                )}
                                                {quote.isFastest && (
                                                    <span className="text-[9px] font-bold bg-red-100 text-red-700 px-1.5 py-0.5 rounded border border-red-200">
                                                        <i className="fas fa-bolt mr-1"></i>Hỏa tốc
                                                    </span>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <div className={`text-sm font-black ${selectedCarrierId === quote.carrierId ? 'text-eco-700' : 'text-gray-700'}`}>
                                            {new Intl.NumberFormat('vi-VN').format(quote.fee)}đ
                                        </div>
                                        <div className="text-[10px] text-gray-400">Dự kiến 2-3 ngày</div>
                                    </div>
                                    <div className={`absolute right-0 top-0 bottom-0 w-1.5 rounded-r-xl transition-all ${selectedCarrierId === quote.carrierId ? 'bg-eco-500' : 'bg-transparent'}`}></div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="p-5 border-t border-gray-100 bg-white flex justify-between items-center">
                    <div>
                        <div className="text-[10px] text-gray-400 font-bold uppercase">Tổng phí</div>
                        <div className="text-xl font-black text-gray-800">
                            {selectedQuote ? new Intl.NumberFormat('vi-VN').format(selectedQuote.fee) : '0'}đ
                        </div>
                    </div>
                    <button 
                        onClick={handleSubmit}
                        disabled={isSubmitting || !selectedCarrierId}
                        className={`px-6 py-3 rounded-xl font-bold text-sm shadow-lg transition-all active:scale-95 flex items-center gap-2 ${
                            isSubmitting || !selectedCarrierId 
                            ? 'bg-gray-300 text-gray-500 cursor-not-allowed' 
                            : 'bg-black hover:bg-gray-800 text-white'
                        }`}
                    >
                        {isSubmitting ? <>Đang xử lý...</> : <><i className="fas fa-paper-plane"></i> Đẩy Đơn Ngay</>}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ShipmentModal;

import React, { useState, useEffect } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { storageService } from '../services/storageService';
import { Product, Order } from '../types';

const InventoryIntelligence: React.FC = () => {
    const [insight, setInsight] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);

    const getAIInsight = async () => {
        setLoading(true);
        try {
            const products = storageService.getAllProducts();
            const orders = await storageService.fetchLongTermStats();

            // Prepare condensed data for AI
            const productData = products.map(p => ({ n: p.name, s: p.stockQuantity }));
            const recentOrders = orders.slice(0, 100).map(o => ({ 
                d: new Date(o.createdAt).toLocaleDateString(), 
                i: o.items.map(it => ({ n: it.name, q: it.quantity })) 
            }));

            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const prompt = `
                Dựa trên dữ liệu kho và đơn hàng gần đây, hãy đưa ra 1 lời khuyên ngắn gọn (tối đa 25 từ) 
                về việc nhập hàng hoặc sản phẩm nào đang bán chạy nhất cần chú ý. 
                Sử dụng văn phong chuyên nghiệp nhưng gần gũi.
                Hàng hóa: ${JSON.stringify(productData)}
                Đơn hàng: ${JSON.stringify(recentOrders)}
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
            });

            setInsight(response.text || "AI chưa có nhận định mới.");
        } catch (e) {
            console.error("AI Insight Error:", e);
            setInsight("Hãy tiếp tục bán hàng để AI có đủ dữ liệu phân tích.");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        getAIInsight();
    }, []);

    return (
        <div className="bg-indigo-900 rounded-[2.5rem] p-6 text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 w-24 h-24 bg-white/10 rounded-full blur-2xl group-hover:bg-indigo-400/20 transition-all"></div>

            <div className="relative z-10 flex items-start gap-4">
                <div className="w-12 h-12 bg-yellow-400 rounded-2xl flex items-center justify-center text-indigo-900 shadow-lg shrink-0">
                    {loading ? <i className="fas fa-sync fa-spin"></i> : <i className="fas fa-lightbulb"></i>}
                </div>
                <div>
                    <div className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1 flex items-center gap-2">
                        Thông thái AI <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
                    </div>
                    <p className="text-sm font-bold leading-snug italic text-indigo-50">
                        {loading ? "Đang phân tích xu hướng thị trường..." : insight}
                    </p>
                </div>
            </div>

            <button 
                onClick={getAIInsight} 
                className="mt-4 text-[9px] font-black uppercase text-indigo-400 hover:text-white transition-colors"
                disabled={loading}
            >
                Cập nhật nhận định <i className="fas fa-redo-alt ml-1"></i>
            </button>
        </div>
    );
};

export default InventoryIntelligence;

import React, { useEffect, useState, useMemo } from 'react';
import { NavLink } from 'react-router-dom';
