    const unsubProducts = storageService.subscribeProducts(setProducts);
    const unsubCustomers = storageService.subscribeCustomers(setCustomers);

    // Load last filter batch from local
    const savedBatch = localStorage.getItem('ecogo_filter_batch');
    if (savedBatch) setFilterBatch(JSON.parse(savedBatch));

    return () => { 
        if (unsubOrders) unsubOrders(); 
        if (unsubProducts) unsubProducts();
        if (unsubCustomers) unsubCustomers(); 
    };
  }, []);

  const batches = useMemo(() => {
    const bSet = new Set<string>();
    orders.forEach(o => { if (o.batchId) bSet.add(o.batchId); });
    return Array.from(bSet).sort();
  }, [orders]);

  const filteredOrders = useMemo(() => {
    let result = orders.filter(o => {
      const matchStatus = filterStatus.length === 0 || filterStatus.includes(o.status);
      const matchBatch = filterBatch.length === 0 || filterBatch.includes(o.batchId);
      const matchSearch = !deferredSearchTerm || 
        normalizeString(o.customerName).includes(normalizeString(deferredSearchTerm)) ||
        o.customerPhone.includes(deferredSearchTerm) ||
        o.id.includes(deferredSearchTerm.toUpperCase()) ||
        o.address.toLowerCase().includes(deferredSearchTerm.toLowerCase());
      return matchStatus && matchBatch && matchSearch;
    });

    if (sortBy === 'NEWEST') result.sort((a, b) => b.createdAt - a.createdAt);
    else if (sortBy === 'STATUS') result.sort((a, b) => a.status.localeCompare(b.status));
    else if (sortBy === 'ROUTE') result.sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0));

    return result;
  }, [orders, filterStatus, filterBatch, deferredSearchTerm, sortBy]);

  // Actions
  const handleToggleSelect = (id: string) => {
    setSelectedOrderIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setIsSelectionMode(next.size > 0);
      return next;
    });
  };

  const handleBulkStatusUpdate = async (status: OrderStatus) => {
    const loading = toast.loading("Đang cập nhật...");
    const ids = Array.from(selectedOrderIds);
    await Promise.all(ids.map(id => storageService.updateStatus(id, status)));
    toast.success(`Đã chuyển ${ids.length} đơn sang ${status}`, { id: loading });
    setSelectedOrderIds(new Set());
    setIsSelectionMode(false);
    setShowBulkStatusModal(false);
  };

  const handleDeleteOrder = async () => {
    if (deleteId) {
      await storageService.deleteOrder(deleteId);
      toast.success("Đã xóa đơn hàng");
      setShowDeleteConfirm(false);
      setDeleteId(null);
    }
  };

  const handlePrintManifest = async () => {
    const batchName = filterBatch.length === 1 ? filterBatch[0] : "MANIFEST";
    toast.loading("Đang tạo bảng kê...", { duration: 2000 });
    await pdfService.generateCompactList(filteredOrders, batchName);
  };

  const handlePrintLabels = async () => {
    const batchName = filterBatch.length === 1 ? filterBatch[0] : "LABELS";
    toast.loading("Đang tạo tem dán...", { duration: 2000 });
    await pdfService.generateInvoiceBatch(filteredOrders, batchName);
  };

  return (
    <div className="max-w-6xl mx-auto pb-32 px-2 animate-fade-in">

      {/* TOOLBAR & FILTERS */}
      <div className="sticky top-16 z-40 bg-gray-50/95 backdrop-blur-md py-4 space-y-3">
          <div className="flex justify-between items-center px-1">
              <h2 className="text-2xl font-black text-gray-900 uppercase italic tracking-tighter">Theo dõi đơn</h2>
              <div className="flex gap-2">
                  <button onClick={() => setIsCompactMode(!isCompactMode)} className={`w-10 h-10 rounded-xl border-2 border-gray-900 flex items-center justify-center transition-all ${isCompactMode ? 'bg-gray-900 text-white' : 'bg-white text-gray-900'}`}>
                      <i className={`fas ${isCompactMode ? 'fa-th-list' : 'fa-th-large'}`}></i>
                  </button>
                  <button onClick={() => setShowRoutePlanner(true)} className="px-4 h-10 bg-eco-500 text-white rounded-xl border-2 border-gray-900 font-black text-xs uppercase shadow-[3px_3px_0px_0px_rgba(0,0,0,1)] active:translate-x-[2px] active:translate-y-[2px] active:shadow-none">
                      Lộ trình <i className="fas fa-route ml-1"></i>
                  </button>
              </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-2">
              <div className="relative flex-grow">
                  <i className="fas fa-search absolute left-3 top-3 text-gray-400"></i>
                  <input 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)} 
                    placeholder="Tìm tên, sđt, địa chỉ..." 
                    className="w-full pl-9 pr-4 py-2.5 bg-white border-2 border-gray-900 rounded-xl outline-none focus:ring-4 focus:ring-eco-50 font-bold text-sm"
                  />
              </div>
              <div className="flex gap-2">
                <select 
                    className="bg-white border-2 border-gray-900 rounded-xl px-3 py-2 text-xs font-black uppercase"
                    value={filterBatch[0] || ''}
                    onChange={(e) => {
                        const val = e.target.value;
                        const next = val ? [val] : [];
                        setFilterBatch(next);
                        localStorage.setItem('ecogo_filter_batch', JSON.stringify(next));
                    }}
                >
                    <option value="">Tất cả lô</option>
                    {batches.map(b => <option key={b} value={b}>{b}</option>)}
                </select>
                <button onClick={handlePrintManifest} className="w-10 h-10 bg-white border-2 border-gray-900 rounded-xl flex items-center justify-center text-gray-800" title="In bảng kê">
                    <i className="fas fa-file-invoice"></i>
                </button>
                <button onClick={handlePrintLabels} className="w-10 h-10 bg-white border-2 border-gray-900 rounded-xl flex items-center justify-center text-gray-800" title="In tem dán">
                    <i className="fas fa-print"></i>
                </button>
              </div>
          </div>
      </div>

      {/* STATS STRIP */}
      <div className="flex gap-2 overflow-x-auto no-scrollbar py-2 mb-4">
          <div className="bg-white border-2 border-gray-900 px-3 py-1.5 rounded-full flex items-center gap-2 whitespace-nowrap">
              <span className="text-[10px] font-black text-gray-400 uppercase">Tổng:</span>
              <span className="text-xs font-black text-gray-900">{filteredOrders.length}</span>
          </div>
          <div className="bg-yellow-50 border-2 border-gray-900 px-3 py-1.5 rounded-full flex items-center gap-2 whitespace-nowrap">
              <span className="text-[10px] font-black text-yellow-600 uppercase">Chờ:</span>
              <span className="text-xs font-black text-yellow-800">{filteredOrders.filter(o => o.status === OrderStatus.PENDING).length}</span>
          </div>
          <div className="bg-blue-50 border-2 border-gray-900 px-3 py-1.5 rounded-full flex items-center gap-2 whitespace-nowrap">
              <span className="text-[10px] font-black text-blue-600 uppercase">Đang đi:</span>
              <span className="text-xs font-black text-blue-800">{filteredOrders.filter(o => o.status === OrderStatus.IN_TRANSIT).length}</span>
          </div>
      </div>

      {/* ORDERS LIST */}
      <div className={isCompactMode ? "space-y-1" : "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4"}>
          {filteredOrders.length === 0 ? (
              <div className="col-span-full py-20 text-center">
                  <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4 text-gray-300 text-3xl">
                      <i className="fas fa-box-open"></i>
                  </div>
                  <p className="text-gray-400 font-black uppercase text-xs tracking-widest">Không có đơn hàng nào</p>
              </div>
          ) : (
            filteredOrders.map((order, idx) => (
                <OrderCard 
                    key={order.id}
                    order={order}
                    index={idx}
                    isCompactMode={isCompactMode}
                    isSelectionMode={isSelectionMode}
                    isSelected={selectedOrderIds.has(order.id)}
                    onToggleSelect={handleToggleSelect}
                    onLongPress={(id) => {
                        handleToggleSelect(id);
                        setIsSelectionMode(true);
                    }}
                    onUpdate={(updated) => storageService.updateOrderDetails(updated)}
                    onDelete={(id) => { setDeleteId(id); setShowDeleteConfirm(true); }}
                    onEdit={(o) => setDetailOrder(o)}
                    onShowQR={(o) => { /* Logic QR */ }}
                />
            ))
          )}
      </div>

      {/* BULK ACTIONS BAR */}
      {isSelectionMode && (
          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 w-[95%] max-w-lg animate-slide-up">
              <div className="bg-gray-900 text-white p-4 rounded-3xl shadow-2xl flex items-center justify-between border-4 border-eco-500">
                  <div className="flex items-center gap-3">
                      <button onClick={() => { setSelectedOrderIds(new Set()); setIsSelectionMode(false); }} className="w-10 h-10 bg-gray-800 rounded-xl flex items-center justify-center">
                          <i className="fas fa-times"></i>
                      </button>
                      <div>
                          <p className="text-[10px] font-black text-gray-400 uppercase leading-none">Đã chọn</p>
                          <p className="text-lg font-black leading-none mt-1">{selectedOrderIds.size} đơn</p>
                      </div>
                  </div>
                  <div className="flex gap-2">
                      <button onClick={() => setShowBulkStatusModal(true)} className="bg-eco-600 px-4 py-2 rounded-xl font-black text-xs uppercase">Trạng thái</button>
                      <button onClick={() => { 
                          if(window.confirm(`Xóa ${selectedOrderIds.size} đơn?`)) {
                              storageService.deleteOrdersBatch(Array.from(selectedOrderIds));
                              setSelectedOrderIds(new Set());
                              setIsSelectionMode(false);
                          }
                      }} className="bg-red-600 px-4 py-2 rounded-xl font-black text-xs uppercase">Xóa</button>
                  </div>
              </div>
          </div>
      )}

      {/* MODALS */}
      <ConfirmModal 
        isOpen={showDeleteConfirm} 
        title="Xóa đơn hàng?" 
        message="Hành động này không thể hoàn tác. Kho hàng đã trừ sẽ không tự động hoàn lại."
        onConfirm={handleDeleteOrder}
        onCancel={() => setShowDeleteConfirm(false)}
        isDanger={true}
      />

      {showBulkStatusModal && (
          <div className="fixed inset-0 z-[100] bg-gray-900/80 backdrop-blur-md flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] border-4 border-gray-900 shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] p-6 w-full max-w-sm">
                  <h3 className="text-xl font-black text-gray-900 uppercase italic mb-6">Đổi trạng thái loạt</h3>
                  <div className="grid grid-cols-1 gap-3">
                      {Object.values(OrderStatus).map(status => (
                          <button key={status} onClick={() => handleBulkStatusUpdate(status)} className="py-4 border-2 border-gray-900 rounded-2xl font-black uppercase text-xs hover:bg-gray-50 transition-all active:scale-95">
                              {status}
                          </button>
                      ))}
                  </div>
                  <button onClick={() => setShowBulkStatusModal(false)} className="w-full mt-6 py-3 text-gray-400 font-bold uppercase text-[10px]">Hủy bỏ</button>
              </div>
          </div>
      )}

      {showRoutePlanner && (
          <RoutePlannerModal 
            isOpen={showRoutePlanner} 
            onClose={() => setShowRoutePlanner(false)} 
            orders={filteredOrders}
            onApplySort={async (sorted) => {
                await storageService.saveOrdersList(sorted);
                setShowRoutePlanner(false);
            }}
          />
      )}
    </div>
  );
};

