        const load = toast.loading("Đang tạo tài liệu hướng dẫn...");
        try {
            await pdfService.generateUserGuidePDF();
            toast.success("Đã tải tài liệu PDF!", { id: load });
        } catch (e) {
            toast.error("Lỗi tạo PDF. Vui lòng thử lại.", { id: load });
        } finally {
            setIsDownloading(false);
        }
